import React, { useRef, useEffect, useState } from "react";
import { App } from "antd";
import type { MenuProps } from "antd";
import type { DataNode, TreeProps } from "antd/es/tree";
import {
  PlusOutlined,
  EditOutlined,
  DeleteOutlined,
  SettingOutlined,
  InfoCircleOutlined,
  SwapOutlined,
} from "@ant-design/icons";
import CategoryTree, {
  CategoryTreeToolbarState,
  CategoryTreeProps,
} from "@/features/category/CategoryTree";
import FloatingContextMenu from "@/components/ContextMenu/FloatingContextMenu";
import CreateCategoryModal from "./components/CreateCategoryModal";
import BatchTransferModal from "./components/BatchTransferModal";
import WorkbookImportModal from "./components/import/WorkbookImportModal";
import WorkbookExportModal from "./components/export/WorkbookExportModal";
import AdminCategoryTreeToolbar from "./components/AdminCategoryTreeToolbar";
import {
  metaCategoryApi,
  type MetaCategoryBatchTransferResponseDto,
  type MetaCategoryBatchTransferTopologyResponseDto,
  type MetaCategoryDetailDto,
} from "@/services/metaCategory";
import { semanticStatusColors } from "@/styles/colors";

interface AdminCategoryTreeProps extends CategoryTreeProps {
  defaultBusinessDomain?: string;
  onMenuClick?: (key: string, node: DataNode) => void;
  onBatchDelete?: (nodes: DataNode[]) => void;
  onTransferSuccess?: (response: MetaCategoryBatchTransferResponseDto | MetaCategoryBatchTransferTopologyResponseDto) => void;
  onCategoryCreated?: (
    created: MetaCategoryDetailDto,
    parent?: {
      id?: string | null;
      code?: string;
      name?: string;
      level?: number;
      path?: string;
    } | null,
  ) => void;
}

type CategorySemanticStatus = "CREATED" | "EFFECTIVE" | "INVALID";

const normalizeCategoryStatus = (status?: string): CategorySemanticStatus => {
  const normalized = String(status || "").toUpperCase();
  if (normalized === "EFFECTIVE" || normalized === "ACTIVE") return "EFFECTIVE";
  if (normalized === "INVALID" || normalized === "INACTIVE") return "INVALID";
  return "CREATED";
};

const statusActionLabel: Record<CategorySemanticStatus, string> = {
  CREATED: "转创建",
  EFFECTIVE: "转生效",
  INVALID: "转失效",
};

const AdminCategoryTree: React.FC<AdminCategoryTreeProps> = ({
  defaultBusinessDomain,
  onMenuClick,
  onBatchDelete,
  onTransferSuccess,
  onCategoryCreated,
  ...props
}) => {
  const { message: messageApi } = App.useApp();
  const containerRef = useRef<HTMLDivElement>(null);

  const [createModalVisible, setCreateModalVisible] = useState(false);
  const [createSubmitting, setCreateSubmitting] = useState(false);
  const [createParentNode, setCreateParentNode] = useState<{
    id?: string | null;
    code?: string;
    name?: string;
    level?: number;
    path?: string;
      businessDomain?: string;
    rootCode?: string;
    rootName?: string;
  } | null>(null);

  const [contextMenuState, setContextMenuState] = useState<{
    visible: boolean;
    x: number;
    y: number;
    node: DataNode | null;
  }>({ visible: false, x: 0, y: 0, node: null });

  // === 迁移 / 复制 弹窗状态 ===
  const [transferModalVisible, setTransferModalVisible] = useState(false);
  const [transferAction, setTransferAction] = useState<'move' | 'copy' | null>(null);
  const [transferCheckedKeys, setTransferCheckedKeys] = useState<React.Key[]>([]);

  // === 导入弹窗状态 ===
  const [importModalVisible, setImportModalVisible] = useState(false);

  // === 导出弹窗状态 ===
  const [exportModalVisible, setExportModalVisible] = useState(false);
  const [exportCheckedKeys, setExportCheckedKeys] = useState<React.Key[]>([]);

  // Add global contextmenu interception
  useEffect(() => {
    const handleContextMenu = (e: MouseEvent) => {
      // Logic: If right-click happens inside the tree container, block default menu
      if (
        containerRef.current &&
        containerRef.current.contains(e.target as Node)
      ) {
        e.preventDefault();
      }
    };

    document.addEventListener("contextmenu", handleContextMenu);
    return () => {
      document.removeEventListener("contextmenu", handleContextMenu);
    };
  }, []);

  const renderContextMenuItems = (
    node: DataNode | null,
  ): MenuProps["items"] => {
    if (!node) return [];
    const nodeRef = (node as any)?.dataRef as
      | { code?: string; name?: string; level?: number }
      | undefined;
    const titleText =
      nodeRef?.code || nodeRef?.name
        ? `${nodeRef?.code || "-"} - ${nodeRef?.name || "未命名分类"}`
        : typeof node.title === "string"
          ? node.title
          : String(node.key);
    const levelText = nodeRef?.level ? `L${nodeRef.level}` : "-";
    const currentStatus = normalizeCategoryStatus((node as any)?.dataRef?.status);
    const transitionTargets = (["CREATED", "EFFECTIVE", "INVALID"] as CategorySemanticStatus[])
      .filter((status) => status !== currentStatus);

    const items: MenuProps["items"] = [
      {
        key: "header",
        label: (
          <span style={{ cursor: "default", color: "#888", fontSize: "12px" }}>
            节点: {titleText} | 层级: {levelText}
          </span>
        ),
        disabled: true,
        style: { cursor: "default", background: "rgba(0,0,0,0.02)" },
      },
      { type: "divider" },
      { key: "add", label: "新增子分类", icon: <PlusOutlined /> },
      { key: "rename", label: "重命名", icon: <EditOutlined /> },
      {
        key: "status-transition",
        label: "状态转换",
        icon: <SwapOutlined />,
        children: transitionTargets.map((status) => ({
          key: `status:${status}`,
          label: (
            <span style={{ display: "inline-flex", alignItems: "center", gap: 8 }}>
              <span
                style={{
                  width: 8,
                  height: 8,
                  borderRadius: "50%",
                  backgroundColor: semanticStatusColors[status],
                  display: "inline-block",
                }}
              />
              {statusActionLabel[status]}
            </span>
          ),
        })),
      },
      { type: "divider" },
      {
        key: "basic-info",
        label: "分类基本信息",
        icon: <InfoCircleOutlined />,
      },
      { type: "divider" },
      { key: "design", label: "属性设计", icon: <SettingOutlined /> },
      { type: "divider" },
      { key: "delete", label: "删除", icon: <DeleteOutlined />, danger: true },
    ];
    return items;
  };

  const handleRightClick: TreeProps["onRightClick"] = ({ event, node }) => {
    setContextMenuState({
      visible: true,
      x: event.clientX,
      y: event.clientY,
      node: node as DataNode,
    });
  };

  const findNodeByKey = (list: DataNode[], key: React.Key): DataNode | null => {
    for (const node of list) {
      if (node.key === key) return node;
      if (node.children) {
        const found = findNodeByKey(node.children, key);
        if (found) return found;
      }
    }
    return null;
  };

  const openCreateModal = (node?: DataNode | null) => {
    const nodeRef = (node as any)?.dataRef as
      | {
          id?: string;
          code?: string;
          name?: string;
          level?: number;
          path?: string;
          businessDomain?: string;
        }
      | undefined;

    setCreateParentNode(
      nodeRef
        ? {
            id: nodeRef.id,
            code: nodeRef.code,
            name: nodeRef.name,
            level: nodeRef.level,
            path: nodeRef.path,
            businessDomain: nodeRef.businessDomain,
            rootCode: undefined,
            rootName: undefined,
          }
        : null,
    );
    setCreateModalVisible(true);

    if (!nodeRef?.id) return;

    metaCategoryApi
      .getNodePath(nodeRef.id, nodeRef.businessDomain || defaultBusinessDomain || '')
      .then((pathNodes) => {
        const rootNode = pathNodes?.[0];
        if (!rootNode) return;
        setCreateParentNode((prev) => {
          if (!prev || prev.id !== nodeRef.id) return prev;
          return {
            ...prev,
            rootCode: rootNode.code,
            rootName: rootNode.name,
          };
        });
      })
      .catch(() => {
        // Keep fallback behavior if path query fails.
      });
  };

  const resolveCheckedNodes = (checkedKeys: React.Key[]) => {
    if (checkedKeys.length === 0) return [];
    return checkedKeys
      .map((key) => findNodeByKey(props.treeData, key))
      .filter((node): node is DataNode => !!node);
  };

  return (
    <>
      <CategoryTree
        ref={containerRef}
        {...props}
        onRightClick={handleRightClick}
        toolbarRender={(toolbarState: CategoryTreeToolbarState) => {
          const { checkableEnabled, checkedKeys } = toolbarState;
          const hasCheckedNodes = checkableEnabled && checkedKeys.length > 0;

          return (
            <AdminCategoryTreeToolbar
              searchPlaceholder={props.searchPlaceholder}
              showCheckableToggle={props.showCheckableToggle !== false}
              hasCheckedNodes={hasCheckedNodes}
              toolbarState={toolbarState}
              onAdd={() => {
                const activeKey = props.selectedKeys?.[0];
                const activeNode = activeKey ? findNodeByKey(props.treeData, activeKey) : null;
                openCreateModal(activeNode);
              }}
              onDelete={() => {
                if (!hasCheckedNodes) return;
                const nodes = resolveCheckedNodes(checkedKeys);
                if (!nodes.length) return;
                if (nodes.length === 1 && onMenuClick) {
                  onMenuClick("delete", nodes[0]);
                  return;
                }
                onBatchDelete?.(nodes);
              }}
              onCut={() => {
                if (!hasCheckedNodes) return;
                setTransferAction('move');
                setTransferCheckedKeys(checkedKeys);
                setTransferModalVisible(true);
              }}
              onCopy={() => {
                if (!hasCheckedNodes) return;
                setTransferAction('copy');
                setTransferCheckedKeys(checkedKeys);
                setTransferModalVisible(true);
              }}
              onImport={() => setImportModalVisible(true)}
              onExport={() => {
                setExportCheckedKeys([]);
                setExportModalVisible(true);
              }}
            />
          );
        }}
      />
      <FloatingContextMenu
        open={contextMenuState.visible}
        x={contextMenuState.x}
        y={contextMenuState.y}
        items={renderContextMenuItems(contextMenuState.node)}
        onMenuClick={({ key, domEvent }) => {
          domEvent.stopPropagation();
          if (key === "add") {
            openCreateModal(contextMenuState.node);
            setContextMenuState((prev) => ({ ...prev, visible: false }));
            return;
          }
          if (onMenuClick && contextMenuState.node) {
            onMenuClick(key, contextMenuState.node);
          } else {
            messageApi.info(
              `Action: ${String(key)} on Node: ${String(contextMenuState.node?.key ?? '')}`,
            );
          }
          setContextMenuState((prev) => ({ ...prev, visible: false }));
        }}
        onClose={() => {
          setContextMenuState((prev) => ({ ...prev, visible: false }));
        }}
      />

      <CreateCategoryModal
        open={createModalVisible}
        parentNode={createParentNode}
        defaultBusinessDomain={defaultBusinessDomain}
        submitLoading={createSubmitting}
        onCancel={() => setCreateModalVisible(false)}
        onOk={async (values) => {
          setCreateSubmitting(true);
          try {
            const created = await metaCategoryApi.createCategory(
              {
                code: values.code,
                generationMode: values.generationMode,
                name: values.name,
                businessDomain: values.businessDomain,
                parentId: values.parentId || undefined,
                status: values.status,
                description: values.description,
              },
              { operator: "admin" },
            );
            messageApi.success("分类创建成功");
            setCreateModalVisible(false);
            onCategoryCreated?.(created, createParentNode);
          } catch (e: any) {
            const msg = e?.message || e?.error || "分类创建失败";
            messageApi.error(msg);
            throw e;
          } finally {
            setCreateSubmitting(false);
          }
        }}
      />

      {/* 批量移动/复制视图弹窗 */}
      <BatchTransferModal
        open={transferModalVisible}
        actionType={transferAction}
        checkedKeys={transferCheckedKeys}
        fullTreeData={props.treeData}
        defaultBusinessDomain={defaultBusinessDomain}
        onCancel={() => setTransferModalVisible(false)}
        onSuccess={(response) => {
          onTransferSuccess?.(response);
          messageApi.success("批量移动/复制已完成，分类树已刷新");
        }}
      />

      {/* 导入分类弹窗 */}
      <WorkbookImportModal
        open={importModalVisible}
        onCancel={() => setImportModalVisible(false)}
        onSuccess={() => {
          setImportModalVisible(false);
          messageApi.success("分类导入完成");
        }}
        defaultBusinessDomain={defaultBusinessDomain}
      />

      {/* 导出完整数据弹窗 */}
      <WorkbookExportModal
        open={exportModalVisible}
        checkedKeys={exportCheckedKeys}
        treeData={props.treeData}
        defaultBusinessDomain={defaultBusinessDomain}
        onCancel={() => setExportModalVisible(false)}
        onSuccess={() => {
          setExportModalVisible(false);
          messageApi.success("完整数据导出文件已生成");
        }}
      />
    </>
  );
};

export default AdminCategoryTree;

import React, { useState, useEffect, useMemo, useRef } from "react";
import {
  App,
  Space,
  Typography,
  Tag,
  Splitter,
  Layout,
  theme,
  Flex,
} from "antd";
import AttributeList from "./components/AttributeList";
import AttributeWorkspace from "./components/AttributeWorkspace";
// import AttributeExportModal from "./components/export/AttributeExportModal";
import { AttributeItem, EnumOptionItem } from "./components/types";
import { metaAttributeApi } from "@/services/metaAttribute";
import {
  CreateAttributeCodePreviewRequestDto,
  MetaAttributeUpsertRequestDto,
  MetaAttributeDefListItemDto,
  MetaAttributeDefDetailDto,
} from "@/models/metaAttribute";
import dayjs from "dayjs";

const isNewAttributeId = (id?: string | null) => !!id && id.startsWith("new_attr_");
const isEnumLikeType = (type?: string | null) => type === "enum" || type === "multi-enum";
const mapAttributeTypeToBackend = (type?: string | null) => (type === "boolean" ? "bool" : type) as any;
const normalizeAttributeTypeFromBackend = (type?: string | null) => {
  if (type === 'bool') {
    return 'boolean';
  }
  if (type === 'multi_enum') {
    return 'multi-enum';
  }
  return type;
};
const normalizeDefaultValueFromBackend = (type?: string | null, value?: string | null) => {
  if (value === undefined || value === null || value === "") {
    return undefined;
  }

  if (type === "boolean") {
    const normalized = String(value).trim().toLowerCase();
    if (normalized === "true") {
      return true;
    }
    if (normalized === "false") {
      return false;
    }
    return undefined;
  }

  if (type === "number") {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : undefined;
  }

  if (type === "multi-enum") {
    return String(value)
      .split(",")
      .map((item) => item.trim())
      .filter(Boolean);
  }

  return value;
};
const serializeDefaultValueForBackend = (value?: AttributeItem["defaultValue"]) => {
  if (value === undefined || value === null) {
    return undefined;
  }

  if (Array.isArray(value)) {
    return value.length > 0 ? value.join(",") : undefined;
  }

  return String(value);
};
const normalizeCode = (value?: string | null) => String(value || "").trim();
const buildLovPreviewPlaceholder = (index: number) => `__DRAFT_ENUM_OPTION_${index + 1}__`;
const isManualCodeOverride = (value?: string | null, suggestedValue?: string | null) => {
  const normalizedValue = normalizeCode(value);
  if (!normalizedValue) {
    return false;
  }
  const normalizedSuggestedValue = normalizeCode(suggestedValue);
  return !normalizedSuggestedValue || normalizedValue !== normalizedSuggestedValue;
};

const normalizeAttributeForCompare = (attribute: AttributeItem | null) => {
  if (!attribute) return null;
  const ignoreGeneratedDraftCode =
    isNewAttributeId(attribute.id) && !isManualCodeOverride(attribute.code, attribute.suggestedCode);
  return {
    id: attribute.id,
    code: ignoreGeneratedDraftCode ? "" : attribute.code,
    name: attribute.name,
    attributeField: attribute.attributeField || "",
    type: attribute.type,
    unit: attribute.unit || "",
    required: !!attribute.required,
    unique: !!attribute.unique,
    hidden: !!attribute.hidden,
    readonly: !!attribute.readonly,
    searchable: !!attribute.searchable,
    description: attribute.description || "",
    defaultValue: attribute.defaultValue ?? null,
    min: attribute.min ?? null,
    max: attribute.max ?? null,
    step: attribute.step ?? null,
    precision: attribute.precision ?? null,
    trueLabel: attribute.trueLabel || "",
    falseLabel: attribute.falseLabel || "",
    renderType: attribute.renderType || "text",
    constraintMode: attribute.constraintMode || "none",
  };
};

const normalizeEnumOptionsForCompare = (options: EnumOptionItem[]) =>
  options.map((item) => ({
    code: item.code || "",
    value: item.value || "",
    label: item.label || "",
    image: item.image || "",
    order: item.order ?? 0,
  }));

const createEmptyAttributeDraft = (id: string): AttributeItem => ({
  id,
  code: "",
  suggestedCode: "",
  freezeKey: false,
  name: "",
  attributeField: "",
  type: "enum",
  unit: "",
  required: false,
  description: "",
  defaultValue: undefined,
  hidden: false,
  readonly: false,
  searchable: false,
  unique: false,
  min: undefined,
  max: undefined,
  step: undefined,
  precision: undefined,
  trueLabel: "",
  falseLabel: "",
  constraintMode: 'none',
  renderType: 'text',
  version: 1,
  isLatest: true,
});

interface Props {
  currentNode?: { title?: string; code?: string; [key: string]: any };
  onUnsavedStateChange?: (state: {
    hasUnsavedChanges: boolean;
    unsavedNewCount: number;
  }) => void;
}

const AttributeDesigner: React.FC<Props> = ({
  currentNode,
  onUnsavedStateChange,
}) => {
  const { token } = theme.useToken();
  const { message: messageApi, modal } = App.useApp();
  const [selectedAttributeId, setSelectedAttributeId] = useState<string | null>(
    null,
  );
  const [selectedAttributeIds, setSelectedAttributeIds] = useState<string[]>([]);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
  const [searchText, setSearchText] = useState("");
  const [dataSource, setDataSource] = useState<AttributeItem[]>([]);
  const [loading, setLoading] = useState(false);

  const [currentAttribute, setCurrentAttribute] =
    useState<AttributeItem | null>(null);
  const [baselineAttribute, setBaselineAttribute] =
    useState<AttributeItem | null>(null);
  const [enumOptions, setEnumOptions] = useState<EnumOptionItem[]>([]);
  const [baselineEnumOptions, setBaselineEnumOptions] = useState<EnumOptionItem[]>([]);
  const previewTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const previewRequestIdRef = useRef(0);
  const [previewLoading, setPreviewLoading] = useState(false);
  const [previewWarnings, setPreviewWarnings] = useState<string[]>([]);
  const [allowManualCodeOverride, setAllowManualCodeOverride] = useState(false);
  const [allowManualEnumCodeOverride, setAllowManualEnumCodeOverride] = useState(false);
  const [attributeExportVisible, setAttributeExportVisible] = useState(false);
  const currentBusinessDomain = String(currentNode?.businessDomain || "").trim();

  // Helper: Map Backend DTO List Item to Frontend AttributeItem
  const mapListItemToAttributeItem = (dto: MetaAttributeDefListItemDto): AttributeItem => {
    const normalizedType = normalizeAttributeTypeFromBackend(dto.dataType) as AttributeItem["type"];

    return {
    id: dto.key,
    code: dto.key,
    suggestedCode: dto.key,
    name: dto.displayName,
    attributeField: dto.attributeField || undefined,
    type: normalizedType,
    unit: dto.unit || undefined,
    version: dto.latestVersionNo,
    isLatest: true,
    // Map the new extended fields from list API
    required: dto.required,
    unique: dto.unique,
    hidden: dto.hidden,
    readonly: dto.readOnly,
    searchable: dto.searchable,
    };
  };

   // Helper: Map Backend Detail DTO to Frontend AttributeItem
   const mapDetailToAttributeItem = (dto: MetaAttributeDefDetailDto): AttributeItem => {
    const normalizedType = normalizeAttributeTypeFromBackend(dto.latestVersion.dataType) as AttributeItem["type"];

    return {
    id: dto.key,
    code: dto.key,
    suggestedCode: dto.key,
    name: dto.latestVersion.displayName,
      attributeField: dto.latestVersion.attributeField || undefined,
    type: normalizedType,
    unit: dto.latestVersion.unit || undefined,
    defaultValue: normalizeDefaultValueFromBackend(normalizedType, dto.latestVersion.defaultValue),
    required: dto.latestVersion.required,
    unique: dto.latestVersion.unique,
    hidden: dto.latestVersion.hidden,
    readonly: dto.latestVersion.readOnly,
    searchable: dto.latestVersion.searchable,
    version: dto.latestVersion.versionNo,
    isLatest: true, 
    createdBy: dto.createdBy,
    createdAt: dto.createdAt ? dayjs(dto.createdAt).format("YYYY-MM-DD HH:mm:ss") : undefined,
    modifiedBy: dto.modifiedBy,
    modifiedAt: dto.modifiedAt ? dayjs(dto.modifiedAt).format("YYYY-MM-DD HH:mm:ss") : undefined,
    description: dto.latestVersion.description || undefined,
    
    // Map extended value configurations
    min: dto.latestVersion.minValue,
    max: dto.latestVersion.maxValue,
    step: dto.latestVersion.step,
    precision: dto.latestVersion.precision,
    trueLabel: dto.latestVersion.trueLabel,
    falseLabel: dto.latestVersion.falseLabel,
    };
  };

  const loadAttributes = async (
    categoryCode: string,
    businessDomain?: string,
    selectAttributeId?: string,
    localUnsavedItems: AttributeItem[] = [],
  ) => {
    setLoading(true);
    try {
      const res = await metaAttributeApi.listAttributes({ 
        businessDomain,
        categoryCode,
        page: 0,
        size: 100,
      });
      const merged = [...res.content.map(mapListItemToAttributeItem), ...localUnsavedItems];
      setDataSource(merged);
      
      if (selectAttributeId) {
        setSelectedAttributeId(selectAttributeId);
        setSelectedAttributeIds([selectAttributeId]);
      }
    } catch (e) {
      console.error(e);
      messageApi.error("加载属性列表失败");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (currentNode?.code) {
      loadAttributes(currentNode.code, currentBusinessDomain, undefined, []);
      setSelectedAttributeId(null);
      setSelectedAttributeIds([]);
      setCurrentAttribute(null);
      setBaselineAttribute(null);
      setEnumOptions([]);
      setBaselineEnumOptions([]);
      setHasUnsavedChanges(false);
    } else {
      setDataSource([]);
      setSelectedAttributeId(null);
      setSelectedAttributeIds([]);
      setCurrentAttribute(null);
      setBaselineAttribute(null);
      setEnumOptions([]);
      setBaselineEnumOptions([]);
      setHasUnsavedChanges(false);
    }
  }, [currentBusinessDomain, currentNode]);

  // Sync currentAttribute from dataSource when selection changes
  useEffect(() => {
    const fetchDetail = async () => {
      if (selectedAttributeId && selectedAttributeIds.length === 1) {
        // First check if it's a new unsaved item (local only) using ID
        if (selectedAttributeId.startsWith('new_attr_')) {
             const localItem = dataSource.find(i => i.id === selectedAttributeId);
             if (localItem) {
               const snapshot = { ...localItem };
               setCurrentAttribute(snapshot);
               setBaselineAttribute(snapshot);
                setEnumOptions([]);
               setBaselineEnumOptions([]);
             }
             return;
        }

          if (!currentBusinessDomain) {
           setCurrentAttribute(null);
           setBaselineAttribute(null);
           setEnumOptions([]);
           setBaselineEnumOptions([]);
           return;
          }

        try {
           console.log(`Fetching detail for ${selectedAttributeId}`);
            const detail = await metaAttributeApi.getAttributeDetail(selectedAttributeId, currentBusinessDomain, true); // includeValues=true
           const mapped = mapDetailToAttributeItem(detail);
           setCurrentAttribute(mapped);
           setBaselineAttribute(mapped);
           
           // Load enum options if present
           if (detail.lovValues && detail.lovValues.length > 0) {
             const mappedOptions = detail.lovValues.map((v: any, index: number) => ({
               id: `enum_${index}`,
               code: v.code,
               suggestedCode: v.code,
               value: v.value, // Backend detail DTO uses `value`
               label: v.label || '',
               order: index
             }));
             setEnumOptions(mappedOptions);
             setBaselineEnumOptions(mappedOptions);
           } else {
             setEnumOptions([]);
             setBaselineEnumOptions([]);
           }
        } catch(e) {
           console.error('Fetch detail failed', e);
            messageApi.error("Failed to load attribute details");
        }
      } else {
        setCurrentAttribute(null);
        setBaselineAttribute(null);
        setEnumOptions([]);
        setBaselineEnumOptions([]);
      }
    };
    fetchDetail();
  }, [currentBusinessDomain, selectedAttributeId, selectedAttributeIds.length, dataSource]);

  // Sync selection state when dataSource changes (e.g. deletion)
  useEffect(() => {
    if (selectedAttributeId && !dataSource.some(item => item.id === selectedAttributeId)) {
      setSelectedAttributeId(null);
    }
    setSelectedAttributeIds((prev) => prev.filter((id) => dataSource.some((item) => item.id === id)));
  }, [dataSource, selectedAttributeId]);

  const computedDirty = useMemo(() => {
    if (!currentAttribute || !baselineAttribute) return false;
    const attrDirty =
      JSON.stringify(normalizeAttributeForCompare(currentAttribute)) !==
      JSON.stringify(normalizeAttributeForCompare(baselineAttribute));

    const enumDirty =
      JSON.stringify(normalizeEnumOptionsForCompare(enumOptions)) !==
      JSON.stringify(normalizeEnumOptionsForCompare(baselineEnumOptions));

    return attrDirty || enumDirty;
  }, [currentAttribute, baselineAttribute, enumOptions, baselineEnumOptions]);

  const effectiveHasUnsavedChanges = computedDirty;

  useEffect(() => {
    setHasUnsavedChanges(computedDirty);
  }, [computedDirty]);

  const enumPreviewSignature = useMemo(() => {
    if (!currentAttribute || !isEnumLikeType(currentAttribute.type)) {
      return "";
    }
    return JSON.stringify(
      enumOptions.map((item) => ({
        id: item.id,
        value: item.value || "",
        label: item.label || "",
        code: item.code || "",
        suggestedCode: item.suggestedCode || "",
      })),
    );
  }, [currentAttribute?.id, currentAttribute?.type, enumOptions]);

  useEffect(() => {
    if (previewTimerRef.current) {
      clearTimeout(previewTimerRef.current);
      previewTimerRef.current = null;
    }

    const categoryCode = currentNode?.code;
    const isNewAttribute = isNewAttributeId(currentAttribute?.id);
    const enumLike = currentAttribute ? isEnumLikeType(currentAttribute.type) : false;
    const persistedAttributeCode = currentAttribute ? normalizeCode(currentAttribute.code) : "";
    const hasExistingEnumRowsNeedingPreview =
      enumLike &&
      !isNewAttribute &&
      enumOptions.some((item) => !normalizeCode(item.code));
    const canPreviewExistingEnumCodes = Boolean(
      persistedAttributeCode && hasExistingEnumRowsNeedingPreview,
    );

    if (!currentAttribute || !categoryCode || !currentBusinessDomain || (!isNewAttribute && !canPreviewExistingEnumCodes)) {
      setPreviewLoading(false);
      setPreviewWarnings([]);
      setAllowManualCodeOverride(false);
      setAllowManualEnumCodeOverride(false);
      return;
    }

    const attributeManualOverride = isManualCodeOverride(currentAttribute.code, currentAttribute.suggestedCode);
    const manualCode = attributeManualOverride ? normalizeCode(currentAttribute.code) : "";
    const previewManualKey = isNewAttribute
      ? (attributeManualOverride ? manualCode : undefined)
      : persistedAttributeCode || undefined;
    const previewLovValues: NonNullable<CreateAttributeCodePreviewRequestDto["lovValues"]> = enumLike
      ? enumOptions
          .map((item, index) => {
            const manualEnumCode = isManualCodeOverride(item.code, item.suggestedCode)
              ? normalizeCode(item.code) || undefined
              : undefined;
            const normalizedValue = item.value?.trim() || undefined;
            const normalizedLabel = item.label?.trim() || undefined;

            return {
              code: manualEnumCode,
              // 后端仅对 name/label 非空的项生成 preview，因此新增空行需要占位值参与预览。
              name: normalizedValue || normalizedLabel || buildLovPreviewPlaceholder(index),
              label: normalizedLabel,
            };
          })
          .filter((item) => item.code || item.name || item.label)
      : [];
    const hasPendingManualAttributeCode = attributeManualOverride && !manualCode;
    const hasPendingManualEnumCode =
      enumLike &&
      enumOptions.some((item) => {
        const hasContent = normalizeCode(item.value) || normalizeCode(item.label);
        return !!hasContent && isManualCodeOverride(item.code, item.suggestedCode) && !normalizeCode(item.code);
      });

    if (isNewAttribute && hasPendingManualAttributeCode) {
      setPreviewLoading(false);
      setPreviewWarnings([]);
      return;
    }

    previewTimerRef.current = setTimeout(async () => {
      const requestId = ++previewRequestIdRef.current;
      setPreviewLoading(true);

      try {
        const preview = await metaAttributeApi.previewCreateCode(currentBusinessDomain, categoryCode, {
          manualKey: previewManualKey,
          dataType: mapAttributeTypeToBackend(currentAttribute.type),
          count: 1,
          lovValues: hasPendingManualEnumCode ? undefined : previewLovValues,
        });

        if (requestId !== previewRequestIdRef.current) {
          return;
        }

        setAllowManualCodeOverride(Boolean(preview.allowManualOverride));
        setAllowManualEnumCodeOverride(Boolean(preview.allowLovValueManualOverride));
        setPreviewWarnings([...(preview.warnings || []), ...(preview.lovWarnings || [])]);

        if (isNewAttribute && !attributeManualOverride) {
          setCurrentAttribute((prev) => {
            if (!prev || prev.id !== currentAttribute.id) {
              return prev;
            }
            const suggestedCode = preview.suggestedCode || "";
            if (prev.code === suggestedCode && prev.suggestedCode === suggestedCode) {
              return prev;
            }
            return { ...prev, code: suggestedCode, suggestedCode };
          });
        } else if (!preview.allowManualOverride) {
          setCurrentAttribute((prev) => {
            if (!prev || prev.id !== currentAttribute.id) {
              return prev;
            }
            const suggestedCode = prev.suggestedCode || preview.suggestedCode || "";
            return {
              ...prev,
              code: suggestedCode,
              suggestedCode,
            };
          });
        }

        if (!enumLike) {
        } else if (isNewAttribute && !preview.allowManualOverride) {
          return;
        }

        const previewCodeByIndex = new Map(
          (preview.lovValuePreviews || []).map((item) => [item.index, item.suggestedCode || ""]),
        );

        setEnumOptions((prev) =>
          prev.map((item, index) => {
            const suggestedCode = previewCodeByIndex.get(index);
            if (suggestedCode == null) {
              return item;
            }
            const manualEnumOverride = isManualCodeOverride(item.code, item.suggestedCode);
            if (manualEnumOverride && preview.allowLovValueManualOverride) {
              return item;
            }
            if (item.code === suggestedCode && item.suggestedCode === suggestedCode) {
              return item;
            }
            return { ...item, code: suggestedCode, suggestedCode };
          }),
        );
      } catch (e: any) {
        if (requestId !== previewRequestIdRef.current) {
          return;
        }

        setPreviewWarnings([e?.message || e?.error || "属性编码预计算失败"]);

        if (isNewAttribute && !attributeManualOverride) {
          setCurrentAttribute((prev) => {
            if (!prev || prev.id !== currentAttribute.id || !prev.code) {
              return prev;
            }
            return { ...prev, code: "", suggestedCode: "" };
          });
        }

        if (enumLike) {
          setEnumOptions((prev) => prev.map((item) => {
            if (isManualCodeOverride(item.code, item.suggestedCode)) {
              return item;
            }
            return item.code || item.suggestedCode ? { ...item, code: "", suggestedCode: "" } : item;
          }));
        }
      } finally {
        if (requestId === previewRequestIdRef.current) {
          setPreviewLoading(false);
        }
      }
    }, attributeManualOverride || hasPendingManualEnumCode ? 300 : 0);

    return () => {
      if (previewTimerRef.current) {
        clearTimeout(previewTimerRef.current);
        previewTimerRef.current = null;
      }
    };
  }, [currentAttribute?.id, currentAttribute?.type, currentAttribute?.code, currentAttribute?.suggestedCode, currentBusinessDomain, enumPreviewSignature, currentNode?.code]);

  useEffect(() => {
    const handleBeforeUnload = (event: BeforeUnloadEvent) => {
      if (!effectiveHasUnsavedChanges) return;
      event.preventDefault();
      event.returnValue = "";
    };

    window.addEventListener("beforeunload", handleBeforeUnload);
    return () => {
      window.removeEventListener("beforeunload", handleBeforeUnload);
    };
  }, [effectiveHasUnsavedChanges]);

  const handleAttributeUpdate = (key: string, value: any) => {
    if (!currentAttribute) return;
    const updated = { ...currentAttribute, [key]: value };
    setCurrentAttribute(updated);
  };

  const resetWorkspaceState = () => {
    setCurrentAttribute(null);
    setBaselineAttribute(null);
    setEnumOptions([]);
    setBaselineEnumOptions([]);
    setPreviewWarnings([]);
    setHasUnsavedChanges(false);
  };

  const discardCurrentEditingState = () => {
    if (selectedAttributeId && isNewAttributeId(selectedAttributeId)) {
      setDataSource((prev) => prev.filter((item) => item.id !== selectedAttributeId));
      setSelectedAttributeIds((prev) => prev.filter((id) => id !== selectedAttributeId));
      setSelectedAttributeId(null);
      resetWorkspaceState();
      return;
    }

    if (baselineAttribute) {
      setCurrentAttribute({ ...baselineAttribute });
      setEnumOptions([...baselineEnumOptions]);
    }
    setPreviewWarnings([]);
    setHasUnsavedChanges(false);
  };

  const runWithUnsavedChangesGuard = (action: () => void) => {
    if (!effectiveHasUnsavedChanges) {
      action();
      return;
    }

    modal.confirm({
      title: "当前属性修改尚未保存，是否放弃修改？",
      content: "继续操作后未保存内容将丢失。",
      okText: "放弃并继续",
      cancelText: "继续编辑",
      okType: "danger",
      onOk: () => {
        discardCurrentEditingState();
        action();
      },
    });
  };

  const applyMultiSelection = (ids: string[], primaryId: string | null) => {
    setCurrentAttribute(null);
    setBaselineAttribute(null);
    setEnumOptions([]);
    setBaselineEnumOptions([]);
    setPreviewWarnings([]);
    setSelectedAttributeIds(ids);
    setSelectedAttributeId(ids.length === 1 ? (primaryId || ids[0]) : null);
  };

  const tryApplySelectionChange = (ids: string[], primaryId: string | null) => {
    const normalizedIds = ids.filter((id) => dataSource.some((item) => item.id === id));
    const nextPrimary = normalizedIds.length === 1 ? (primaryId || normalizedIds[0]) : null;
    const samePrimary = selectedAttributeId === nextPrimary;

    if (samePrimary) {
      setSelectedAttributeIds(normalizedIds);
      return;
    }

    if (!effectiveHasUnsavedChanges) {
      applyMultiSelection(normalizedIds, nextPrimary);
      return;
    }

    runWithUnsavedChangesGuard(() => {
      applyMultiSelection(normalizedIds, nextPrimary);
    });
  };

  const handleAddAttribute = () => {
    runWithUnsavedChangesGuard(() => {
      const timestamp = Date.now();
      const newAttr = createEmptyAttributeDraft(`new_attr_${timestamp}`);
      setDataSource((prev) => [...prev, newAttr]);
      setSelectedAttributeId(newAttr.id);
      setSelectedAttributeIds([newAttr.id]);
      setCurrentAttribute({ ...newAttr });
      setBaselineAttribute({ ...newAttr });
      setEnumOptions([]);
      setBaselineEnumOptions([]);
      setPreviewWarnings([]);
      setHasUnsavedChanges(false);
    });
  };

  const handleDuplicateAttribute = (source: AttributeItem) => {
    runWithUnsavedChangesGuard(() => {
      const timestamp = Date.now();
      const duplicate: AttributeItem = {
        ...source,
        id: `new_attr_${timestamp}`,
        code: "",
        suggestedCode: "",
        freezeKey: false,
        name: source.name ? `${source.name}_COPY` : "",
        version: 1,
        isLatest: true,
      };
      setDataSource((prev) => [...prev, duplicate]);
      setSelectedAttributeId(duplicate.id);
      setSelectedAttributeIds([duplicate.id]);
      setCurrentAttribute({ ...duplicate });
      setBaselineAttribute({ ...duplicate });
      setEnumOptions([]);
      setBaselineEnumOptions([]);
      setPreviewWarnings([]);
      setHasUnsavedChanges(false);
    });
  };

  const handleSingleSave = async (
    attribute: AttributeItem,
    options?: { saveAndNext?: boolean },
  ) => {
      if (!currentNode?.code || !currentBusinessDomain) {
        messageApi.error("缺少业务领域上下文，无法保存属性");
        return;
      }
      
      const isNew = attribute.id.startsWith("new_attr_");
      const attributeManualOverride = isNew && allowManualCodeOverride && isManualCodeOverride(attribute.code, attribute.suggestedCode);
      const unsavedNewItems = dataSource.filter((item) => isNewAttributeId(item.id));
      const currentNewIndex = unsavedNewItems.findIndex((item) => item.id === attribute.id);
      const nextUnsavedNewId =
        options?.saveAndNext && currentNewIndex > -1 && currentNewIndex < unsavedNewItems.length - 1
          ? unsavedNewItems[currentNewIndex + 1].id
          : undefined;

      // Use the modified code if not new, or the new code
      const dto: MetaAttributeUpsertRequestDto = {
          key: isNew && !attributeManualOverride ? undefined : attribute.code,
          generationMode: isNew && attributeManualOverride ? "MANUAL" : undefined,
          freezeKey: isNew ? Boolean(attribute.freezeKey) : undefined,
          displayName: attribute.name,
          attributeField: attribute.attributeField,
          dataType: mapAttributeTypeToBackend(attribute.type),
          unit: attribute.unit,
          defaultValue: serializeDefaultValueForBackend(attribute.defaultValue),
          required: attribute.required,
          unique: attribute.unique,
          hidden: attribute.hidden,
          readOnly: attribute.readonly,
          searchable: attribute.searchable,
          description: attribute.description,
          
          // Extended value configurations
          minValue: attribute.min,
          maxValue: attribute.max,
          step: attribute.step,
          precision: attribute.precision,
          trueLabel: attribute.trueLabel,
          falseLabel: attribute.falseLabel,
          lovValues: attribute.type === 'enum' || attribute.type === 'multi-enum' 
            ? enumOptions.map(opt => ({
              code: isNew && !(allowManualEnumCodeOverride && isManualCodeOverride(opt.code, opt.suggestedCode)) ? undefined : opt.code,
                name: opt.value, // Using value as name for now
                label: opt.label
              }))
            : undefined
      };

      try {
            let savedDetail: MetaAttributeDefDetailDto;
          if (isNew) {
          savedDetail = await metaAttributeApi.createAttribute(currentBusinessDomain, currentNode.code, dto);
              messageApi.success("Created successfully");
          } else {
          savedDetail = await metaAttributeApi.updateAttribute(attribute.code, currentBusinessDomain, currentNode.code, dto);
              messageApi.success("Updated successfully");
          }

          const remainingUnsavedItems = dataSource.filter(
            (item) => !isNewAttributeId(item.id) || item.id !== attribute.id,
          );

          const targetId = nextUnsavedNewId || savedDetail.key;
          await loadAttributes(
            currentNode.code,
            currentBusinessDomain,
            targetId,
            remainingUnsavedItems.filter((item) => isNewAttributeId(item.id)),
          );

          if (nextUnsavedNewId) {
            setSelectedAttributeId(nextUnsavedNewId);
          }

          if (isNew) {
            setDataSource((prev) => prev.filter((item) => item.id !== attribute.id));
          }

          setBaselineAttribute(null);
          setBaselineEnumOptions([]);
          setHasUnsavedChanges(false);
      } catch (e: any) {
          console.error("Save error:", e);
          // Since request.ts interceptor now rejects with error.response.data directly
          let errorMsg = e.message || e.error || "Operation failed";
          
          // User-friendly error message translation
          if (errorMsg.includes("attribute code already exists in business domain") || errorMsg.includes("attribute already exists")) {
            errorMsg = `保存失败：属性编码在当前业务领域内已存在，请使用其他编码。`;
          } else if (errorMsg.includes("enum option code already exists in business domain")) {
            errorMsg = "保存失败：枚举值编码在当前业务领域内已存在，请调整后重试。";
          } else if (errorMsg.includes("INVALID_ARGUMENT")) {
            errorMsg = `参数错误：${errorMsg}`;
          } else {
            errorMsg = `保存失败：${errorMsg}`;
          }
          
            messageApi.error(errorMsg);
          throw e; // Throw to let Workspace know it failed
      }
  };

  const handleDeleteAttribute = (attribute: AttributeItem) => {
    modal.confirm({
      title: "确认删除 (Confirm Delete)",
      content: `确定要删除属性 "${attribute.name}" 吗？此操作不可恢复。`,
      okType: "danger",
      onOk: async () => {
        // If it's a new unsaved attribute, just remove from list
        if (attribute.id.startsWith("new_attr_")) {
          setDataSource((prev) => prev.filter((item) => item.id !== attribute.id));
          if (selectedAttributeId === attribute.id) {
            setSelectedAttributeId(null);
            setSelectedAttributeIds((prev) => prev.filter((id) => id !== attribute.id));
            setCurrentAttribute(null);
            setBaselineAttribute(null);
            setEnumOptions([]);
            setBaselineEnumOptions([]);
          }
          messageApi.success("已移除 (Removed)");
          return;
        }

        // If it's a real backend attribute
        if (!currentNode?.code || !currentBusinessDomain) {
          messageApi.error("缺少业务领域上下文，无法删除属性");
          return;
        }

        try {
          await metaAttributeApi.deleteAttribute(attribute.code, currentBusinessDomain, currentNode.code);
          messageApi.success("删除成功 (Deleted)");
          // Refresh list
          loadAttributes(
            currentNode.code,
            currentBusinessDomain,
            undefined,
            dataSource.filter((item) => isNewAttributeId(item.id)),
          );
        } catch (e) {
          console.error(e);
          messageApi.error("删除失败 (Delete Failed)");
        }
      },
    });
  };

  const handleBatchRemoveAttributes = (ids: string[]) => {
    const unsavedIds = ids.filter((id) => isNewAttributeId(id));
    const persistedCount = ids.length - unsavedIds.length;

    if (unsavedIds.length > 0) {
      setDataSource((prev) => prev.filter((item) => !unsavedIds.includes(item.id)));
      setSelectedAttributeIds((prev) => prev.filter((id) => !unsavedIds.includes(id)));
      if (selectedAttributeId && unsavedIds.includes(selectedAttributeId)) {
        setSelectedAttributeId(null);
        setCurrentAttribute(null);
        setBaselineAttribute(null);
        setEnumOptions([]);
        setBaselineEnumOptions([]);
      }
      messageApi.success(`已批量移除 ${unsavedIds.length} 条未保存新属性`);
    }

    if (persistedCount > 0) {
      messageApi.warning("批量移除仅支持未保存的新属性，已存在属性请单条删除");
    }
  };

  const hasNextUnsavedNew = useMemo(() => {
    if (!selectedAttributeId || !isNewAttributeId(selectedAttributeId)) return false;
    const unsavedNewIds = dataSource.filter((item) => isNewAttributeId(item.id)).map((item) => item.id);
    const index = unsavedNewIds.findIndex((id) => id === selectedAttributeId);
    return index > -1 && index < unsavedNewIds.length - 1;
  }, [dataSource, selectedAttributeId]);

  const unsavedNewCount = useMemo(
    () => dataSource.filter((item) => isNewAttributeId(item.id)).length,
    [dataSource],
  );

  useEffect(() => {
    onUnsavedStateChange?.({
      hasUnsavedChanges: effectiveHasUnsavedChanges,
      unsavedNewCount,
    });
  }, [effectiveHasUnsavedChanges, unsavedNewCount, onUnsavedStateChange]);

  const handleSaveAll = () => {
    // Optional: Bulk save implementation if backend supports it, otherwise warn user
    messageApi.info("Please save each attribute individually in the workspace.");
  };

  // Modal Title
  const modalTitle = (
    <Space align="center">
      <Typography.Title level={5} style={{ margin: 0 }}>
        &gt; {currentNode?.title || "未知对象 (Unknown Item)"}
      </Typography.Title>
      {effectiveHasUnsavedChanges && (
         <Tag color="warning" variant="filled" style={{ marginLeft: 8 }}>
            未保存 (Unsaved Changes)
         </Tag>
      )}
    </Space>
  );

  // Toolbar Actions
  const renderToolbar = () => (
    <Flex
      justify="space-between"
      align="center"
      style={{
        height: 48,
        padding: "0 16px",
        borderBottom: `1px solid ${token.colorBorderSecondary}`,
        background: token.colorBgLayout,
      }}
    >
      <Space>
        <Typography.Title level={5} style={{ margin: 0, marginRight: 16 }}>
          {currentNode?.title || "未知对象 (Unknown Item)"}
        </Typography.Title>
      </Space>
      <Space>
        {/* <Button icon={<EyeOutlined />}>预览 (Preview)</Button> */}
        {/* <Button icon={<HistoryOutlined />}>日志 (Log)</Button> */}
        {/* Bulk Save is disabled or hidden as we move to single save */}
        {/* <Button type="primary" icon={<SaveOutlined />} onClick={handleSaveAll}>保存模型</Button> */}
      </Space>
    </Flex>
  );

  return (
    <Layout style={{ height: "100%", flexDirection: "column", overflow: "hidden" }}>
      {renderToolbar()}

      <Splitter style={{ flex: 1, minHeight: 0 }}>
        <Splitter.Panel defaultSize={450} min={350} max={550} collapsible>
          <AttributeList
            dataSource={dataSource}
            setDataSource={setDataSource}
            selectedAttributeIds={selectedAttributeIds}
            activeAttributeId={selectedAttributeId}
            onSelectionChange={tryApplySelectionChange}
            searchText={searchText}
            onSearchTextChange={setSearchText}
            onAddAttribute={handleAddAttribute}
            onDuplicateAttribute={handleDuplicateAttribute}
            onDeleteAttribute={handleDeleteAttribute}
            onBatchRemoveAttributes={handleBatchRemoveAttributes}
            onExportAttributes={() => setAttributeExportVisible(true)}
          />
        </Splitter.Panel>
        <Splitter.Panel>
          <AttributeWorkspace
            key={selectedAttributeIds.length === 1 ? (currentAttribute?.id || selectedAttributeId || 'attribute-workspace-empty') : 'attribute-workspace-multi'}
            attribute={selectedAttributeIds.length === 1 ? currentAttribute : null}
            selectedCount={selectedAttributeIds.length}
            onUpdate={handleAttributeUpdate}
            enumOptions={enumOptions}
            setEnumOptions={setEnumOptions}
            previewLoading={previewLoading}
            previewWarnings={previewWarnings}
            allowManualCodeOverride={allowManualCodeOverride}
            allowManualEnumCodeOverride={allowManualEnumCodeOverride}
            onSave={(attribute) => handleSingleSave(attribute, { saveAndNext: false })}
            onSaveAndNext={(attribute) => handleSingleSave(attribute, { saveAndNext: true })}
            showSaveAndNext={hasNextUnsavedNew}
            hasUnsavedChanges={effectiveHasUnsavedChanges}
            onDiscard={(id) => {
              setDataSource((prev) => prev.filter((item) => item.id !== id));
              if (selectedAttributeId === id) {
                setSelectedAttributeId(null);
              }
              setSelectedAttributeIds((prev) => prev.filter((itemId) => itemId !== id));
              setCurrentAttribute(null);
              setBaselineAttribute(null);
              setEnumOptions([]);
              setBaselineEnumOptions([]);
              setHasUnsavedChanges(false);
            }}
            onCancelEdit={() => {
              if (baselineAttribute) {
                setCurrentAttribute({ ...baselineAttribute });
                setEnumOptions([...baselineEnumOptions]);
              }
              setHasUnsavedChanges(false);
            }}
          />
        </Splitter.Panel>
      </Splitter>

      {/* <AttributeExportModal
        open={attributeExportVisible}
        attributes={dataSource}
        selectedAttributeIds={selectedAttributeIds}
        categoryTitle={currentNode?.title}
        onCancel={() => setAttributeExportVisible(false)}
      /> */}
    </Layout>
  );
};

export default AttributeDesigner;

"use client";

import React, { useState, useEffect } from "react";
import { App, Splitter, Input, Drawer, Descriptions, Typography, theme, Spin, Empty, Divider, Button, Form, Select, Space, Card, Row, Col, Tabs } from "antd";
import type { DataNode, TreeProps } from "antd/es/tree";
import dynamic from "next/dynamic";
import CategoryTree from "../AdminCategoryTree";
import VersionGraph from "@/components/VersionGraph";
import {
  metaCategoryApi,
  MetaCategoryNodeDto,
  type MetaCategoryBatchTransferResponseDto,
  type MetaCategoryBatchTransferTopologyResponseDto,
  type MetaCategoryDetailDto,
} from "@/services/metaCategory";
import BatchDeleteModal, { type DeleteTargetNode } from "../components/BatchDeleteModal";
import {
  CheckCircleOutlined,
  ClockCircleOutlined,
  StopOutlined,
  QuestionCircleOutlined,
} from "@ant-design/icons";
import AttributeDesigner from "../AttributeDesigner";
import { useDictionary } from "@/contexts/DictionaryContext";
import type { MetaDictionaryEntryDto } from "@/models/dictionary";
import {
  CATEGORY_BUSINESS_DOMAIN_DICT_CODE,
  getCategoryBusinessDomainConfigs,
  getCategoryBusinessDomainPath,
  getDefaultCategoryBusinessDomain,
  resolveCategoryBusinessDomain,
} from "@/features/category/businessDomains";

import { useParams, useRouter } from "next/navigation";

const ReactQuill = dynamic(() => import("react-quill-new"), { ssr: false });
const EMPTY_QUILL_DELTA_JSON = '{"ops":[{"insert":"\\n"}]}'

const normalizeDeltaJson = (value?: string) => {
  if (!value || typeof value !== "string") {
    return EMPTY_QUILL_DELTA_JSON;
  }
  try {
    return JSON.stringify(JSON.parse(value));
  } catch {
    return value;
  }
};

const quillModules = {
  toolbar: [
    [{ header: [1, 2, 3, false] }],
    [{ font: [] }],
    ["bold", "italic", "underline", "strike"],
    [{ color: [] }, { background: [] }],
    [{ list: "ordered" }, { list: "bullet" }],
    [{ align: [] }],
    ["blockquote", "code-block"],
    ["link", "image"],
    ["clean"],
  ],
};

const quillFormats = [
  "header",
  "font",
  "bold",
  "italic",
  "underline",
  "strike",
  "color",
  "background",
  "list",
  "align",
  "blockquote",
  "code-block",
  "link",
  "image",
];

interface CategoryTreeNode extends Omit<DataNode, "children"> {
  children?: CategoryTreeNode[];
  dataRef?: CategoryNodeRef;
  level?: "segment" | "family" | "class" | "commodity" | "item";
  loaded?: boolean;
  familyCode?: string;
  classCode?: string; // For Commodity nodes to know their parent Class
  commodityCode?: string;
}

interface CategoryNodeRef extends MetaCategoryNodeDto {
  key?: string;
  title?: string;
  depth?: number;
}

type BatchTransferSuccessResponse =
  | MetaCategoryBatchTransferResponseDto
  | MetaCategoryBatchTransferTopologyResponseDto;

const getChildLevel = (
  level?: CategoryTreeNode["level"],
): CategoryTreeNode["level"] | undefined => {
  if (level === "segment") return "family";
  if (level === "family") return "class";
  if (level === "class") return "commodity";
  if (level === "commodity") return "item";
  return undefined;
};

const resolveStatusSemantic = (
  status: string | undefined,
  entries: MetaDictionaryEntryDto[],
) => {
  const normalized = String(status || "").toUpperCase();
  const matched = entries.find((entry) => {
    const dbValue = typeof entry.extra?.dbValue === "string" ? entry.extra.dbValue : undefined;
    return [entry.key, entry.value, dbValue]
      .filter(Boolean)
      .some((item) => String(item).toUpperCase() === normalized);
  });
  return String(matched?.value || normalized).toUpperCase();
};

const getStatusIcon = (status?: string, entries: MetaDictionaryEntryDto[] = []) => {
  const semantic = resolveStatusSemantic(status, entries);

  if (semantic === "CREATED" || semantic === "DRAFT") {
    return <ClockCircleOutlined style={{ color: "#faad14" }} />;
  }

  if (semantic === "EFFECTIVE" || semantic === "ACTIVE") {
    return <CheckCircleOutlined style={{ color: "#52c41a" }} />;
  }

  if (semantic === "INVALID" || semantic === "INACTIVE") {
    return <StopOutlined style={{ color: "#ff4d4f" }} />;
  }

  return <QuestionCircleOutlined style={{ color: "#8c8c8c" }} />;
};

const getLevelByNumber = (level?: number): CategoryTreeNode["level"] => {
  if (level === 1) return "segment";
  if (level === 2) return "family";
  if (level === 3) return "class";
  if (level === 4) return "commodity";
  return "item";
};

const deltaJsonToPlainText = (input?: string | null) => {
  if (!input) return "";
  try {
    const parsed = JSON.parse(input);
    if (!parsed || !Array.isArray(parsed.ops)) return input;
    return parsed.ops
      .map((op: any) => (typeof op?.insert === "string" ? op.insert : ""))
      .join("")
      .trim();
  } catch {
    return input;
  }
};

const toSemanticCategoryStatus = (status?: string): "CREATED" | "EFFECTIVE" | "INVALID" => {
  const normalized = String(status || "").toUpperCase();
  if (normalized === "EFFECTIVE" || normalized === "ACTIVE") return "EFFECTIVE";
  if (normalized === "INVALID" || normalized === "INACTIVE") return "INVALID";
  return "CREATED";
};

const CategoryManagementPage: React.FC = () => {
  const { message: messageApi, modal } = App.useApp();
  const { token } = theme.useToken();
  const { ensureScene, getEntries, getLabel } = useDictionary();
  const router = useRouter();
  const params = useParams();
  const routeBusinessDomain = params.id as string;

  useEffect(() => {
    void ensureScene("category-admin");
  }, [ensureScene]);

  const categoryStatusEntries = getEntries("META_CATEGORY_STATUS");
  const businessDomainEntries = getEntries(CATEGORY_BUSINESS_DOMAIN_DICT_CODE);
  const businessDomainConfigs = getCategoryBusinessDomainConfigs(businessDomainEntries);
  const defaultBusinessDomain = getDefaultCategoryBusinessDomain(businessDomainEntries);
  const resolvedBusinessDomain = resolveCategoryBusinessDomain(businessDomainEntries, routeBusinessDomain);
  const currentBusinessDomain = resolvedBusinessDomain?.code;
  const activeBusinessDomain = currentBusinessDomain || '';

  useEffect(() => {
    if (resolvedBusinessDomain && routeBusinessDomain !== resolvedBusinessDomain.code) {
      router.replace(getCategoryBusinessDomainPath(resolvedBusinessDomain.code));
    }
  }, [resolvedBusinessDomain, routeBusinessDomain, router]);

  const [selectedKey, setSelectedKey] = useState<React.Key>("");
  const [selectedNode, setSelectedNode] = useState<
    CategoryTreeNode | undefined
  >(undefined);
  const [leftCollapsed, setLeftCollapsed] = useState(false);

  const [drawerVisible, setDrawerVisible] = useState(false);
  const [previewNode, setPreviewNode] = useState<CategoryTreeNode | undefined>(undefined);
  const [previewDetail, setPreviewDetail] = useState<MetaCategoryDetailDto | null>(null);
  const [previewLoading, setPreviewLoading] = useState(false);
  const [previewEditing, setPreviewEditing] = useState(false);
  const [previewSaving, setPreviewSaving] = useState(false);
  const [renameGuidedEdit, setRenameGuidedEdit] = useState(false);
  const [previewEditBaseline, setPreviewEditBaseline] = useState("");
  const [previewEditCurrent, setPreviewEditCurrent] = useState("");
  const [pendingPreviewFormValues, setPendingPreviewFormValues] = useState<Record<string, any> | null>(null);
  const [previewForm] = Form.useForm();

  const [treeData, setTreeData] = useState<CategoryTreeNode[]>([]);
  const [expandedKeys, setExpandedKeys] = useState<React.Key[]>([]);
  const [loadedKeys, setLoadedKeys] = useState<React.Key[]>([]);
  const [attributeUnsavedState, setAttributeUnsavedState] = useState({
    hasUnsavedChanges: false,
    unsavedNewCount: 0,
  });

  const [deleteModalOpen, setDeleteModalOpen] = useState(false);
  const [deleteTargetNodes, setDeleteTargetNodes] = useState<DeleteTargetNode[]>([]);

  const updateNodeInTree = (
    list: CategoryTreeNode[],
    key: React.Key,
    updater: (node: CategoryTreeNode) => CategoryTreeNode,
  ): CategoryTreeNode[] => {
    return list.map((node) => {
      if (node.key === key) {
        return updater(node);
      }
      if (node.children) {
        return {
          ...node,
          children: updateNodeInTree(node.children, key, updater),
        };
      }
      return node;
    });
  };

  const removeNodeFromTree = (
    list: CategoryTreeNode[],
    key: React.Key,
  ): CategoryTreeNode[] => {
    return list
      .filter((node) => node.key !== key)
      .map((node) => {
        if (!node.children) return node;
        return {
          ...node,
          children: removeNodeFromTree(node.children, key),
        };
      });
  };

  const removeNodesFromTree = (
    list: CategoryTreeNode[],
    keysToRemove: Set<React.Key>,
  ): CategoryTreeNode[] => {
    return list
      .filter((node) => !keysToRemove.has(node.key))
      .map((node) => {
        const nextChildren = node.children
          ? removeNodesFromTree(node.children, keysToRemove)
          : node.children;

        if (!node.children) {
          return node;
        }

        const normalizedChildren = nextChildren ?? [];
        const hasChildren = normalizedChildren.length > 0;

        return {
          ...node,
          children: normalizedChildren,
          isLeaf: !hasChildren,
          dataRef: node.dataRef
            ? {
                ...node.dataRef,
                hasChildren,
                leaf: !hasChildren,
              }
            : node.dataRef,
        };
      });
  };

  const collectNodeKeys = (nodes: CategoryTreeNode[]): Set<React.Key> => {
    const keySet = new Set<React.Key>();
    const visit = (items: CategoryTreeNode[]) => {
      items.forEach((item) => {
        keySet.add(item.key);
        if (item.children?.length) {
          visit(item.children);
        }
      });
    };
    visit(nodes);
    return keySet;
  };

  const buildParentKeyMap = (nodes: CategoryTreeNode[]) => {
    const parentMap = new Map<React.Key, React.Key | null>();
    const visit = (items: CategoryTreeNode[], parentKey: React.Key | null = null) => {
      items.forEach((item) => {
        parentMap.set(item.key, parentKey);
        if (item.children?.length) {
          visit(item.children, item.key);
        }
      });
    };
    visit(nodes);
    return parentMap;
  };

  const mapNodeToTreeNode = (node: MetaCategoryNodeDto): CategoryTreeNode => {
    const ref: CategoryNodeRef = {
      ...node,
      key: node.id,
      title: node.name,
      depth: (node.level ?? 1) - 1,
    };

    return {
      title: `${node.code} - ${node.name}`,
      key: node.id,
      isLeaf: !node.hasChildren,
      dataRef: ref,
      level: getLevelByNumber(node.level),
      icon: getStatusIcon(node.status, categoryStatusEntries),
    };
  };

  const findNodeInTree = (
    nodes: CategoryTreeNode[],
    key: React.Key,
  ): CategoryTreeNode | undefined => {
    for (const node of nodes) {
      if (String(node.key) === String(key)) {
        return node;
      }

      if (node.children?.length) {
        const found = findNodeInTree(node.children, key);
        if (found) {
          return found;
        }
      }
    }

    return undefined;
  };

  const isTopologyTransferResponse = (
    response: BatchTransferSuccessResponse,
  ): response is MetaCategoryBatchTransferTopologyResponseDto => {
    return Array.isArray((response as MetaCategoryBatchTransferTopologyResponseDto).finalParentMappings);
  };

  const collectTransferAffectedNodeIds = (response: BatchTransferSuccessResponse) => {
    const affectedNodeIds = new Set<string>();

    if (isTopologyTransferResponse(response)) {
      response.results?.forEach((result) => {
        if (result.sourceNodeId) {
          affectedNodeIds.add(result.sourceNodeId);
        }
        if (result.targetParentId) {
          affectedNodeIds.add(result.targetParentId);
        }
        if (result.effectiveTargetParentId) {
          affectedNodeIds.add(result.effectiveTargetParentId);
        }
      });

      response.finalParentMappings?.forEach((mapping) => {
        if (mapping.sourceNodeId) {
          affectedNodeIds.add(mapping.sourceNodeId);
        }
        if (mapping.finalParentId) {
          affectedNodeIds.add(mapping.finalParentId);
        }
      });

      return Array.from(affectedNodeIds);
    }

    response.results?.forEach((result) => {
      if (result.sourceNodeId) {
        affectedNodeIds.add(result.sourceNodeId);
      }
      if (result.targetParentId) {
        affectedNodeIds.add(result.targetParentId);
      }
      result.movedIds?.forEach((id: string) => affectedNodeIds.add(id));
      result.createdIds?.forEach((id: string) => affectedNodeIds.add(id));
      if (result.createdRootId) {
        affectedNodeIds.add(result.createdRootId);
      }
    });

    return Array.from(affectedNodeIds);
  };

  const fetchRootNodes = async () => {
    const page = await metaCategoryApi.listNodes({
    businessDomain: activeBusinessDomain,
      level: 1,
      status: "ALL",
      page: 0,
      size: 200,
    });

    return (Array.isArray(page.content) ? page.content : []).map(mapNodeToTreeNode);
  };

  const fetchChildNodes = async (parentId: React.Key) => {
    const page = await metaCategoryApi.listNodes({
      businessDomain: activeBusinessDomain,
      parentId: String(parentId),
      status: "ALL",
      page: 0,
      size: 200,
    });

    return (page.content || []).map(mapNodeToTreeNode);
  };

  const resolvePathKeys = async (targetNodeIds: string[]) => {
    const uniqueIds = Array.from(new Set(targetNodeIds.map((id) => String(id).trim()).filter(Boolean)));
    if (!uniqueIds.length) {
      return [] as string[][];
    }

    const results = await Promise.allSettled(
      uniqueIds.map((id) => metaCategoryApi.getNodePath(id, activeBusinessDomain)),
    );

    return results
      .filter((result): result is PromiseFulfilledResult<MetaCategoryNodeDto[]> => result.status === "fulfilled")
      .map((result) => result.value.map((node) => String(node.id)).filter(Boolean))
      .filter((path) => path.length > 0)
      .sort((left, right) => left.length - right.length);
  };



  const applyDeletedNodes = (deletedKeys: React.Key[]) => {
    if (!deletedKeys.length) return;

    const deletedKeySet = new Set<React.Key>(deletedKeys);
    setTreeData((origin) => removeNodesFromTree(origin, deletedKeySet));

    if (selectedKey && deletedKeySet.has(selectedKey)) {
      setSelectedKey("");
      setSelectedNode(undefined);
    }

    if (previewNode && deletedKeySet.has(previewNode.key)) {
      setDrawerVisible(false);
      setPreviewNode(undefined);
      setPreviewDetail(null);
      setPreviewEditing(false);
      setRenameGuidedEdit(false);
      setPreviewEditBaseline("");
      setPreviewEditCurrent("");
      setPendingPreviewFormValues(null);
    }
  };


  const normalizeBatchDeleteTargets = (nodes: CategoryTreeNode[]) => {
    const existingKeys = collectNodeKeys(treeData);
    const parentMap = buildParentKeyMap(treeData);
    const uniqueNodes = new Map<React.Key, CategoryTreeNode>();

    nodes.forEach((node) => {
      if (existingKeys.has(node.key)) {
        uniqueNodes.set(node.key, node);
      }
    });

    return Array.from(uniqueNodes.values()).filter((node) => {
      let currentParent = parentMap.get(node.key);
      while (currentParent) {
        if (uniqueNodes.has(currentParent)) {
          return false;
        }
        currentParent = parentMap.get(currentParent);
      }
      return true;
    });
  };

  const openDeleteModal = (nodes: CategoryTreeNode[]) => {
    const targetNodes = normalizeBatchDeleteTargets(nodes);
    if (!targetNodes.length) {
      messageApi.info("未找到可删除的分类");
      return;
    }
    setDeleteTargetNodes(
      targetNodes.map((n) => ({
        key: n.key,
        name: n.dataRef?.name,
        code: n.dataRef?.code,
        level: n.dataRef?.level,
        status: n.dataRef?.status,
      })),
    );
    setDeleteModalOpen(true);
  };

  // Initial Load (Segments)
  useEffect(() => {
    if (!currentBusinessDomain) {
      return;
    }

    setSelectedKey("");
    setSelectedNode(undefined);
    setDrawerVisible(false);
    setPreviewNode(undefined);
    setPreviewDetail(null);
    setPreviewEditing(false);
    setRenameGuidedEdit(false);
    setPreviewEditBaseline("");
    setPreviewEditCurrent("");
    setPendingPreviewFormValues(null);
    setExpandedKeys([]);
    setLoadedKeys([]);
    setAttributeUnsavedState({ hasUnsavedChanges: false, unsavedNewCount: 0 });
    void loadSegments();
  }, [currentBusinessDomain]);

  const loadSegments = async () => {
    try {
      const nodes = await fetchRootNodes();
      setTreeData(nodes);
      setLoadedKeys([]);
      return nodes;
    } catch (error) {
      console.error(error);
      messageApi.error("Failed to load segments");
      return [] as CategoryTreeNode[];
    }
  };

  const onLoadData = async (node: any): Promise<void> => {
    const { key, children } = node as CategoryTreeNode;
    if (children && children.length > 0) return;

    try {
      const childNodes = await fetchChildNodes(key);

      setTreeData((origin) =>
        updateTreeData(origin, key as React.Key, childNodes),
      );
      setLoadedKeys((keys) => [...keys, key as React.Key]);
    } catch (error) {
      console.error(error);
      messageApi.error("Failed to load children");
    }
  };

  const updateTreeData = (
    list: CategoryTreeNode[],
    key: React.Key,
    children: CategoryTreeNode[],
  ): CategoryTreeNode[] => {
    return list.map((node) => {
      if (node.key === key) {
        return { ...node, children };
      }
      if (node.children) {
        return {
          ...node,
          children: updateTreeData(node.children, key, children),
        };
      }
      return node;
    });
  };

  const refreshTreeAfterBatchTransfer = async (response: BatchTransferSuccessResponse) => {
    try {
      const preservedExpandedKeys = expandedKeys.map((key) => String(key));
      const pathTargetIds = [
        ...preservedExpandedKeys,
        ...collectTransferAffectedNodeIds(response),
        selectedKey ? String(selectedKey) : "",
        previewNode ? String(previewNode.key) : "",
      ].filter(Boolean);

      const resolvedPaths = await resolvePathKeys(pathTargetIds);
      const nextExpandedKeySet = new Set<React.Key>(preservedExpandedKeys);

      resolvedPaths.forEach((path) => {
        path.forEach((pathKey) => nextExpandedKeySet.add(pathKey));
      });

      let nextTreeData = await fetchRootNodes();
      const nextLoadedKeySet = new Set<React.Key>();

      for (const path of resolvedPaths) {
        for (const pathKey of path) {
          const currentNode = findNodeInTree(nextTreeData, pathKey);
          if (!currentNode?.dataRef?.hasChildren || nextLoadedKeySet.has(pathKey)) {
            continue;
          }

          const childNodes = await fetchChildNodes(pathKey);
          nextTreeData = updateTreeData(nextTreeData, pathKey, childNodes);
          nextLoadedKeySet.add(pathKey);
        }
      }

      setTreeData(nextTreeData);
      setLoadedKeys(Array.from(nextLoadedKeySet));
      setExpandedKeys(Array.from(nextExpandedKeySet));

      if (selectedKey) {
        const refreshedSelectedNode = findNodeInTree(nextTreeData, selectedKey);
        if (refreshedSelectedNode) {
          setSelectedNode(refreshedSelectedNode);
        } else {
          setSelectedKey("");
          setSelectedNode(undefined);
        }
      }

      if (previewNode) {
        const refreshedPreviewNode = findNodeInTree(nextTreeData, previewNode.key);
        if (refreshedPreviewNode) {
          setPreviewNode(refreshedPreviewNode);
        } else {
          setDrawerVisible(false);
          setPreviewNode(undefined);
          setPreviewDetail(null);
          setPreviewEditing(false);
          setRenameGuidedEdit(false);
          setPreviewEditBaseline("");
          setPreviewEditCurrent("");
          setPendingPreviewFormValues(null);
        }
      }
    } catch (error) {
      console.error(error);
      messageApi.error("批量移动/复制完成，但分类树状态恢复失败，已回退为全量刷新");
      await loadSegments();
    }
  };

  const requestCategorySelection = (
    nextKey: React.Key,
    nextNode?: CategoryTreeNode,
  ) => {
    if (nextKey === selectedKey) {
      return;
    }

    if (attributeUnsavedState.hasUnsavedChanges || attributeUnsavedState.unsavedNewCount > 0) {
      const unsavedParts: string[] = [];
      if (attributeUnsavedState.hasUnsavedChanges) {
        unsavedParts.push("当前属性存在未保存修改");
      }
      if (attributeUnsavedState.unsavedNewCount > 0) {
        unsavedParts.push(`存在 ${attributeUnsavedState.unsavedNewCount} 条未保存新建属性`);
      }

      modal.confirm({
        title: "切换分类前确认",
        content: `检测到${unsavedParts.join("，")}。切换后将放弃这些内容，是否继续？`,
        okText: "放弃并切换",
        cancelText: "继续编辑",
        okType: "danger",
        onOk: () => {
          setSelectedKey(nextKey);
          setSelectedNode(nextNode);
          setAttributeUnsavedState({ hasUnsavedChanges: false, unsavedNewCount: 0 });
        },
      });
      return;
    }

    setSelectedKey(nextKey);
    setSelectedNode(nextNode);
  };

  const onSelect: TreeProps["onSelect"] = (keys, info) => {
    const nextKey = keys.length > 0 ? keys[0] : "";
    const nextNode = keys.length > 0 ? (info.node as CategoryTreeNode) : undefined;

    if (keys.length > 0) {
      requestCategorySelection(nextKey, nextNode);
    } else {
      requestCategorySelection("", undefined);
    }
  };

  const buildPreviewSnapshot = (values?: {
    name?: string;
    businessDomain?: string;
    status?: string;
    description?: string;
  }) => JSON.stringify({
    name: values?.name || "",
    businessDomain: values?.businessDomain || "",
    status: values?.status || "",
    description: normalizeDeltaJson(values?.description || EMPTY_QUILL_DELTA_JSON),
  });

  const checkPreviewUnsaved = (onConfirm: () => void) => {
    if (!previewEditing) {
      setPreviewEditBaseline("");
      setPreviewEditCurrent("");
      onConfirm();
      return;
    }

    const hasRealChanges = previewEditing && !!previewEditBaseline && previewEditCurrent !== previewEditBaseline;

    if (hasRealChanges) {
      modal.confirm({
        title: "放弃修改确认",
        content: "检测到分类详细信息存在未保存的修改，放弃或离开后将丢失这些内容，是否继续？",
        okText: "放弃并继续",
        cancelText: "取消",
        okType: "danger",
        onOk: () => {
          setPreviewEditBaseline("");
          setPreviewEditCurrent("");
          onConfirm();
        },
      });
    } else {
      setPreviewEditBaseline("");
      setPreviewEditCurrent("");
      onConfirm();
    }
  };

  useEffect(() => {
    if (!drawerVisible || !previewEditing || !pendingPreviewFormValues) {
      return;
    }
    previewForm.setFieldsValue(pendingPreviewFormValues);
    setPendingPreviewFormValues(null);
  }, [drawerVisible, previewEditing, pendingPreviewFormValues, previewForm]);

  const openPreviewDetail = (
    node: CategoryTreeNode,
    startEdit = false,
    options?: { openAfterDataReady?: boolean },
  ) => {
    setPreviewNode(node);
    const id = String(node.key);
    const openAfterDataReady = !!options?.openAfterDataReady;

    if (!openAfterDataReady) {
      setDrawerVisible(true);
    }

    if (id.startsWith("local_")) {
      setPreviewDetail(null);
      setPreviewEditing(false);
      setRenameGuidedEdit(false);
      setPendingPreviewFormValues(null);
      setPreviewEditBaseline("");
      setPreviewEditCurrent("");
      messageApi.warning(
        startEdit
          ? "本地临时节点暂不支持重命名，请保存后在详情页编辑"
          : "本地临时节点暂无完整详情，请保存后查看",
      );
      return;
    }

    setPreviewLoading(true);
    metaCategoryApi
      .getCategoryDetail(id)
      .then((detail) => {
        setPreviewDetail(detail);

        if (startEdit) {
          setRenameGuidedEdit(true);
          const initialValues = {
            name: detail.latestVersion?.name || "",
            businessDomain: detail.businessDomain,
            status: resolveStatusSemantic(detail.status, categoryStatusEntries),
            description: detail.description || EMPTY_QUILL_DELTA_JSON,
          };
          const snapshot = buildPreviewSnapshot(initialValues);
          setPreviewEditBaseline(snapshot);
          setPreviewEditCurrent(snapshot);
          setPendingPreviewFormValues(initialValues);
          setPreviewEditing(true);
        } else {
          setPreviewEditing(false);
          setRenameGuidedEdit(false);
          setPreviewEditBaseline("");
          setPreviewEditCurrent("");
          setPendingPreviewFormValues(null);
        }

        if (openAfterDataReady) {
          setDrawerVisible(true);
        }
      })
      .catch((e) => {
        console.error(e);
        setPreviewDetail(null);
        setPreviewEditing(false);
        setRenameGuidedEdit(false);
        setPreviewEditBaseline("");
        setPreviewEditCurrent("");
        setPendingPreviewFormValues(null);
        messageApi.error("加载分类详情失败");
      })
      .finally(() => {
        setPreviewLoading(false);
      });
  };

  const handleMenuClick = (key: string, node: CategoryTreeNode) => {
    if (key === "basic-info") {
      checkPreviewUnsaved(() => openPreviewDetail(node, false));
      return;
    }

    if (key === "design") {
      requestCategorySelection(node.key, node);
      return;
    }

    if (key === "add") {
      const childLevel = getChildLevel(node.level);
      if (!childLevel) {
        messageApi.warning("当前节点不支持新增子分类");
        return;
      }

      let inputValue = "";
      modal.confirm({
        title: "新增子分类",
        content: (
          <Input
            placeholder="请输入子分类名称"
            onChange={(e) => {
              inputValue = e.target.value;
            }}
          />
        ),
        okText: "确认",
        cancelText: "取消",
        onOk: () => {
          const trimmed = inputValue.trim();
          if (!trimmed) {
            messageApi.warning("请输入子分类名称");
            return Promise.reject();
          }

          const localCode = `LOCAL_${Date.now()}`;
          const levelNumber = ((node.dataRef?.level ?? 1) + 1);
          const childNode: CategoryTreeNode = {
            key: `local_${childLevel}_${Date.now()}`,
            title: `${localCode} - ${trimmed}`,
            dataRef: {
              id: `local_${childLevel}_${Date.now()}`,
              businessDomain: node.dataRef?.businessDomain || activeBusinessDomain,
              key: `local_${childLevel}_${Date.now()}`,
              code: localCode,
              name: trimmed,
              title: trimmed,
              hasChildren: childLevel !== "commodity" && childLevel !== "item",
              level: levelNumber,
              depth: (node.dataRef?.depth ?? 0) + 1,
            },
            level: childLevel,
            isLeaf: childLevel === "commodity" || childLevel === "item",
            icon: getStatusIcon("CREATED", categoryStatusEntries),
          };

          setTreeData((origin) =>
            updateNodeInTree(origin, node.key, (targetNode) => ({
              ...targetNode,
              isLeaf: false,
              children: [...(targetNode.children ?? []), childNode],
            })),
          );

          setLoadedKeys((keys) =>
            keys.includes(node.key) ? keys : [...keys, node.key],
          );
          messageApi.success("子分类已新增");
          return Promise.resolve();
        },
      });
      return;
    }

    if (key.startsWith("status:")) {
      const targetStatus = key.replace("status:", "") as "CREATED" | "EFFECTIVE" | "INVALID";
      const applyStatusTransition = async () => {
        const id = String(node.key);
        if (id.startsWith("local_")) {
          messageApi.warning("本地临时节点暂不支持状态转换，请保存后再操作");
          return;
        }

        const currentStatus = toSemanticCategoryStatus((node.dataRef as any)?.status);
        if (currentStatus === targetStatus) {
          messageApi.info("当前已是目标状态");
          return;
        }

        try {
          const updated = await metaCategoryApi.patchCategory(
            id,
            { status: targetStatus },
            { operator: "admin" },
          );

          setTreeData((origin) =>
            updateNodeInTree(origin, id, (targetNode) => {
              const nextName = updated.latestVersion?.name || targetNode.dataRef?.name || "未命名分类";
              return {
                ...targetNode,
                title: `${updated.code} - ${nextName}`,
                icon: getStatusIcon(updated.status, categoryStatusEntries),
                dataRef: targetNode.dataRef
                  ? {
                      ...targetNode.dataRef,
                      status: updated.status,
                      name: nextName,
                    }
                  : targetNode.dataRef,
              };
            }),
          );

          if (selectedKey === id) {
            setSelectedNode((prev) =>
              prev
                ? {
                    ...prev,
                    title: `${updated.code} - ${updated.latestVersion?.name || prev.dataRef?.name || "未命名分类"}`,
                    icon: getStatusIcon(updated.status, categoryStatusEntries),
                    dataRef: prev.dataRef
                      ? {
                          ...prev.dataRef,
                          status: updated.status,
                          name: updated.latestVersion?.name || prev.dataRef.name,
                        }
                      : prev.dataRef,
                  }
                : prev,
            );
          }

          if (previewNode && String(previewNode.key) === id) {
            setPreviewNode((prev) =>
              prev
                ? {
                    ...prev,
                    icon: getStatusIcon(updated.status, categoryStatusEntries),
                    dataRef: prev.dataRef
                      ? {
                          ...prev.dataRef,
                          status: updated.status,
                          name: updated.latestVersion?.name || prev.dataRef.name,
                        }
                      : prev.dataRef,
                  }
                : prev,
            );
          }

          if (previewDetail?.id === id) {
            setPreviewDetail(updated);
            if (previewEditing) {
              setPendingPreviewFormValues((prev) => ({
                ...(prev || {}),
                status: resolveStatusSemantic(updated.status, categoryStatusEntries),
              }));
            }
          }

          messageApi.success("状态转换成功");
        } catch (e: any) {
          const msg = e?.message || e?.error || "状态转换失败";
          messageApi.error(msg);
        }
      };

      checkPreviewUnsaved(() => {
        void applyStatusTransition();
      });
      return;
    }

    if (key === "rename") {
      checkPreviewUnsaved(() => openPreviewDetail(node, true, { openAfterDataReady: true }));
      return;
    }

    if (key === "delete") {
      openDeleteModal([node]);
    }
  };

  const handleCategoryCreated = (
    created: MetaCategoryDetailDto,
    parent?: {
      id?: string | null;
      level?: number;
      path?: string;
      code?: string;
      name?: string;
    } | null,
  ) => {
    const levelNumber =
      created.level ?? (parent?.level ? parent.level + 1 : 1);
    const level = getLevelByNumber(levelNumber);
    const name = created.latestVersion?.name || "未命名分类";

    const newNode: CategoryTreeNode = {
      key: created.id,
      title: `${created.code} - ${name}`,
      isLeaf: true,
      dataRef: {
        id: created.id,
        businessDomain: created.businessDomain || activeBusinessDomain,
          key: created.id,
        code: created.code,
        name,
          title: name,
        level: levelNumber,
          depth: levelNumber - 1,
        parentId: created.parentId || null,
        path: created.path,
        hasChildren: false,
        leaf: true,
        status: created.status,
        sort: created.sort,
      },
      level,
      icon: getStatusIcon(created.status, categoryStatusEntries),
    };

    if (!created.parentId) {
      setTreeData((prev) => {
        if (prev.some((item) => item.key === created.id)) return prev;
        return [...prev, newNode];
      });
      return;
    }

    setTreeData((origin) =>
      updateNodeInTree(origin, created.parentId!, (targetNode) => {
        const existingChildren = targetNode.children ?? [];
        if (existingChildren.some((child) => child.key === created.id)) {
          return targetNode;
        }
        return {
          ...targetNode,
          isLeaf: false,
          children: [...existingChildren, newNode],
          dataRef: targetNode.dataRef
            ? { ...targetNode.dataRef, hasChildren: true, leaf: false }
            : targetNode.dataRef,
        };
      }),
    );
    setLoadedKeys((keys) =>
      keys.includes(created.parentId!) ? keys : [...keys, created.parentId!],
    );
  };

  const handleStartPreviewEdit = () => {
    if (!previewDetail) return;
    setRenameGuidedEdit(false);
    const initialValues = {
      name: previewDetail.latestVersion?.name || "",
      businessDomain: previewDetail.businessDomain,
      status: resolveStatusSemantic(previewDetail.status, categoryStatusEntries),
      description: previewDetail.description || EMPTY_QUILL_DELTA_JSON,
    };
    const snapshot = buildPreviewSnapshot(initialValues);
    setPreviewEditBaseline(snapshot);
    setPreviewEditCurrent(snapshot);
    setPendingPreviewFormValues(initialValues);
    setPreviewEditing(true);
  };

  const handleSavePreviewEdit = async () => {
    if (!previewDetail) return;
    const values = await previewForm.validateFields();

    setPreviewSaving(true);
    try {
      const updated = await metaCategoryApi.updateCategory(
        previewDetail.id,
        {
          name: values.name,
          businessDomain: values.businessDomain,
          parentId: previewDetail.parentId || null,
          status: values.status,
          description: values.description || EMPTY_QUILL_DELTA_JSON,
        },
        { operator: "admin" },
      );

      setPreviewDetail(updated);
      setPreviewEditing(false);
      setRenameGuidedEdit(false);
      setPreviewEditBaseline("");
      setPreviewEditCurrent("");
      setPendingPreviewFormValues(null);

      setTreeData((origin) =>
        updateNodeInTree(origin, previewDetail.id, (targetNode) => ({
          ...targetNode,
          title: `${updated.code} - ${updated.latestVersion?.name || updated.code}`,
          icon: getStatusIcon(updated.status, categoryStatusEntries),
          dataRef: targetNode.dataRef
            ? {
                ...targetNode.dataRef,
                name: updated.latestVersion?.name || targetNode.dataRef.name,
                status: updated.status,
              }
            : targetNode.dataRef,
        })),
      );

      if (selectedKey === previewDetail.id) {
        setSelectedNode((prev) =>
          prev
            ? {
                ...prev,
                title: `${updated.code} - ${updated.latestVersion?.name || updated.code}`,
                icon: getStatusIcon(updated.status, categoryStatusEntries),
                dataRef: prev.dataRef
                  ? {
                      ...prev.dataRef,
                      name: updated.latestVersion?.name || prev.dataRef.name,
                      status: updated.status,
                    }
                  : prev.dataRef,
              }
            : prev,
        );
      }

      messageApi.success("分类信息已更新");
    } catch (e: any) {
      const msg = e?.message || e?.error || "更新分类失败";
      messageApi.error(msg);
    } finally {
      setPreviewSaving(false);
    }
  };

  if (!businessDomainConfigs.length) {
    return (
      <div
        style={{
          height: "calc(100vh - 163px)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          background: "var(--ant-color-bg-container, #fff)",
          borderRadius: 8,
          border: "1px solid var(--ant-color-border-secondary, #f0f0f0)",
        }}
      >
        <Spin tip="正在加载业务领域配置..." />
      </div>
    );
  }

  if (!resolvedBusinessDomain || !currentBusinessDomain) {
    return (
      <div
        style={{
          height: "calc(100vh - 163px)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          background: "var(--ant-color-bg-container, #fff)",
          borderRadius: 8,
          border: "1px solid var(--ant-color-border-secondary, #f0f0f0)",
        }}
      >
        <div style={{ color: "#999", fontSize: 16 }}>
          未识别的业务领域，无法加载分类管理页面。
        </div>
      </div>
    );
  }

  return (
    <div
      style={{
        height: "calc(100vh - 163px)",
        display: "flex",
        flexDirection: "column",
        gap: 16,
        overflow: "hidden",
      }}
    >
      <Splitter
        onCollapse={(collapsed) => setLeftCollapsed(collapsed[0] ?? false)}
        style={{
          flex: 1,
          minHeight: 0,
          background: "var(--ant-color-bg-container, #fff)",
          borderRadius: 8,
          border: "1px solid var(--ant-color-border-secondary, #f0f0f0)",
          boxShadow: "0 0 10px rgba(0, 0, 0, 0.05)",
          overflow: "hidden",
        }}
      >
        <Splitter.Panel
          defaultSize={450}
          min={350}
          max={600}
          collapsible={{
            end: true,
            showCollapsibleIcon: leftCollapsed ? true : "auto",
          }}
        >
          <CategoryTree
            onSelect={onSelect}
            treeData={treeData}
            defaultBusinessDomain={currentBusinessDomain}
            selectedKeys={selectedKey ? [selectedKey] : []}
            expandedKeys={expandedKeys}
            onExpandedKeysChange={setExpandedKeys}
            loadData={onLoadData}
            loadedKeys={loadedKeys}
            onLoad={(keys) => setLoadedKeys(keys as React.Key[])}
            onMenuClick={handleMenuClick}
            onBatchDelete={(nodes) => openDeleteModal(nodes as CategoryTreeNode[])}
            onTransferSuccess={(response) => {
              void refreshTreeAfterBatchTransfer(response);
            }}
            onCategoryCreated={handleCategoryCreated}
          />
        </Splitter.Panel>
        <Splitter.Panel>
          <div style={{ position: "relative", height: "100%", overflow: "hidden" }}>
            {selectedNode ? (
              <AttributeDesigner
                currentNode={selectedNode.dataRef}
                onUnsavedStateChange={setAttributeUnsavedState}
              />
            ) : (
              <div
                style={{
                  height: "100%",
                  padding: "16px",
                  color: "#999",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                }}
              >
                请选择左侧分类节点
              </div>
            )}
            
            <Drawer
              title={previewNode?.dataRef?.name ? `分类详细信息 - ${previewNode.dataRef.name}` : "分类详细信息"}
              placement="right"
              closable={true}
              extra={
                previewDetail ? (
                  previewEditing ? (
                    <Space>
                      <Button onClick={() => checkPreviewUnsaved(() => {
                        setPreviewEditing(false);
                        setRenameGuidedEdit(false);
                        setPreviewEditBaseline("");
                        setPreviewEditCurrent("");
                        setPendingPreviewFormValues(null);
                      })}>取消</Button>
                      <Button type="primary" loading={previewSaving} onClick={handleSavePreviewEdit}>
                        保存
                      </Button>
                    </Space>
                  ) : (
                    <Button type="primary" onClick={handleStartPreviewEdit}>编辑</Button>
                  )
                ) : null
              }
              onClose={() => {
                checkPreviewUnsaved(() => {
                  setDrawerVisible(false);
                  setPreviewDetail(null);
                  setPreviewEditing(false);
                  setRenameGuidedEdit(false);
                  setPreviewEditBaseline("");
                  setPreviewEditCurrent("");
                  setPendingPreviewFormValues(null);
                });
              }}
              open={drawerVisible}
              forceRender
              getContainer={false}
              rootStyle={{ position: 'absolute' }}
              width="100%"
            >
              {previewLoading ? (
                <div style={{ height: 220, display: "flex", alignItems: "center", justifyContent: "center" }}>
                  <Spin />
                </div>
              ) : previewDetail ? (
                <Tabs
                  defaultActiveKey="basic"
                  items={[
                    {
                      key: 'basic',
                      label: '基本信息',
                      children: (
                        <>
                          {previewEditing ? (
                            <Form
                              form={previewForm}
                              layout="vertical"
                              onValuesChange={(_, allValues) => {
                                setPreviewEditCurrent(buildPreviewSnapshot(allValues));
                              }}
                            >
                              <Card 
                                size="small" 
                                variant="outlined" 
                                style={{ 
                                  borderRadius: token.borderRadiusLG,
                                  backgroundColor: token.colorFillAlter,
                                  marginBottom: 16
                                }}
                              >
                                <Row gutter={24}>
                                  <Col span={12}>
                                    <Form.Item label="分类编码">
                                      <Input 
                                        value={previewDetail.code} 
                                        readOnly 
                                        style={{ 
                                          color: token.colorTextDisabled, 
                                          backgroundColor: token.colorBgContainerDisabled, 
                                          cursor: 'not-allowed' 
                                        }} 
                                      />
                                    </Form.Item>
                                  </Col>
                                  <Col span={12}>
                                    <Form.Item label="分类名称" name="name" rules={[{ required: true, message: "请输入分类名称" }]}>
                                      <Input
                                        autoFocus={renameGuidedEdit}
                                        placeholder="请输入分类名称"
                                        style={renameGuidedEdit ? { borderColor: token.colorInfo, boxShadow: `0 0 0 2px ${token.colorInfoBg}` } : undefined}
                                      />
                                    </Form.Item>
                                  </Col>
                                </Row>

                                <Row gutter={24}>
                                  <Col span={12}>
                                    <Form.Item label="业务领域" name="businessDomain" rules={[{ required: true, message: "请选择业务领域" }]}>
                                      <Select placeholder="请选择业务领域">
                                        {businessDomainEntries.map((entry) => (
                                          <Select.Option key={entry.value} value={entry.value}>
                                            {entry.label} ({entry.value})
                                          </Select.Option>
                                        ))}
                                      </Select>
                                    </Form.Item>
                                  </Col>
                                  <Col span={12}>
                                    <Form.Item label="上级分类">
                                      <Input 
                                        value={previewDetail.parentCode ? `${previewDetail.parentCode} - ${previewDetail.parentName || ""}` : "-"} 
                                        readOnly 
                                        style={{ 
                                          color: token.colorTextDisabled, 
                                          backgroundColor: token.colorBgContainerDisabled, 
                                          cursor: 'not-allowed' 
                                        }} 
                                      />
                                    </Form.Item>
                                  </Col>
                                </Row>

                                <Row gutter={24}>
                                  <Col span={12}>
                                    <Form.Item label="分类状态" name="status" rules={[{ required: true, message: "请选择分类状态" }]}>
                                      <Select placeholder="请选择分类状态">
                                        {categoryStatusEntries
                                          .filter((entry) => ["CREATED", "EFFECTIVE", "INVALID"].includes(String(entry.value).toUpperCase()))
                                          .map((entry) => (
                                            <Select.Option key={entry.value} value={entry.value}>
                                              {entry.label}
                                            </Select.Option>
                                          ))}
                                      </Select>
                                    </Form.Item>
                                  </Col>
                                  <Col span={12}>
                                    <Form.Item label="根分类">
                                      <Input 
                                        value={previewDetail.rootCode ? `${previewDetail.rootCode} - ${previewDetail.rootName || ""}` : "-"} 
                                        readOnly 
                                        style={{ 
                                          color: token.colorTextDisabled, 
                                          backgroundColor: token.colorBgContainerDisabled, 
                                          cursor: 'not-allowed' 
                                        }} 
                                      />
                                    </Form.Item>
                                  </Col>
                                </Row>

                                <Row gutter={24}>
                                  <Col span={24}>
                                    <Form.Item label="详细信息">
                                      <div
                                        className="category-description-editor"
                                        style={{
                                          border: `1px solid ${token.colorBorder}`,
                                          borderRadius: token.borderRadius,
                                          overflow: "hidden",
                                          background: token.colorBgContainer,
                                        }}
                                      >
                                        <Form.Item
                                          name="description"
                                          noStyle
                                          trigger="onChange"
                                          getValueFromEvent={(_content, _delta, _source, editor) => {
                                            if (!editor || typeof editor.getContents !== "function") {
                                              return EMPTY_QUILL_DELTA_JSON;
                                            }
                                            return JSON.stringify(editor.getContents());
                                          }}
                                          getValueProps={(value) => {
                                            if (!value || typeof value !== "string") {
                                              return { value: undefined };
                                            }
                                            try {
                                              return { value: JSON.parse(value) };
                                            } catch {
                                              return { value: undefined };
                                            }
                                          }}
                                        >
                                          <ReactQuill
                                            theme="snow"
                                            modules={quillModules}
                                            formats={quillFormats}
                                            placeholder="请输入详细信息"
                                            style={{ minHeight: 180 }}
                                          />
                                        </Form.Item>
                                      </div>
                                    </Form.Item>
                                  </Col>
                                </Row>
                              </Card>
                            </Form>
                          ) : (
                            <Descriptions column={1} bordered size="small">
                              <Descriptions.Item label="分类编码">{previewDetail.code || "-"}</Descriptions.Item>
                              <Descriptions.Item label="分类名称">{previewDetail.latestVersion?.name || "-"}</Descriptions.Item>
                              <Descriptions.Item label="业务领域">
                                {getLabel("META_CATEGORY_BUSINESS_DOMAIN", previewDetail.businessDomain, {
                                  fallback: previewDetail.businessDomain || "-",
                                })}
                              </Descriptions.Item>
                              <Descriptions.Item label="分类状态">
                                {getLabel("META_CATEGORY_STATUS", previewDetail.status, {
                                  matchDbValue: true,
                                  fallback: previewDetail.status || "-",
                                })}
                              </Descriptions.Item>
                              <Descriptions.Item label="上级分类">{previewDetail.parentCode ? `${previewDetail.parentCode} - ${previewDetail.parentName || ""}` : "-"}</Descriptions.Item>
                              <Descriptions.Item label="根分类">{previewDetail.rootCode ? `${previewDetail.rootCode} - ${previewDetail.rootName || ""}` : "-"}</Descriptions.Item>
                              <Descriptions.Item label="详细信息">
                                {deltaJsonToPlainText(previewDetail.description) || "暂无描述"}
                              </Descriptions.Item>
                              <Descriptions.Item label="创建人">{previewDetail.createdBy || "-"}</Descriptions.Item>
                              <Descriptions.Item label="创建时间">{previewDetail.createdAt ? new Date(previewDetail.createdAt).toLocaleString() : "-"}</Descriptions.Item>
                              <Descriptions.Item label="修改人">{previewDetail.modifiedBy || "-"}</Descriptions.Item>
                              <Descriptions.Item label="修改时间">{previewDetail.modifiedAt ? new Date(previewDetail.modifiedAt).toLocaleString() : "-"}</Descriptions.Item>
                              <Descriptions.Item label="版本">{previewDetail.version ?? "-"}</Descriptions.Item>
                            </Descriptions>
                          )}
                        </>
                      )
                    },
                    {
                      key: 'version',
                      label: '版本信息',
                      children: <VersionGraph categoryId={previewDetail.id} versions={(previewDetail as any).historyVersions || []} />
                    }
                  ]}
                />
              ) : (
                <div style={{ color: "#999", textAlign: "center", marginTop: 40 }}>请选择节点查看信息</div>
              )}
            </Drawer>
          </div>
        </Splitter.Panel>
      </Splitter>

      <BatchDeleteModal
        open={deleteModalOpen}
        nodes={deleteTargetNodes}
        onClose={() => setDeleteModalOpen(false)}
        onDeleted={(deletedIds) => {
          applyDeletedNodes(deletedIds);
          setDeleteModalOpen(false);
        }}
      />
    </div>
  );
};

export default CategoryManagementPage;

import React, { useEffect, useMemo, useState } from "react";
import { Collapse, Spin, Tag, Timeline, Typography, theme } from "antd";

const { Text } = Typography;

export interface DryRunTimelineItem {
  key: string;
  title: string;
  detail?: string;
  color?: "blue" | "red" | "green" | "gray";
}

type ExecutionStage = "starting" | "processing" | "success" | "failed";

interface BatchTransferDryRunPanelProps {
  actionLabel: string;
  status: "passed" | "failed";
  total: number;
  successCount: number;
  planningMode?: string;
  normalizedCount?: number;
  pendingOperations: DryRunTimelineItem[];
  resolvedOrder: DryRunTimelineItem[];
  finalPlacements: DryRunTimelineItem[];
  failedIssues: DryRunTimelineItem[];
  warnings: string[];
  height?: string | number;
  executionStage?: ExecutionStage;
  executionSummary?: string;
}

const buildPanelLabel = (label: string) => (
  <div
    style={{
      minHeight: 32,
      display: "flex",
      alignItems: "center",
      lineHeight: 1.3,
    }}
  >
    {label}
  </div>
);

const getExecutionTag = (stage: ExecutionStage) => {
  switch (stage) {
    case "starting":
      return { color: "processing", label: "准备执行" };
    case "processing":
      return { color: "processing", label: "执行中" };
    case "success":
      return { color: "success", label: "执行完成" };
    case "failed":
      return { color: "error", label: "执行失败" };
    default:
      return { color: "default", label: "处理中" };
  }
};

const buildExecutionTimelineItems = (
  actionLabel: string,
  stage: ExecutionStage,
  summary: string,
) => {
  const isFinished = stage === "success" || stage === "failed";

  return [
    {
      color: stage === "starting" ? "blue" : "green",
      children: (
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <Text strong>创建执行任务</Text>
          <Text type="secondary">已锁定本次确认内容，准备发起批量{actionLabel}请求。</Text>
        </div>
      ),
    },
    {
      color:
        stage === "starting"
          ? "gray"
          : stage === "processing"
            ? "blue"
            : stage === "success"
              ? "green"
              : "red",
      dot: stage === "processing" ? <Spin size="small" /> : undefined,
      children: (
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <Text strong>服务端执行批量{actionLabel}</Text>
          <Text type="secondary">正在等待服务端完成执行与结果汇总。</Text>
        </div>
      ),
    },
    {
      color: !isFinished ? "gray" : stage === "success" ? "green" : "red",
      children: (
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <Text strong>返回执行结果</Text>
          <Text type="secondary">{summary}</Text>
        </div>
      ),
    },
  ];
};

const renderTimeline = (
  items: DryRunTimelineItem[],
  emptyText: string,
  maxHeight: string,
) => {
  if (!items.length) {
    return <Text type="secondary">{emptyText}</Text>;
  }

  return (
    <div style={{ maxHeight, overflowY: "auto", paddingRight: 8 }}>
      <Timeline
        items={items.map((item) => ({
          color: item.color || "blue",
          children: (
            <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
              <Text strong>{item.title}</Text>
              {item.detail ? <Text type="secondary">{item.detail}</Text> : null}
            </div>
          ),
        }))}
      />
    </div>
  );
};

export default function BatchTransferDryRunPanel({
  actionLabel,
  status,
  total,
  successCount,
  planningMode,
  normalizedCount = 0,
  pendingOperations,
  resolvedOrder,
  finalPlacements,
  failedIssues,
  warnings,
  height = "68vh",
  executionStage,
  executionSummary,
}: BatchTransferDryRunPanelProps) {
  const { token } = theme.useToken();
  const hasExecutionProgress = Boolean(executionStage && executionSummary);
  const panelBodyMaxHeight = hasExecutionProgress
    ? `calc(${height} - 340px)`
    : `calc(${height} - 220px)`;
  const [activeKey, setActiveKey] = useState<string[]>(["summary"]);

  useEffect(() => {
    setActiveKey(hasExecutionProgress ? ["execution"] : ["summary"]);
  }, [hasExecutionProgress, executionStage, executionSummary]);

  const executionTimelineItems = useMemo(
    () =>
      hasExecutionProgress && executionStage && executionSummary
        ? buildExecutionTimelineItems(
            actionLabel,
            executionStage,
            executionSummary,
          )
        : [],
    [
      actionLabel,
      executionStage,
      executionSummary,
      hasExecutionProgress,
    ],
  );

  const summaryTagColor = status === "passed" ? "success" : "error";
  const collapseItems = [
    {
      key: "execution",
      label: buildPanelLabel("执行进度"),
      collapsible: hasExecutionProgress ? undefined : ("disabled" as const),
      children: hasExecutionProgress && executionStage && executionSummary ? (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 8,
              flexWrap: "wrap",
            }}
          >
            <Tag color={getExecutionTag(executionStage).color}>
              {getExecutionTag(executionStage).label}
            </Tag>
            <Text strong>正在执行批量{actionLabel}</Text>
            <Text type="secondary">{executionSummary}</Text>
          </div>
          <div style={{ maxHeight: 180, overflowY: "auto", paddingRight: 8 }}>
            <Timeline items={executionTimelineItems} />
          </div>
        </div>
      ) : (
        <Text type="secondary">点击确认移动后，此处将展示执行进度。</Text>
      ),
    },
    {
      key: "summary",
      label: buildPanelLabel("校验概览"),
      children: (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
            <Tag color={summaryTagColor}>
              {status === "passed" ? "预检通过" : "预检未通过"}
            </Tag>
            <Text>
              本次计划{actionLabel} {total} 项。
            </Text>
            <Text>预计可执行 {successCount} 项。</Text>
          </div>
          {planningMode ? (
            <Text type="secondary">服务端规划模式：{planningMode}</Text>
          ) : null}
          {normalizedCount > 0 ? (
            <Text type="warning">
              有 {normalizedCount} 项父子重叠请求被自动归一化处理。
            </Text>
          ) : null}
          {status === "failed" && failedIssues.length > 0 ? (
            <Text type="danger">
              当前存在 {failedIssues.length} 项未通过校验，请先处理后再提交。
            </Text>
          ) : null}
        </div>
      ),
    },
    {
      key: "operations",
      label: buildPanelLabel(`操作流程（${pendingOperations.length}）`),
      children: renderTimeline(
        pendingOperations,
        `当前没有待${actionLabel}的操作。`,
        panelBodyMaxHeight,
      ),
    },
  ];

  if (resolvedOrder.length > 0) {
    collapseItems.push({
      key: "resolved-order",
      label: buildPanelLabel(`服务端执行顺序（${resolvedOrder.length}）`),
      children: renderTimeline(
        resolvedOrder,
        "当前没有额外的执行顺序信息。",
        panelBodyMaxHeight,
      ),
    });
  }

  if (finalPlacements.length > 0) {
    collapseItems.push({
      key: "placements",
      label: buildPanelLabel(`最终落位（${finalPlacements.length}）`),
      children: renderTimeline(
        finalPlacements,
        "当前没有最终落位信息。",
        panelBodyMaxHeight,
      ),
    });
  }

  if (failedIssues.length > 0 || warnings.length > 0) {
    collapseItems.push({
      key: "risks",
      label: buildPanelLabel(
        status === "failed" ? "未通过原因与提示" : "提示信息",
      ),
      children: (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {failedIssues.length > 0
            ? renderTimeline(
                failedIssues,
                "当前没有失败项。",
                panelBodyMaxHeight,
              )
            : null}
          {warnings.length > 0 ? (
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                gap: 6,
                padding: 12,
                borderRadius: 10,
                background: token.colorWarningBg,
                border: `1px solid ${token.colorWarningBorder}`,
              }}
            >
              {warnings.map((warning) => (
                <Text key={warning}>{warning}</Text>
              ))}
            </div>
          ) : null}
        </div>
      ),
    });
  }

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        gap: 12,
        height,
        minHeight: 420,
        width: "100%",
      }}
    >
      <div
        style={{
          flex: 1,
          minHeight: 0,
          width: "100%",
          display: "flex",
          justifyContent: "center",
        }}
      >
        <Collapse
          className="batch-transfer-dry-run-collapse"
          accordion
          activeKey={activeKey}
          onChange={(key) => {
            const nextKeys = Array.isArray(key)
              ? key.map(String)
              : key
                ? [String(key)]
                : [];
            setActiveKey(nextKeys);
          }}
          items={collapseItems}
          style={{
            flex: 1,
            overflow: "hidden",
            width: "min(100%, 980px)",
          }}
        />
        <style
          dangerouslySetInnerHTML={{
            __html: `
              .batch-transfer-dry-run-collapse .ant-collapse-item > .ant-collapse-header {
                min-height: 58px;
                display: flex;
                align-items: center;
              }
              .batch-transfer-dry-run-collapse .ant-collapse-expand-icon {
                height: 100%;
                display: flex;
                align-items: center;
              }
              .batch-transfer-dry-run-collapse .ant-collapse-header-text {
                min-height: 28px;
                display: flex;
                align-items: center;
              }
            `,
          }}
        />
      </div>
    </div>
  );
}

import React from 'react';
import { Tree, theme } from 'antd';
import type { TreeDataNode } from 'antd';
import { FolderOutlined, FolderOpenOutlined } from '@ant-design/icons';
import { useDraggable } from '@dnd-kit/core';
import type { TransferTreeNode } from './TransferWorkspace';
import { getTransferNodeLabelStyle } from './transferNodeStyles';

interface DraggableSourceTreeProps {
  treeData: TransferTreeNode[];
  expandedKeys: React.Key[];
  onExpand: (expandedKeys: React.Key[]) => void;
  onMovedNodeHover?: (key: React.Key | null) => void;
}

// 封装自定义的可拖拽节点 Title
const SourceNodeTitle = ({
  nodeData,
  token,
  onMovedNodeHover,
}: {
  nodeData: any;
  token: any;
  onMovedNodeHover?: (key: React.Key | null) => void;
}) => {
  const { isContextOnly, isMovedSource } = nodeData;
  const { attributes, listeners, setNodeRef, isDragging } = useDraggable({
    id: `src-${nodeData.key}`,
    data: nodeData,
    disabled: isContextOnly || isMovedSource
  });

  return (
    <span
      ref={setNodeRef}
      {...listeners}
      {...attributes}
      onMouseEnter={() => {
        if (isMovedSource) {
          onMovedNodeHover?.(nodeData.key);
        }
      }}
      onMouseLeave={() => {
        if (isMovedSource) {
          onMovedNodeHover?.(null);
        }
      }}
      style={{
        ...getTransferNodeLabelStyle(token, {
          disabled: isContextOnly || isMovedSource,
          dragging: isDragging,
        }),
        color: isContextOnly
          ? token.colorTextDescription
          : isMovedSource
            ? token.colorTextSecondary
            : undefined,
        opacity: isContextOnly
          ? 0.52
          : isMovedSource && !isDragging
            ? 0.72
            : undefined,
      }}
    >
      <span
        style={{
          overflow: 'hidden',
          textOverflow: 'ellipsis',
          whiteSpace: 'nowrap',
          textDecoration: isMovedSource ? 'line-through' : 'none',
          textDecorationThickness: isMovedSource ? 1.5 : undefined,
          fontStyle: isContextOnly ? 'normal' : undefined,
        }}
      >
        {nodeData.title}
      </span>
      {isMovedSource && (
        <span
          style={{
            marginLeft: 8,
            fontSize: 12,
            color: token.colorSuccess,
            background: token.colorSuccessBg,
            border: `1px solid ${token.colorSuccessBorder}`,
            borderRadius: 999,
            padding: '1px 6px',
            lineHeight: '18px',
            flexShrink: 0,
          }}
        >
          已移动
        </span>
      )}
    </span>
  );
};

export default function DraggableSourceTree({
  treeData,
  expandedKeys,
  onExpand,
  onMovedNodeHover,
}: DraggableSourceTreeProps) {
  const { token } = theme.useToken();

  const titleRender = (nodeData: any) => {
    return <SourceNodeTitle nodeData={nodeData} token={token} onMovedNodeHover={onMovedNodeHover} />;
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', minHeight: 0 }}>
      <div style={{ flex: '1 1 0', minHeight: 0, overflow: 'auto' }}>
        <Tree
          className="draggable-source-tree dnd-transfer-tree"
          treeData={treeData as TreeDataNode[]}
          expandedKeys={expandedKeys}
          autoExpandParent
          onExpand={onExpand}
          titleRender={titleRender}
          showIcon
          icon={(nodeProps: any) => 
            nodeProps.expanded ? <FolderOpenOutlined /> : <FolderOutlined />
          }
          blockNode
          selectable={false}
        />
      </div>
    </div>
  );
}

import React from 'react';
import { Tree, Input, theme } from 'antd';
import type { TreeDataNode } from 'antd';
import { SearchOutlined, FolderOutlined, FolderOpenOutlined, ApartmentOutlined } from '@ant-design/icons';
import { useDroppable } from '@dnd-kit/core';
import type { TransferTreeNode } from './TransferWorkspace';
import { colorToRgba } from './transferNodeStyles';

const { Search } = Input;

interface DropTargetTreeProps {
  treeData: TransferTreeNode[];
  expandedKeys: React.Key[];
  onExpand: (keys: React.Key[]) => void;
  loadData?: (node: TransferTreeNode) => Promise<void>;
  disabledKeys: React.Key[]; 
  pendingDropKeys?: React.Key[];
  hoveredTargetKey?: React.Key | null; // 从外部透传的悬停状态，用于绘制呼吸灯
  rootDropTargetKey: React.Key;
  rootDropTargetTitle: string;
  rootPendingCount?: number;
  rootDropDisabled?: boolean;
  scrollViewportRef?: React.RefObject<HTMLDivElement | null>;
  rootDropTargetRef?: React.RefObject<HTMLDivElement | null>;
  highlightedPreviewKey?: React.Key | null;
}

const RootDropTarget = ({
  dropKey,
  title,
  token,
  isHoveringByDnd,
  disabled = false,
  rootDropTargetRef,
}: {
  dropKey: React.Key;
  title: string;
  token: any;
  isHoveringByDnd: boolean;
  disabled?: boolean;
  rootDropTargetRef?: React.RefObject<HTMLDivElement | null>;
}) => {
  const rootDropNode: TransferTreeNode = {
    key: String(dropKey),
    title,
    isLeaf: false,
  };

  const { setNodeRef, isOver } = useDroppable({
    id: `tgt-${String(dropKey)}`,
    data: rootDropNode,
  });

  const active = !disabled && (isOver || isHoveringByDnd);

  return (
    <div
      ref={(element) => {
        setNodeRef(element);
        if (rootDropTargetRef) {
          rootDropTargetRef.current = element;
        }
      }}
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        gap: 10,
        padding: '12px 16px',
        marginBottom: 12,
        borderRadius: 8,
        border: `1px dashed ${disabled ? token.colorBorderSecondary : active ? token.colorPrimary : token.colorBorder}`,
        background: disabled
          ? colorToRgba(token.colorBgContainer, 0.62)
          : active
            ? colorToRgba(token.colorPrimaryBg, 0.82)
            : colorToRgba(token.colorBgElevated, 0.72),
        backdropFilter: 'blur(6px) saturate(140%)',
        WebkitBackdropFilter: 'blur(6px) saturate(140%)',
        boxShadow: active ? token.boxShadowSecondary : token.boxShadowTertiary,
        color: disabled ? token.colorTextDisabled : token.colorText,
        transition: 'all 0.2s ease',
        position: 'sticky',
        top: 0,
        zIndex: 2,
        textAlign: 'center',
      }}
    >
      <ApartmentOutlined style={{ color: disabled ? token.colorTextDisabled : active ? token.colorPrimary : token.colorTextSecondary }} />
      <span style={{ fontWeight: 500 }}>{title}</span>
      <span style={{ fontSize: 12, color: disabled ? token.colorTextDisabled : token.colorTextDescription }}>
        {disabled ? '当前源节点已是根分类，不能再次拖拽为根分类' : '拖到这里可提升为根分类'}
      </span>
    </div>
  );
};

const TargetNodeTitle = ({
  nodeData,
  token,
  disabledKeys,
  pendingDropKeys = [],
  isHoveringByDnd,
  highlightedPreviewKey,
}: any) => {
  const isDisabled = disabledKeys.includes(nodeData.key);
  const isPendingTarget = pendingDropKeys.includes(nodeData.key);
  const isPendingPlacement = Boolean(nodeData.isPendingPlacement);
  const isPreviewNode = Boolean(nodeData.isPreviewNode || nodeData.isPreviewRoot);
  const isAffectedHighlight = highlightedPreviewKey != null && nodeData.key === highlightedPreviewKey;

  const { setNodeRef, isOver } = useDroppable({
    id: `tgt-${nodeData.key}`,
    data: nodeData,
    disabled: isDisabled || isPendingPlacement
  });

  return (
    <span
      ref={setNodeRef}
      style={{
        transition: 'all 0.3s ease',
        backgroundColor: isAffectedHighlight
          ? token.colorInfoBg
          : isPendingPlacement
            ? token.colorPrimaryBg
            : (isOver || isHoveringByDnd) && !isDisabled
              ? token.colorPrimaryBgHover
              : 'transparent',
        color: isDisabled ? token.colorTextDisabled : token.colorText,
        padding: '4px 8px',
        borderRadius: 4,
        border: isAffectedHighlight
          ? `1px solid ${token.colorInfoBorder}`
          : isPendingPlacement || isPendingTarget
            ? `1px dashed ${token.colorPrimary}`
            : '1px solid transparent',
        boxShadow: isAffectedHighlight ? `inset 0 0 0 1px ${token.colorInfoBorder}` : 'none',
        display: 'inline-flex',
        alignItems: 'center',
        width: '100%',
        flex: 1,
        minHeight: 24,
        minWidth: 0,
        lineHeight: 1,
        verticalAlign: 'middle',
        boxSizing: 'border-box'
      }}
    >
      <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{nodeData.title}</span>
      {isPreviewNode && (
        <span
          style={{
            marginLeft: 8,
            fontSize: 12,
            color: token.colorInfo,
            background: token.colorInfoBg,
            border: `1px solid ${token.colorInfoBorder}`,
            borderRadius: 999,
            padding: '1px 6px',
            lineHeight: '18px',
            flexShrink: 0,
          }}
        >
          预览
        </span>
      )}
      {(isPendingPlacement || isPendingTarget) && (
        <span
          style={{
            marginLeft: 8,
            fontSize: 12,
            color: token.colorPrimary,
            background: token.colorPrimaryBg,
            border: `1px solid ${token.colorPrimaryBorder}`,
            borderRadius: 999,
            padding: '1px 6px',
            lineHeight: '18px',
            flexShrink: 0,
          }}
        >
          待确认位置
        </span>
      )}
    </span>
  );
};

export default function DropTargetTree({
  treeData,
  expandedKeys,
  onExpand,
  loadData,
  disabledKeys,
  pendingDropKeys = [],
  hoveredTargetKey,
  rootDropTargetKey,
  rootDropTargetTitle,
  rootPendingCount = 0,
  rootDropDisabled = false,
  scrollViewportRef,
  rootDropTargetRef,
  highlightedPreviewKey,
}: DropTargetTreeProps) {
  const { token } = theme.useToken();

  const titleRender = (nodeData: any) => {
    return (
      <TargetNodeTitle 
        nodeData={nodeData} 
        token={token} 
        disabledKeys={disabledKeys}
        pendingDropKeys={pendingDropKeys}
        isHoveringByDnd={nodeData.key === hoveredTargetKey}
        highlightedPreviewKey={highlightedPreviewKey}
      />
    );
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', minHeight: 0 }}>
      <Search 
        placeholder="搜索目标分类..." 
        allowClear 
        prefix={<SearchOutlined />} 
        style={{ marginBottom: 16 }}
      />
      <div ref={scrollViewportRef} style={{ flex: '1 1 0', height: 0, minHeight: 0, overflow: 'auto' }}>
        <RootDropTarget
          dropKey={rootDropTargetKey}
          title={rootDropTargetTitle}
          token={token}
          isHoveringByDnd={!rootDropDisabled && hoveredTargetKey === rootDropTargetKey}
          disabled={rootDropDisabled}
          rootDropTargetRef={rootDropTargetRef}
        />
        <Tree
          className="drop-target-tree dnd-transfer-tree"
          treeData={treeData as TreeDataNode[]}
          expandedKeys={expandedKeys}
          onExpand={onExpand}
          loadData={loadData ? (node) => loadData(node as unknown as TransferTreeNode) : undefined}
          titleRender={titleRender}
          showIcon
          icon={(nodeProps: any) => 
            nodeProps.expanded ? <FolderOpenOutlined /> : <FolderOutlined />
          }
          blockNode
          selectable={false}
        />
      </div>
    </div>
  );
}

"use client";

import React, { useEffect, useMemo, useRef, useState } from "react";
import { createPortal } from "react-dom";
import { App, Col, Row, Spin, theme } from "antd";
import { FolderOutlined } from "@ant-design/icons";
import {
