} from "@dnd-kit/core";
import type {
  MetaCategoryBatchTransferRequestDto,
  MetaCategoryBatchTransferResponseDto,
  MetaCategoryBatchTransferTopologyRequestDto,
  MetaCategoryBatchTransferTopologyResponseDto,
