import React, { useEffect, useState, useMemo, useRef } from "react";
import {
  App,
  Empty,
  Typography,
  Form,
  Input,
  Select,
  Switch,
  Space,
  InputNumber,
  Divider,
  Alert,
  theme,
  Flex,
  Tag,
  Radio,
  Button,
  Descriptions,
  Splitter,
  Badge,
  Tooltip,
  Row,
  Col,
  Collapse,
  Tabs,
  Upload,
  Image,
  Slider,
  Table,
} from "antd";
import type { MenuProps } from "antd";
import {
  InfoCircleOutlined,
  EditOutlined,
  AppstoreOutlined,
  SaveOutlined,
  CloseOutlined,
  DatabaseOutlined,
  UploadOutlined,
  PictureOutlined,
  ColumnWidthOutlined,
  PlusOutlined,
  ImportOutlined,
  ExportOutlined,
  SearchOutlined,
  SortAscendingOutlined,
  DeleteOutlined,
  HistoryOutlined,
  UnorderedListOutlined,
  BarsOutlined,
  SettingOutlined,
} from "@ant-design/icons";
import { AgGridReact } from "ag-grid-react";
import {
  ColDef,
  ModuleRegistry,
  AllCommunityModule,
  themeQuartz,
  ICellRendererParams,
  Theme,
} from "ag-grid-community";
import { AttributeItem, EnumOptionItem, AttributeType } from "./types";
import FloatingContextMenu from "@/components/ContextMenu/FloatingContextMenu";

// Register AG Grid modules
ModuleRegistry.registerModules([AllCommunityModule]);

interface AttributeWorkspaceProps {
  attribute: AttributeItem | null;
  selectedCount?: number;
  onUpdate: (key: string, value: any) => void;
  enumOptions: EnumOptionItem[];
  setEnumOptions: (data: EnumOptionItem[]) => void;
  previewLoading?: boolean;
  previewWarnings?: string[];
  allowManualCodeOverride?: boolean;
  allowManualEnumCodeOverride?: boolean;
  onDiscard?: (id: string) => void;
  onSave?: (attribute: AttributeItem) => Promise<void>;
  onSaveAndNext?: (attribute: AttributeItem) => Promise<void>;
  showSaveAndNext?: boolean;
  onCancelEdit?: () => void;
  hasUnsavedChanges?: boolean;
}

const { Option } = Select;
const { Text, Title } = Typography;
const { Panel } = Collapse;
const READ_ONLY_ENUM_TABLE_HEADER_OFFSET = 47;

const isEmptyDefaultValue = (value: AttributeItem["defaultValue"]) =>
  value === undefined || value === null || (Array.isArray(value) && value.length === 0);

const normalizeNumericDefaultValue = (value: AttributeItem["defaultValue"]) => {
  if (value === undefined || value === null || value === "") {
    return undefined;
  }

  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : undefined;
};

const normalizeBooleanDefaultValue = (value: AttributeItem["defaultValue"]) => {
  if (typeof value === "boolean") {
    return value;
  }
  if (value === undefined || value === null || value === "") {
    return undefined;
  }

  const normalized = String(value).trim().toLowerCase();
  if (normalized === "true") {
    return true;
  }
  if (normalized === "false") {
    return false;
  }
  return undefined;
};

const normalizeMultiEnumDefaultValue = (value: AttributeItem["defaultValue"]) => {
  if (Array.isArray(value)) {
    return value;
  }
  if (value === undefined || value === null || value === "") {
    return [];
  }

  return String(value)
    .split(",")
    .map((item) => item.trim())
    .filter(Boolean);
};

const getBooleanDisplayLabel = (attribute: AttributeItem, value: boolean) => {
  if (value) {
    return attribute.trueLabel?.trim() || "True";
  }
  return attribute.falseLabel?.trim() || "False";
};

const formatDefaultValueForDisplay = (
  attribute: AttributeItem,
  enumOptions: EnumOptionItem[],
) => {
  if (isEmptyDefaultValue(attribute.defaultValue)) {
    return "-";
  }

  if (attribute.type === "boolean") {
    const normalized = normalizeBooleanDefaultValue(attribute.defaultValue);
    return normalized === undefined ? "-" : getBooleanDisplayLabel(attribute, normalized);
  }

  if (attribute.type === "multi-enum") {
    return normalizeMultiEnumDefaultValue(attribute.defaultValue)
      .map((item) => enumOptions.find((option) => option.value === item)?.label || item)
      .join(", ");
  }

  if (attribute.type === "enum") {
    const rawValue = String(attribute.defaultValue);
    return enumOptions.find((option) => option.value === rawValue)?.label || rawValue;
  }

  return String(attribute.defaultValue);
};

const getRenderTypeLabel = (renderType?: AttributeItem["renderType"]) => {
  if (renderType === "image") {
    return "图片 (Image)";
  }
  if (renderType === "color") {
    return "颜色 (Color)";
  }
  return "文本 (Text)";
};

const getEnumDefaultValueSet = (attribute: AttributeItem) => {
  if (attribute.type === "multi-enum") {
    return new Set(normalizeMultiEnumDefaultValue(attribute.defaultValue));
  }

  if (attribute.type === "enum") {
    const normalized = normalizeDefaultValueForType(attribute.type, attribute.defaultValue);
    return normalized ? new Set([String(normalized)]) : new Set<string>();
  }

  return new Set<string>();
};

const normalizeDefaultValueForType = (
  type: AttributeType,
  value: AttributeItem["defaultValue"],
) => {
  if (type === "boolean") {
    return normalizeBooleanDefaultValue(value);
  }
  if (type === "number") {
    return normalizeNumericDefaultValue(value);
  }
  if (type === "multi-enum") {
    const normalized = normalizeMultiEnumDefaultValue(value);
    return normalized.length > 0 ? normalized : undefined;
  }
  if (type === "enum") {
    if (Array.isArray(value)) {
      return value[0] || undefined;
    }
    return value === undefined || value === null || value === "" ? undefined : String(value);
  }
  if (Array.isArray(value)) {
    return value[0] || undefined;
  }
  return value === undefined || value === null || value === "" ? undefined : String(value);
};

const AttributeWorkspace: React.FC<AttributeWorkspaceProps> = ({
  attribute,
  selectedCount = 0,
  onUpdate,
  enumOptions,
  setEnumOptions,
  previewLoading = false,
  previewWarnings = [],
  allowManualCodeOverride = false,
  allowManualEnumCodeOverride = false,
  onDiscard,
  onSave,
  onSaveAndNext,
  showSaveAndNext,
  onCancelEdit,
  hasUnsavedChanges,
}) => {
  const { token } = theme.useToken();
  const { modal } = App.useApp();
  const [form] = Form.useForm();
  const [isEditing, setIsEditing] = useState(false);
  const [numericDefaultSliderOpen, setNumericDefaultSliderOpen] = useState(false);
  const [readOnlyEnumTableScrollY, setReadOnlyEnumTableScrollY] = useState(240);
  const [saveStatus, setSaveStatus] = useState<"idle" | "loading" | "success">("idle");
  const gridRef = useRef<AgGridReact>(null);
  const readOnlyEnumTableContainerRef = useRef<HTMLDivElement | null>(null);

  const [contextMenu, setContextMenu] = useState<{
    open: boolean;
    x: number;
    y: number;
    record: EnumOptionItem | null;
  }>({
    open: false,
    x: 0,
    y: 0,
    record: null,
  });

  const enumOptionsRef = useRef(enumOptions);
  useEffect(() => {
    enumOptionsRef.current = enumOptions;
  }, [enumOptions]);

  const showGridImage = attribute?.renderType === "image";

  const colDefs = useMemo<ColDef<EnumOptionItem>[]>(() => {
    const ImageCellRenderer = (params: ICellRendererParams) => {
      const beforeUpload = (file: File) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
          params.node.setDataValue("image", reader.result);
        };
        return false;
      };

      const handleRemove = (e: React.MouseEvent) => {
        e.stopPropagation();
        params.node.setDataValue("image", undefined);
      };

      return (
        <Flex align="center" justify="space-between" style={{ width: "100%" }}>
          {params.value ? (
            <Image
              src={params.value}
              alt="preview"
              width={24}
              height={24}
              style={{ objectFit: "cover", borderRadius: 4 }}
              preview={{
                mask: null,
              }}
              onClick={(e) => e.stopPropagation()}
            />
          ) : (
            <div
              style={{
                width: 24,
                height: 24,
                background: token.colorFillAlter,
                borderRadius: 4,
              }}
            />
          )}
          {params.value && (
            <Button
              type="text"
              danger
              size="small"
              icon={<CloseOutlined />}
              onClick={handleRemove}
              title="删除图片 (Delete Image)"
              style={{
                marginLeft: 0,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            />
          )}
          <Upload
            showUploadList={false}
            beforeUpload={beforeUpload}
            accept="image/*"
          >
            <Button
              type="text"
              size="small"
              icon={<UploadOutlined />}
              title={params.value ? "更换图片 (Replace)" : "上传图片 (Upload)"}
              style={{
                color: token.colorTextSecondary,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            />
          </Upload>
        </Flex>
      );
    };

    const baseDefs: ColDef<EnumOptionItem>[] = [
      {
        headerName: "",
        valueGetter: "node.rowIndex + 1",
        width: 50,
        flex: 0,
        editable: false,
        pinned: "left",
        lockPosition: true,
        suppressMovable: true,
        resizable: false,
        cellStyle: {
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          backgroundColor: token.colorFillAlter,
          color: token.colorTextSecondary,
          fontWeight: 600,
        },
      },
      {
        headerName: "",
        width: 50,
        pinned: "left",
        lockPosition: true,
        suppressMovable: true,
        checkboxSelection: true,
        headerCheckboxSelection: true,
        flex: 0,
        resizable: false,
        cellStyle: {
          justifyContent: "center",
          alignItems: "center",
        },
      },
      {
        headerName: "编码 (Code)",
        field: "code",
        editable: true,
        flex: 1,
        rowDrag: true,
      },
      {
        headerName: "枚举值 (Value)",
        field: "value",
        editable: true,
        flex: 1,
        cellEditor: "agTextCellEditor",
      },
      {
        headerName: "显示标签 (Label)",
        field: "label",
        editable: true,
        flex: 1,
      },
      {
        headerName: "操作",
        width: 70,
        flex: 0,
        editable: false,
        sortable: false,
        pinned: "right",
        lockPosition: true,
        cellStyle: {
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
        },
        cellRenderer: (params: ICellRendererParams) => (
          <Button
            type="text"
            danger
            size="small"
            icon={<DeleteOutlined />}
            onClick={() =>
              setEnumOptions(
                enumOptionsRef.current.filter(
                  (item) => item.id !== params.data.id,
                ),
              )
            }
          />
        ),
      },
    ];

    if (showGridImage) {
      baseDefs.splice(4, 0, {
        headerName: "图片 (Image)",
        field: "image",
        width: 120,
        flex: 0,
        editable: false,
        cellRenderer: ImageCellRenderer,
        cellStyle: { display: "flex", alignItems: "center" },
      });
    }

    return baseDefs;
  }, [showGridImage, token, setEnumOptions]);

  // Consolidated effect to handle attribute changes
  const prevAttributeIdRef = useRef<string | undefined>(undefined);

  useEffect(() => {
    if (!attribute) {
      prevAttributeIdRef.current = undefined;
      form.resetFields();
      setIsEditing(false);
      setSaveStatus("idle");
      return;
    }

    if (attribute.id !== prevAttributeIdRef.current) {
      // Attribute selection changed: switch editing mode by attribute type
      const isNew = attribute.id.startsWith("new_attr_");
      form.resetFields();
      form.setFieldsValue(attribute);
      setIsEditing(isNew);
      setSaveStatus("idle");
      prevAttributeIdRef.current = attribute.id;
      return;
    }

    // Same attribute updated while editing: keep form in sync.
    if (isEditing) {
      form.setFieldsValue(attribute);
    }
  }, [attribute, isEditing, form]);

  useEffect(() => {
    // Ensure form values are written only after edit form is mounted.
    if (!isEditing || !attribute) return;
    form.setFieldsValue(attribute);
  }, [isEditing, attribute, form]);

  useEffect(() => {
    setNumericDefaultSliderOpen(false);
  }, [attribute?.id, attribute?.type]);

  useEffect(() => {
    const container = readOnlyEnumTableContainerRef.current;
    if (!container || attribute?.type !== "enum" && attribute?.type !== "multi-enum") {
      return;
    }

    const updateTableScrollY = () => {
      const nextHeight = Math.max(
        container.clientHeight - READ_ONLY_ENUM_TABLE_HEADER_OFFSET,
        120,
      );
      setReadOnlyEnumTableScrollY(nextHeight);
    };

    updateTableScrollY();

    const observer = new ResizeObserver(() => {
      updateTableScrollY();
    });

    observer.observe(container);
    return () => {
      observer.disconnect();
    };
  }, [attribute?.id, attribute?.type, enumOptions.length]);

  /* Removed conflicting useEffects */

  if (!attribute) {
    if (selectedCount > 1) {
      return (
        <Flex
          vertical
          justify="center"
          align="center"
          style={{
            height: "100%",
            background: token.colorBgLayout,
            padding: 24,
          }}
        >
          <AppstoreOutlined style={{ fontSize: 52, color: token.colorInfo, marginBottom: 20 }} />
          <Title level={3} style={{ margin: 0, marginBottom: 16 }}>
            已选择 {selectedCount} 个属性
          </Title>
          <Alert
            type="info"
            showIcon
            message="选择单个属性以查看详细信息并编辑"
            style={{ maxWidth: 520, width: "100%" }}
          />
        </Flex>
      );
    }

    return (
      <Flex
        justify="center"
        align="center"
        style={{
          height: "100%",
          color: token.colorTextQuaternary,
          background: token.colorBgLayout,
        }}
      >
        <Empty
          image={Empty.PRESENTED_IMAGE_SIMPLE}
          description="请选择一个属性进行配置 (Select an attribute)"
        />
      </Flex>
    );
  }

  const handleFormChange = (changedValues: any) => {
    if (attribute && "type" in changedValues) {
      const nextType = changedValues.type as AttributeType;
      const nextDefaultValue = normalizeDefaultValueForType(
        nextType,
        attribute.defaultValue,
      );

      onUpdate("type", nextType);
      onUpdate("defaultValue", nextDefaultValue);
      form.setFieldValue("defaultValue", nextDefaultValue);
      return;
    }

    Object.keys(changedValues).forEach((key) => {
      onUpdate(key, changedValues[key]);
    });
  };

  const handleSave = (saveAndNext: boolean = false) => {
    form
      .validateFields()
      .then(async () => {
        if (attribute && ((saveAndNext && onSaveAndNext) || (!saveAndNext && onSave))) {
          setSaveStatus("loading");
          try {
             if (saveAndNext && onSaveAndNext) {
               await onSaveAndNext(attribute);
             } else if (onSave) {
               await onSave(attribute);
               setIsEditing(false);
             }
             setSaveStatus("success");
             setTimeout(() => setSaveStatus("idle"), 2000);
          } catch (e: any) {
             setSaveStatus("idle");
             // Error handling should be done by onSave or global message
             const errorMsg = e?.message || e?.error || "";
             if (errorMsg.includes("attribute already exists")) {
               form.setFields([
                 {
                   name: "code",
                   errors: ["属性编码已存在，请修改"],
                 },
               ]);
             }
          }
        } else {
             setIsEditing(false);
             setSaveStatus("success");
             setTimeout(() => setSaveStatus("idle"), 2000);
        }
      })
      .catch((info) => {
        console.log("Validate Failed:", info);
      });
  };

  const handleCancel = () => {
    if (
      attribute?.id.startsWith("new_attr_") &&
      onDiscard
    ) {
      modal.confirm({
        title: "放弃新建? (Discard New Attribute?)",
        content:
          "这是一个未保存的新属性，取消将直接删除该属性。是否确认放弃？(This is an unsaved new attribute. Canceling will delete it. Are you sure?)",
        okText: "放弃 (Discard)",
        cancelText: "继续编辑 (Continue Editing)",
        okButtonProps: { danger: true },
        onOk: () => {
          onDiscard(attribute.id);
        },
      });
    } else {
      onCancelEdit?.();
      setIsEditing(false);
    }
  };

  // Determine Modes
  const isListMode =
    attribute.type === "enum" ||
    attribute.type === "multi-enum" ||
    (attribute.type === "number" && attribute.constraintMode === "list");
  const isNewAttribute = attribute.id.startsWith("new_attr_");

  // --- Render Sections ---

  const renderHeader = () => (
    <Flex
      align="center"
      justify="space-between"
      style={{
        padding: "8px 16px",
        borderBottom: `1px solid ${token.colorBorderSecondary}`,
        background: token.colorBgContainer,
        height: 44,
      }}
    >
      <Space size={12}>
        <Title level={5} style={{ margin: 0 }}>
          {attribute.name}
        </Title>
        {hasUnsavedChanges && (
          <Tag color="warning" variant="filled" style={{ marginInlineEnd: 0 }}>
            未保存
          </Tag>
        )}
        <Tag color="cyan">V{attribute.version}.0</Tag>
        <Text type="secondary" copyable style={{ fontSize: 12 }}>
          {attribute.attributeField || attribute.code}
        </Text>
        <Tag color="blue" variant="filled">
          {attribute.type}
        </Tag>
      </Space>

      <Space size="small">
        {!isEditing ? (
          <Button
            type="text"
            size="small"
            icon={<EditOutlined />}
            onClick={() => {
              if (!attribute) return;
              setIsEditing(true);
            }}
          >
            编辑 (Edit)
          </Button>
        ) : (
          <>
            <Button size="small" onClick={handleCancel}>
              取消
            </Button>
            <Button
              type="primary"
              size="small"
              icon={<SaveOutlined />}
              onClick={() => handleSave(false)}
            >
              保存
            </Button>
            {showSaveAndNext && (
              <Button
                size="small"
                onClick={() => handleSave(true)}
              >
                保存并转至下一条
              </Button>
            )}
          </>
        )}
      </Space>
    </Flex>
  );

  const renderReadOnlyMeta = () => {
    const sortedEnumOptions = [...enumOptions].sort(
      (left, right) => (left.order ?? 0) - (right.order ?? 0),
    );
    const defaultValueSet = getEnumDefaultValueSet(attribute);
    const isEnumType = attribute.type === "enum" || attribute.type === "multi-enum";
    const enumTableColumns = [
      {
        title: "#",
        dataIndex: "index",
        key: "index",
        width: 56,
        align: "center" as const,
        render: (_: unknown, __: EnumOptionItem, index: number) => (
          <Text type="secondary">{index + 1}</Text>
        ),
      },
      {
        title: "枚举值",
        dataIndex: "value",
        key: "value",
        width: attribute.renderType === "image" ? 120 : 220,
        render: (value: string, option: EnumOptionItem, index: number) => (
          <Flex align="center" gap={8}>
            {option.image ? (
              <Image
                src={option.image}
                alt={option.value || option.label || `enum-option-${index + 1}`}
                width={24}
                height={24}
                style={{ objectFit: "cover", borderRadius: 4, flex: "0 0 auto" }}
                preview={false}
              />
            ) : null}
            <Text ellipsis style={{ minWidth: 0 }}>
              {value || "-"}
            </Text>
          </Flex>
        ),
      },
      {
        title: "显示标签",
        dataIndex: "label",
        key: "label",
        render: (value: string) => (
          <Text ellipsis style={{ minWidth: 0 }}>
            {value || "-"}
          </Text>
        ),
      },
      {
        title: "编码",
        dataIndex: "code",
        key: "code",
        width: 320,
        render: (value: string) => (
          <Text type="secondary" ellipsis style={{ minWidth: 0 }}>
            {value || "-"}
          </Text>
        ),
      },
      {
        title: "默认值",
        key: "isDefault",
        width: 96,
        align: "center" as const,
        render: (_: unknown, option: EnumOptionItem) => (
          defaultValueSet.has(option.value) ? (
            <Tag color="blue" style={{ marginInlineEnd: 0 }}>
              默认
            </Tag>
          ) : (
            <Text type="secondary">-</Text>
          )
        ),
      },
    ];

    return (
      <div
        style={{
          padding: 12,
          height: "100%",
          display: "flex",
          flexDirection: "column",
          minHeight: 0,
          overflow: "hidden",
        }}
      >
      <Title
        level={5}
        style={{
          marginTop: 0,
          marginBottom: 12,
          fontSize: 16,
          color: token.colorTextSecondary,
        }}
      >
        基础信息 (Basic Information)
      </Title>
      <Descriptions
        column={2}
        bordered
        size="small"
        styles={{ label: { width: "180px" } }}
      >
        <Descriptions.Item label="名称 (Display Name)">
          {attribute.name}
        </Descriptions.Item>
        <Descriptions.Item label="数据类型 (Data Type)">
          {attribute.type}
        </Descriptions.Item>
        <Descriptions.Item label="属性字段 (Attribute Field)">
          {attribute.attributeField || "-"}
        </Descriptions.Item>
        <Descriptions.Item label="编码 (Code)">
          {attribute.code}
        </Descriptions.Item>
        <Descriptions.Item label="默认值 (Default)">
          {formatDefaultValueForDisplay(attribute, enumOptions)}
        </Descriptions.Item>
        <Descriptions.Item label="单位 (Unit)">
          {attribute.unit || "-"}
        </Descriptions.Item>
        <Descriptions.Item label="可见性 (Visibility)">
          <Space separator={<Divider orientation="vertical" />}>
            <Text>{attribute.hidden ? "Hidden" : "Visible"}</Text>
            <Text>{attribute.readonly ? "Read-only" : "Writable"}</Text>
          </Space>
        </Descriptions.Item>
        <Descriptions.Item label="必填 (Required)">
          {attribute.required ? "Yes" : "No"}
        </Descriptions.Item>
        <Descriptions.Item label="描述 (Description)">
          {attribute.description || "-"}
        </Descriptions.Item>
        <Descriptions.Item label="创建人 (Created By)">
          {attribute.createdBy || "Admin"}
        </Descriptions.Item>
        <Descriptions.Item label="创建时间 (Created At)">
          {attribute.createdAt || "2023-01-01 12:00"}
        </Descriptions.Item>
        <Descriptions.Item label="修改人 (Modified By)">
          {attribute.modifiedBy || "Admin"}
        </Descriptions.Item>
        <Descriptions.Item label="修改时间 (Modified At)">
          {attribute.modifiedAt || "2023-10-24 14:30"}
        </Descriptions.Item>
      </Descriptions>

      <Title
        level={5}
        style={{
          marginTop: 16,
          marginBottom: 12,
          fontSize: 16,
          color: token.colorTextSecondary,
        }}
      >
        类型配置 (Type Configuration)
      </Title>
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          flex: isEnumType ? 1 : "0 0 auto",
          minHeight: 0,
        }}
      >
        <Descriptions
          column={2}
          bordered
          size="small"
          styles={{ label: { width: "180px" } }}
        >
          <Descriptions.Item label="数据类型 (Data Type)">
            {attribute.type}
          </Descriptions.Item>
          <Descriptions.Item label="默认值策略 (Default Strategy)">
            {attribute.defaultValue === undefined || attribute.defaultValue === null
              ? "未配置 (Not Configured)"
              : "已配置 (Configured)"}
          </Descriptions.Item>
          {attribute.type === "number" ? (
            <>
              <Descriptions.Item label="最小值 (Min Value)">
                {attribute.min ?? "-"}
              </Descriptions.Item>
              <Descriptions.Item label="最大值 (Max Value)">
                {attribute.max ?? "-"}
              </Descriptions.Item>
              <Descriptions.Item label="步长 (Step)">
                {attribute.step ?? "-"}
              </Descriptions.Item>
              <Descriptions.Item label="精度 (Precision)">
                {attribute.precision ?? "-"}
              </Descriptions.Item>
            </>
          ) : null}
          {attribute.type === "boolean" ? (
            <>
              <Descriptions.Item label="True 显示文本 (True Label)">
                {attribute.trueLabel || "True"}
              </Descriptions.Item>
              <Descriptions.Item label="False 显示文本 (False Label)">
                {attribute.falseLabel || "False"}
              </Descriptions.Item>
            </>
          ) : null}
          {isEnumType ? (
            <>
              <Descriptions.Item label="渲染方式 (Render Type)">
                {getRenderTypeLabel(attribute.renderType)}
              </Descriptions.Item>
              <Descriptions.Item label="可选项数量 (Option Count)">
                {enumOptions.length}
              </Descriptions.Item>
            </>
          ) : null}
          {(attribute.type === "string" || attribute.type === "date") ? (
            <Descriptions.Item label="附加配置 (Additional Config)" span={2}>
              当前数据类型暂无额外配置。
            </Descriptions.Item>
          ) : null}
        </Descriptions>

        {isEnumType ? (
          <div
            style={{
              marginTop: 12,
              display: "flex",
              flexDirection: "column",
              flex: 1,
              minHeight: 0,
              overflow: "hidden",
            }}
          >
            <Text
              type="secondary"
              style={{
                marginBottom: 8,
                fontSize: 12,
              }}
            >
              选项内容 (Options)
            </Text>
            <div
              ref={readOnlyEnumTableContainerRef}
              style={{
                flex: 1,
                minHeight: 0,
                overflow: "hidden",
                border: `1px solid ${token.colorBorderSecondary}`,
                borderRadius: token.borderRadiusLG,
              }}
            >
              <Table
                className="app-ant-table-scroll"
                size="small"
                bordered={false}
                pagination={false}
                columns={enumTableColumns}
                dataSource={sortedEnumOptions}
                rowKey="id"
                scroll={{ y: readOnlyEnumTableScrollY, x: 760 }}
                onRow={(record) => ({
                  style: {
                    background: defaultValueSet.has(record.value)
                      ? token.colorPrimaryBg
                      : token.colorBgContainer,
                  },
                })}
              />
            </div>
          </div>
        ) : null}
      </div>
    </div>
    );
  };

  const renderEditForm = () => (
    <Form
      form={form}
      layout="vertical"
      onValuesChange={handleFormChange}
      style={{ height: "100%", overflowY: "auto" }}
      size="small"
    >
      <Tabs
        defaultActiveKey="basic"
        style={{ height: "100%" }}
        tabBarStyle={{ padding: "0 16px", margin: 0 }}
        items={[
          {
            key: "basic",
            label: (
              <span>
                <BarsOutlined /> 基础 (Basic)
              </span>
            ),
            children: (
              <div style={{ padding: 12 }}>
                <div
                  style={{
                    background: "transparent",
                    borderRadius: 0,
                    padding: 0,
                  }}
                >
                  <Title
                    level={5}
                    style={{
                      marginTop: 0,
                      marginBottom: 15,
                      fontSize: 16,
                      color: token.colorTextSecondary,
                    }}
                  >
                    属性详情 (Attribute Details)
                  </Title>
                  <Row gutter={[16, 0]}>
                    <Col xs={24} sm={12} md={12} lg={12} xl={6}>
                      <Form.Item
                        label="名称 (Display Name)"
                        name="name"
                        rules={[{ required: true }]}
                      >
                        <Input size="middle" />
                      </Form.Item>
                    </Col>
                    <Col xs={24} sm={12} md={12} lg={12} xl={6}>
                      <Form.Item
                        label="属性字段 (Attribute Field)"
                        name="attributeField"
                      >
                        <Input size="middle" />
                      </Form.Item>
                    </Col>
                    <Col xs={24} sm={12} md={12} lg={12} xl={6}>
                      <Form.Item
                        label="编码 (Code)"
                        name="code"
                        rules={[{ required: true }]}
                      >
                        <Input
                          disabled={!attribute.isLatest}
                          size="middle"
                          placeholder={isNewAttribute ? "系统会先自动建议编码，你也可以直接改写" : undefined}
                        />
                      </Form.Item>
                    </Col>
                    <Col xs={24} sm={12} md={12} lg={12} xl={6}>
                      <Form.Item label="数据类型 (Data Type)" name="type">
                        <Select size="middle">
                          <Option value="number">Number</Option>
                          <Option value="boolean">Boolean</Option>
                          <Option value="enum">Enum</Option>
                          <Option value="multi-enum">Multi Enum</Option>
                        </Select>
                      </Form.Item>
                    </Col>
                  </Row>

                  <Row gutter={[16, 0]}>
                    <Col xs={24} sm={24} md={24} lg={12} xl={10}>
                      <Form.Item
                        label="描述 (Description)"
                        name="description"
                      >
                        <Input size="middle" />
                      </Form.Item>
                    </Col>
                    <Col xs={24} sm={12} md={12} lg={6} xl={7}>
                      <Form.Item label="单位 (Unit)" name="unit">
                        <Input size="middle" />
                      </Form.Item>
                    </Col>
                    <Col xs={24} sm={12} md={12} lg={6} xl={7}>
                      <Form.Item label="默认值 (Default Value)">
                        {attribute.type === "boolean" ? (
                          <Select
                            placeholder="选择默认值 (Select default)"
                            allowClear
                            size="middle"
                            value={normalizeBooleanDefaultValue(attribute.defaultValue)}
                            onChange={(value) => {
                              onUpdate("defaultValue", value);
                              form.setFieldValue("defaultValue", value);
                            }}
                            onClear={() => {
                              onUpdate("defaultValue", undefined);
                              form.setFieldValue("defaultValue", undefined);
                            }}
                            options={[
                              {
                                label: getBooleanDisplayLabel(attribute, true),
                                value: true,
                              },
                              {
                                label: getBooleanDisplayLabel(attribute, false),
                                value: false,
                              },
                            ]}
                          />
                        ) : attribute.type === "number" ? (
                          <Flex
                            vertical
                            gap={8}
                            onMouseLeave={() => {
                              setNumericDefaultSliderOpen(false);
                            }}
                          >
                            <InputNumber
                              style={{ width: "100%" }}
                              size="middle"
                              min={attribute.min}
                              max={attribute.max}
                              step={typeof attribute.step === "number" && attribute.step > 0 ? attribute.step : 1}
                              precision={attribute.precision}
                              placeholder="输入默认值 (Enter default)"
                              value={normalizeNumericDefaultValue(attribute.defaultValue)}
                              onFocus={() => {
                                if (
                                  typeof attribute.min === "number" &&
                                  typeof attribute.max === "number" &&
                                  attribute.max > attribute.min
                                ) {
                                  setNumericDefaultSliderOpen(true);
                                }
                              }}
                              onClick={() => {
                                if (
                                  typeof attribute.min === "number" &&
                                  typeof attribute.max === "number" &&
                                  attribute.max > attribute.min
                                ) {
                                  setNumericDefaultSliderOpen(true);
                                }
                              }}
                              onChange={(value) => {
                                const nextValue = value === null ? undefined : value;
                                onUpdate("defaultValue", nextValue);
                                form.setFieldValue("defaultValue", nextValue);
                              }}
                            />
                            {numericDefaultSliderOpen &&
                            typeof attribute.min === "number" &&
                            typeof attribute.max === "number" &&
                            attribute.max > attribute.min ? (
                              <div
                                style={{
                                  padding: 12,
                                  borderRadius: token.borderRadiusLG,
                                  border: `1px solid ${token.colorBorderSecondary}`,
                                  background: token.colorFillQuaternary,
                                }}
                              >
                                <Slider
                                  min={attribute.min}
                                  max={attribute.max}
                                  step={typeof attribute.step === "number" && attribute.step > 0 ? attribute.step : 1}
                                  value={normalizeNumericDefaultValue(attribute.defaultValue)}
                                  onChange={(value) => {
                                    const nextValue = Array.isArray(value) ? value[0] : value;
                                    onUpdate("defaultValue", nextValue);
                                    form.setFieldValue("defaultValue", nextValue);
                                  }}
                                  tooltip={{ open: false }}
                                />
                                <Flex justify="space-between" align="center">
                                  <Text type="secondary" style={{ fontSize: 12 }}>
                                    {attribute.min} ~ {attribute.max}
                                  </Text>
                                  <Text type="secondary" style={{ fontSize: 12 }}>
                                    步长 {typeof attribute.step === "number" && attribute.step > 0 ? attribute.step : 1}
                                  </Text>
                                </Flex>
                              </div>
                            ) : null}
                            <Text type="secondary" style={{ fontSize: 12 }}>
                              {typeof attribute.min === "number" && typeof attribute.max === "number"
                                ? "点击输入框可展开滑块，选定数值后会自动收起。"
                                : "设置最小值和最大值后，可在此处用滑块快速选择默认值。"}
                            </Text>
                          </Flex>
                        ) : isListMode ? (
                          <Select
                            placeholder="选择默认值 (Select default)"
                            allowClear
                            mode={
                              attribute.type === "multi-enum"
                                ? "multiple"
                                : undefined
                            }
                            size="middle"
                            optionLabelProp="label"
                            value={
                              attribute.type === "multi-enum"
                                ? normalizeMultiEnumDefaultValue(attribute.defaultValue)
                                : normalizeDefaultValueForType(attribute.type, attribute.defaultValue)
                            }
                            onChange={(value) => {
                              const nextValue = attribute.type === "multi-enum"
                                ? (Array.isArray(value) ? value : [])
                                : value;
                              onUpdate("defaultValue", nextValue);
                              form.setFieldValue("defaultValue", nextValue);
                            }}
                            onClear={() => {
                              const nextValue = attribute.type === "multi-enum" ? [] : undefined;
                              onUpdate("defaultValue", nextValue);
                              form.setFieldValue("defaultValue", nextValue);
                            }}
                          >
                            {enumOptions.map((opt) => (
                              <Option
                                key={opt.id}
                                value={opt.value}
                                label={opt.value}
                              >
                                <Space>
                                  {opt.image && (
                                    <img
                                      src={opt.image}
                                      alt={opt.value}
                                      style={{
                                        width: 16,
                                        height: 16,
                                        objectFit: "cover",
                                        borderRadius: 2,
                                        verticalAlign: "middle",
                                      }}
                                    />
                                  )}
                                  <span>
                                    {opt.value}
                                  </span>
                                </Space>
                              </Option>
                            ))}
                          </Select>
                        ) : (
                          <Input
                            placeholder="-"
                            size="middle"
                            value={
                              attribute.defaultValue === undefined || attribute.defaultValue === null
                                ? undefined
                                : String(attribute.defaultValue)
                            }
                            onChange={(event) => {
                              const nextValue = event.target.value || undefined;
                              onUpdate("defaultValue", nextValue);
                              form.setFieldValue("defaultValue", nextValue);
                            }}
                          />
                        )}
                      </Form.Item>
                    </Col>
                  </Row>

                </div>
              </div>
            ),
          },
          {
            key: "settings",
            label: (
              <span>
                <SettingOutlined /> 设置 (Settings)
              </span>
            ),
            children: (
              <div style={{ padding: 12 }}>
                <Row gutter={16}>
                  <Col span={12}>
                    <div
                      style={{
                        background: token.colorFillQuaternary,
                        borderRadius: 8,
                        padding: 8,
                        height: "100%",
                      }}
                    >
                      <Title
                        level={5}
                        style={{
                          marginTop: 0,
                          marginBottom: 16,
                          fontSize: 16,
                          color: token.colorTextSecondary,
                        }}
                      >
                        行为控制 (Behavior)
                      </Title>
                      <Flex vertical gap="middle">
                        <Flex justify="space-between" align="center">
                          <span>必填 (Required)</span>
                          <Form.Item
                            name="required"
                            valuePropName="checked"
                            noStyle
                          >
                            <Switch size="small" />
                          </Form.Item>
                        </Flex>
                        <Flex justify="space-between" align="center">
                          <span>唯一 (Unique)</span>
                          <Form.Item
                            name="unique"
                            valuePropName="checked"
                            noStyle
                          >
                            <Switch size="small" />
                          </Form.Item>
                        </Flex>
                      </Flex>
                    </div>
                  </Col>
                  <Col span={12}>
                    <div
                      style={{
                        background: token.colorFillQuaternary,
                        borderRadius: 8,
                        padding: 8,
                        height: "100%",
                      }}
                    >
                      <Title
                        level={5}
                        style={{
                          marginTop: 0,
                          marginBottom: 16,
                          fontSize: 16,
                          color: token.colorTextSecondary,
                        }}
                      >
                        可见性 (Visibility)
                      </Title>
                      <Flex vertical gap="middle">
                        <Flex justify="space-between" align="center">
                          <span>隐藏 (Hidden)</span>
                          <Form.Item
                            name="hidden"
                            valuePropName="checked"
                            noStyle
                          >
                            <Switch size="small" />
                          </Form.Item>
                        </Flex>
                        <Flex justify="space-between" align="center">
                          <span>只读 (Read-only)</span>
                          <Form.Item
                            name="readonly"
                            valuePropName="checked"
                            noStyle
                          >
                            <Switch size="small" />
                          </Form.Item>
                        </Flex>
                        <Flex justify="space-between" align="center">
                          <span>搜索索引 (Search Index)</span>
                          <Form.Item
                            name="searchable"
                            valuePropName="checked"
                            noStyle
                          >
                            <Switch size="small" />
                          </Form.Item>
                        </Flex>
                      </Flex>
                    </div>
                  </Col>
                </Row>
              </div>
            ),
          },
        ]}
      />
    </Form>
  );

  const renderValueDomain = () => {
    // Helper to update attribute type
    const handleTypeChange = (newType: AttributeType) => {
      onUpdate("type", newType);
      form.setFieldValue("type", newType);
    };

    // Helper to update specific fields
    const updateAttribute = (updates: Partial<AttributeItem>) => {
      Object.entries(updates).forEach(([key, value]) => {
        onUpdate(key, value);
      });
      form.setFieldsValue(updates);
    };

    const renderCommonHelper = (
      title: string,
      children: React.ReactNode,
      extra?: React.ReactNode,
    ) => (
      <div style={{ height: "100%", display: "flex", flexDirection: "column" }}>
        <Flex
          justify="space-between"
          align="center"
          style={{
            padding: "8px 12px",
            borderBottom: `1px solid ${token.colorBorderSecondary}`,
            background: token.colorPrimaryBg,
          }}
        >
          <Space size="small">
            <AppstoreOutlined />
            <span style={{ fontWeight: 600, fontSize: 13 }}>{title}</span>
          </Space>
          {extra}
        </Flex>
        <div style={{ flex: 1, padding: 12, overflowY: "auto" }}>
          {children}
        </div>
      </div>
    );

    // 1. String: Text Rules
    // if (attribute.type === "string") {
    //   return renderCommonHelper(
    //     "文本规则 (Text Rules)",
    //     <Form layout="vertical" size="small">
    //       <Row gutter={16}>
    //         <Col span={12}>
    //           <Form.Item label="最小长度 (Min Length)">
    //             <InputNumber
    //               style={{ width: "100%" }}
    //               min={0}
    //               value={attribute.minLength}
    //               onChange={(v) =>
    //                 updateAttribute({ minLength: v || undefined })
    //               }
    //             />
    //           </Form.Item>
    //         </Col>
    //         <Col span={12}>
    //           <Form.Item label="最大长度 (Max Length)">
    //             <InputNumber
    //               style={{ width: "100%" }}
    //               min={0}
    //               value={attribute.maxLength}
    //               onChange={(v) =>
    //                 updateAttribute({ maxLength: v || undefined })
    //               }
    //             />
    //           </Form.Item>
    //         </Col>
    //       </Row>
    //       <Form.Item label="正则表达式 (Regex Pattern)">
    //         <Input
    //           prefix="/"
    //           placeholder="e.g. ^[a-z]+$"
    //           value={attribute.pattern}
    //           onChange={(e) => updateAttribute({ pattern: e.target.value })}
    //         />
    //       </Form.Item>
    //     </Form>,
    //     <Button
    //       size="small"
    //       type="link"
    //       onClick={() => handleTypeChange("enum")}
    //     >
    //       转为枚举 (Convert to Enum)
    //     </Button>
    //   );
    // }

    // 2. Number: Numeric Rules
    if (attribute.type === "number") {
      return renderCommonHelper(
        "数值规则 (Numeric Rules)",
        <Form layout="vertical" size="middle">
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item label="最小值 (Min Value)">
                <InputNumber
                  style={{ width: "100%" }}
                  value={attribute.min}
                  onChange={(value) => updateAttribute({ min: value ?? undefined })}
                />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item label="最大值 (Max Value)">
                <InputNumber
                  style={{ width: "100%" }}
                  value={attribute.max}
                  onChange={(value) => updateAttribute({ max: value ?? undefined })}
                />
              </Form.Item>
            </Col>
          </Row>
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item label="步长 (Step)">
                <InputNumber
                  style={{ width: "100%" }}
                  min={0}
                  value={attribute.step}
                  onChange={(value) => updateAttribute({ step: value ?? undefined })}
                />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item label="精度 (Precision)">
                <InputNumber
                  style={{ width: "100%" }}
                  min={0}
                  max={10}
                  value={attribute.precision}
                  onChange={(value) =>
                    updateAttribute({ precision: value ?? undefined })
                  }
                />
              </Form.Item>
            </Col>
          </Row>
        </Form>,
      );
    }

    // 3. Boolean: Display Config
    if (attribute.type === "boolean") {
      return renderCommonHelper(
        "布尔配置 (Boolean Configuration)",
        <Form layout="vertical" size="small">
          <Form.Item label="True 显示文本 (Display for True)">
            <Input
              placeholder="e.g. Yes, Open, Active"
              value={attribute.trueLabel}
              onChange={(e) => updateAttribute({ trueLabel: e.target.value })}
            />
          </Form.Item>
          <Form.Item label="False 显示文本 (Display for False)">
            <Input
              placeholder="e.g. No, Closed, Inactive"
              value={attribute.falseLabel}
              onChange={(e) =>
                updateAttribute({ falseLabel: e.target.value })
              }
            />
          </Form.Item>
        </Form>
      );
    }

    const showImage = attribute.renderType === "image";

    const handleAddRow = () => {
      const newItem: EnumOptionItem = {
        id: Math.random().toString(36).substr(2, 9),
        code: "",
        value: "",
        label: "",
        order: enumOptions.length + 1,
      };
      const newOptions = [...enumOptions, newItem];
      setEnumOptions(newOptions);

      // Automatically scroll to the newly added row
      setTimeout(() => {
        if (gridRef.current && gridRef.current.api) {
          const lastIndex = newOptions.length - 1;
          gridRef.current.api.ensureIndexVisible(lastIndex, "bottom");
          gridRef.current.api.setFocusedCell(lastIndex, "value");
        }
      }, 100);
    };

    const handleContextMenu = (params: any) => {
      params.event.preventDefault();
      setContextMenu({
        open: true,
        x: params.event.clientX,
        y: params.event.clientY,
        record: params.data,
      });
    };

    const contextMenuItems: MenuProps["items"] = [
      {
        key: "add",
        label: "新增行 (Add Row)",
        icon: <PlusOutlined />,
      },
      {
        type: "divider",
      },
      {
        key: "delete",
        label: "删除此行 (Delete Row)",
        icon: <DeleteOutlined />,
        danger: true,
        disabled: !contextMenu.record,
      },
    ];

    const handleExport = () => {
      const header = ["Code", "Value", "Label", "Image"];
      const csvContent = [
        header.join(","),
        ...enumOptions.map((item) =>
          [item.code, item.value, item.label, item.image || ""]
            .map((field) => `"${String(field || "").replace(/"/g, '""')}"`)
            .join(",")
        ),
      ].join("\n");
      const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `enum_options_${new Date().getTime()}.csv`;
      link.click();
      URL.revokeObjectURL(url);
    };

    const handleImport = (file: File) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const content = e.target?.result as string;
        const lines = content.split(/\r\n|\n/);
        const newItems: EnumOptionItem[] = [];
        lines.forEach((line, index) => {
          if (!line.trim()) return;
          const parts = line
            .split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/)
            .map((s) => s.replace(/^"|"$/g, "").trim());
          if (
            index === 0 &&
            (parts[0].toLowerCase() === "code" ||
              parts[0].toLowerCase() === '"code"')
          )
            return;

          if (parts.length >= 3) {
            newItems.push({
              id: Math.random().toString(36).substr(2, 9),
              code: parts[0],
              value: parts[1],
              label: parts[2],
              image: parts[3] ? parts[3] : undefined,
              order: enumOptions.length + newItems.length + 1,
            });
          }
        });
        setEnumOptions([...enumOptions, ...newItems]);
      };
      reader.readAsText(file);
      return false;
    };

    return (
      <div style={{ height: "100%", display: "flex", flexDirection: "column" }}>
        <FloatingContextMenu
          open={contextMenu.open}
          x={contextMenu.x}
          y={contextMenu.y}
          items={contextMenuItems}
          onMenuClick={({ key, domEvent }) => {
            domEvent.stopPropagation();
            if (key === "add") {
              handleAddRow();
            }
            if (key === "delete" && contextMenu.record) {
              setEnumOptions(
                enumOptions.filter((item) => item.id !== contextMenu.record?.id),
              );
            }
            setContextMenu((prev) => ({ ...prev, open: false }));
          }}
          onClose={() => {
            setContextMenu((prev) => ({ ...prev, open: false }));
          }}
        />
        {/* Toolbar */}
        <Flex
          justify="space-between"
          align="center"
          style={{
            padding: "8px 12px",
            borderBottom: `1px solid ${token.colorBorderSecondary}`,
            background: token.colorPrimaryBg,
          }}
        >
          <Space size="small">
            <AppstoreOutlined />
            <span style={{ fontWeight: 600, fontSize: 13 }}>枚举值定义</span>
          </Space>
          <Space>
            <Button
              type="text"
              size="small"
              icon={<PlusOutlined />}
              onClick={handleAddRow}
              title="新增 (Add)"
            >
              新增
            </Button>
            <Divider orientation="vertical" />
            <Upload
              beforeUpload={handleImport}
              showUploadList={false}
              accept=".csv"
            >
              <Button
                type="text"
                size="small"
                icon={<ImportOutlined />}
                title="导入 (Import)"
              >
                导入
              </Button>
            </Upload>
            <Button
              type="text"
              size="small"
              icon={<ExportOutlined />}
              onClick={handleExport}
              title="导出 (Export)"
            >
              导出
            </Button>
            <Divider orientation="vertical" />
            <span style={{ fontSize: 12, color: token.colorTextSecondary }}>
              图片描述 (Image Description)
            </span>
            <Switch
              size="small"
              checked={showImage}
              onChange={(checked) =>
                updateAttribute({ renderType: checked ? "image" : "text" })
              }
            />
            <Divider orientation="vertical" />
          </Space>
        </Flex>

        <div style={{ flex: 1, overflow: "hidden" }}>
          <AgGridReact
            ref={gridRef}
            preventDefaultOnContextMenu={true}
            onCellContextMenu={handleContextMenu}
            onBodyScroll={() => {
              if (contextMenu.open) {
                setContextMenu((prev) => ({ ...prev, open: false }));
              }
            }}
            theme={themeQuartz}
            rowData={enumOptions}
            columnDefs={colDefs}
            getRowId={(params) => params.data.id}
            rowSelection="multiple"
            defaultColDef={{
              flex: 1,
              editable: true,
              resizable: true,
            }}
            onCellValueChanged={(event) => {
              const newOptions = [...enumOptions];
              const index = newOptions.findIndex((i) => i.id === event.data.id);
              if (index > -1) {
                newOptions[index] = event.data;
                setEnumOptions(newOptions);
              }
            }}
            rowDragManaged={true}
            animateRows={true}
            onRowDragEnd={(event) => {
              const newOrder: EnumOptionItem[] = [];
              event.api.forEachNode((node) => {
                if (node.data)
                  newOrder.push({
                    ...node.data,
                    order: (node.rowIndex || 0) + 1,
                  });
              });
              setEnumOptions(newOrder);
            }}
            stopEditingWhenCellsLoseFocus={true}
          />
        </div>
      </div>
    );
  };

  const getContainerStyle = () => ({
    height: "100%",
    background: token.colorBgContainer,
    border: `2px solid ${
      saveStatus === "success"
        ? token.colorSuccess
        : isEditing
          ? token.colorPrimary
          : "transparent"
    }`,
    transition: "all 0.3s ease",
    boxShadow:
      saveStatus === "success"
        ? `0 0 8px ${token.colorSuccessBg}`
        : isEditing
          ? `0 0 8px ${token.colorPrimaryBg}`
          : "none",
  });

  if (!isEditing) {
    return (
      <Flex vertical style={getContainerStyle()}>
        {renderHeader()}
        <div style={{ flex: 1, overflow: "hidden" }}>
          {renderReadOnlyMeta()}
        </div>
      </Flex>
    );
  }

  return (
    <Flex vertical style={getContainerStyle()}>
      {renderHeader()}
      <div style={{ flex: 1, overflow: "hidden" }}>
        <Splitter orientation="vertical">
          <Splitter.Panel defaultSize="40%" min="30%" max="80%">
            {renderEditForm()}
          </Splitter.Panel>
          <Splitter.Panel>{renderValueDomain()}</Splitter.Panel>
        </Splitter>
      </div>
    </Flex>
  );
};

export default AttributeWorkspace;

'use client';

import React, { useState, useEffect, useMemo, useRef } from 'react';
import {
  Modal,
  Switch,
  Checkbox,
  Tag,
  Tooltip,
  Typography,
  Space,
  Skeleton,
  Result,
  Spin,
  Button,
  theme,
  App,
} from 'antd';
import LinearProgress from '@mui/material/LinearProgress';
import { ProTable } from '@ant-design/pro-components';
import type { ProColumns } from '@ant-design/pro-components';
import {
  DeleteOutlined,
  ExclamationCircleOutlined,
  CheckCircleOutlined,
  WarningOutlined,
} from '@ant-design/icons';
import {
  metaCategoryApi,
  type MetaCategoryBatchDeleteResponseDto,
} from '@/services/metaCategory';

const { Text } = Typography;

// ─── Types ───────────────────────────────────────────────────────

type DeletePhase = 'idle' | 'dryrun' | 'impact' | 'executing' | 'result';

export interface DeleteTargetNode {
  key: React.Key;
  name?: string;
  code?: string;
  level?: number;
  status?: string;
}

export interface BatchDeleteModalProps {
  open: boolean;
  nodes: DeleteTargetNode[];
  onClose: () => void;
  onDeleted: (deletedIds: string[]) => void;
}

// ─── Constants ───────────────────────────────────────────────────

const CATEGORY_HAS_CHILDREN = 'CATEGORY_HAS_CHILDREN';
const CATEGORY_NOT_FOUND = 'CATEGORY_NOT_FOUND';

// ─── Detail list item ───────────────────────────────────────────

interface DetailItem {
  id: string;
  name: string;
  code: string;
  level?: number;
  isLocal: boolean;
  dryRunSuccess: boolean;
  errorCode: string | null;
  message: string | null;
  wouldDeleteCount: number;
}

// ─── Component ──────────────────────────────────────────────────

const BatchDeleteModal: React.FC<BatchDeleteModalProps> = ({
  open,
  nodes,
  onClose,
  onDeleted,
}) => {
  const { token } = theme.useToken();
  const { message: messageApi } = App.useApp();

  const [phase, setPhase] = useState<DeletePhase>('idle');
  const [dryRunResponse, setDryRunResponse] = useState<MetaCategoryBatchDeleteResponseDto | null>(null);
  const [executeResponse, setExecuteResponse] = useState<MetaCategoryBatchDeleteResponseDto | null>(null);
  const [cascadeEnabled, setCascadeEnabled] = useState(false);
  const [cascadeConfirmed, setCascadeConfirmed] = useState(false);
  const [atomicEnabled, setAtomicEnabled] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [rechecking, setRechecking] = useState(false);
  const [cascadeHintCount, setCascadeHintCount] = useState(0);
  const recheckSeq = useRef(0);

  // ─── Separate local / remote nodes ────────────────────────────

  const { localNodes, remoteIds, nodeMap } = useMemo(() => {
    const local: DeleteTargetNode[] = [];
    const ids: string[] = [];
    const map = new Map<string, DeleteTargetNode>();

    nodes.forEach((n) => {
      const id = String(n.key);
      map.set(id, n);
      if (id.startsWith('local_')) {
        local.push(n);
      } else {
        ids.push(id);
      }
    });

    return { localNodes: local, remoteIds: ids, nodeMap: map };
  }, [nodes]);

  // ─── Reset / auto-trigger dryRun ──────────────────────────────

  useEffect(() => {
    if (!open) {
      setPhase('idle');
      setDryRunResponse(null);
      setExecuteResponse(null);
      setCascadeEnabled(false);
      setCascadeConfirmed(false);
      setAtomicEnabled(true);
      setError(null);
      setRechecking(false);
      setCascadeHintCount(0);
      recheckSeq.current = 0;
      return;
    }

    if (nodes.length === 0) return;

    // All local → skip dryRun
    if (remoteIds.length === 0) {
      setPhase('impact');
      return;
    }

    setPhase('dryrun');
    metaCategoryApi
      .batchDeleteCategories({
        ids: remoteIds,
        cascade: false,
        confirm: false,
        atomic: true,
        dryRun: true,
        operator: 'admin',
      })
      .then((response) => {
        setDryRunResponse(response);
        setPhase('impact');
      })
      .catch((err) => {
        setError(err?.message || '预检失败');
        setPhase('impact');
      });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [open]);

  // ─── Derived impact data ──────────────────────────────────────

  const { detailItems, hasCascadeRequired, cascadeRequiredCount } = useMemo(() => {
    const items: DetailItem[] = [];
    let cascadeCount = 0;

    localNodes.forEach((n) => {
      items.push({
        id: String(n.key),
        name: n.name || '未命名',
        code: n.code || '-',
        level: n.level,
        isLocal: true,
        dryRunSuccess: true,
        errorCode: null,
        message: null,
        wouldDeleteCount: 1,
      });
    });

    dryRunResponse?.results.forEach((result) => {
      const node = nodeMap.get(result.id);
      items.push({
        id: result.id,
        name: node?.name || result.id,
        code: node?.code || '-',
        level: node?.level,
        isLocal: false,
        dryRunSuccess: result.success,
        errorCode: result.code || null,
        message: result.message || null,
        wouldDeleteCount: result.wouldDeleteCount ?? (result.success ? 1 : 0),
      });
      if (result.code === CATEGORY_HAS_CHILDREN) cascadeCount++;
    });

    return {
      detailItems: items,
      hasCascadeRequired: cascadeCount > 0,
      cascadeRequiredCount: cascadeCount,
    };
  }, [localNodes, dryRunResponse, nodeMap]);

  const totalWouldDelete =
    dryRunResponse?.totalWouldDeleteCount ??
    detailItems.reduce((sum, i) => sum + i.wouldDeleteCount, 0);

  // anomalies only (exclude cascade-needed items)
  const anomalyCount = Math.max(
    0,
    (dryRunResponse?.failureCount ?? 0) - cascadeRequiredCount,
  );

  useEffect(() => {
    if (cascadeRequiredCount > 0) {
      setCascadeHintCount(cascadeRequiredCount);
    }
  }, [cascadeRequiredCount]);

  // ─── Cascade toggle → re-dryRun ──────────────────────────────

  const rerunDryRun = (options: { cascade: boolean; atomic: boolean }) => {
    if (remoteIds.length === 0) return;

    const seq = ++recheckSeq.current;
    setRechecking(true);

    metaCategoryApi
      .batchDeleteCategories({
        ids: remoteIds,
        cascade: options.cascade,
        confirm: options.cascade,
        atomic: options.atomic,
        dryRun: true,
        operator: 'admin',
      })
      .then((response) => {
        if (recheckSeq.current !== seq) return;
        setDryRunResponse(response);
      })
      .catch((err) => {
        if (recheckSeq.current !== seq) return;
        messageApi.error(err?.message || '重新评估失败');
      })
      .finally(() => {
        if (recheckSeq.current === seq) setRechecking(false);
      });
  };

  const handleCascadeToggle = (checked: boolean) => {
    setCascadeEnabled(checked);
    setCascadeConfirmed(false);
    rerunDryRun({ cascade: checked, atomic: atomicEnabled });
  };

  const handleAtomicToggle = (checked: boolean) => {
    setAtomicEnabled(checked);
    rerunDryRun({ cascade: cascadeEnabled, atomic: checked });
  };

  // ─── Execute delete ───────────────────────────────────────────

  const handleExecute = async () => {
    setPhase('executing');
    setError(null);

    try {
      if (remoteIds.length === 0) {
        // Only local nodes
        setExecuteResponse({
          total: localNodes.length,
          successCount: localNodes.length,
          failureCount: 0,
          deletedCount: localNodes.length,
          totalWouldDeleteCount: localNodes.length,
          atomic: false,
          dryRun: false,
          results: localNodes.map((n) => ({
            id: String(n.key),
            success: true,
            deletedCount: 1,
          })),
        });
      } else {
        const response = await metaCategoryApi.batchDeleteCategories({
          ids: remoteIds,
          cascade: cascadeEnabled,
          confirm: cascadeEnabled && cascadeConfirmed,
          atomic: atomicEnabled,
          dryRun: false,
          operator: 'admin',
        });
        setExecuteResponse(response);
      }
      setPhase('result');
    } catch (err: any) {
      setError(err?.message || '删除执行失败');
      setPhase('result');
    }
  };

  // ─── Finish & report ──────────────────────────────────────────

  const handleFinish = () => {
    const deletedIds: string[] = [];
    localNodes.forEach((n) => deletedIds.push(String(n.key)));
    executeResponse?.results.forEach((r) => {
      if (r.success) deletedIds.push(r.id);
    });
    if (deletedIds.length > 0) onDeleted(deletedIds);
    onClose();
  };

  // ─── Derived flags ────────────────────────────────────────────

  const cascadeDisplayCount = cascadeRequiredCount || cascadeHintCount;

  const cascadeDescription = cascadeDisplayCount > 0
    ? `${cascadeDisplayCount} 个分类包含子节点，开启后将同步删除所有子分类`
    : '当前选择未检测到必须级联删除的子节点';

  const canExecute =
    phase === 'impact' &&
    !error &&
    !rechecking &&
    (cascadeDisplayCount === 0 || cascadeEnabled) &&
    (!cascadeEnabled || cascadeConfirmed);

  const executeDisabledReason = !error && !rechecking && cascadeDisplayCount > 0 && !cascadeEnabled
    ? '存在需级联删除的对象，请先开启级联删除'
    : !error && !rechecking && cascadeEnabled && !cascadeConfirmed
      ? '请先确认已知晓将同步删除所有子分类'
      : undefined;

  const isSingleDelete = nodes.length === 1;
  const modalTitle = isSingleDelete
    ? '删除分类'
    : `批量删除分类（${nodes.length} 项）`;

  const renderSummaryBar = (
    items: Array<{
      key: string;
      label: string;
      value: React.ReactNode;
      icon: React.ReactNode;
      valueColor?: string;
    }>,
  ) => (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        gap: 16,
        padding: '10px 14px',
        borderRadius: token.borderRadiusLG,
        border: `1px solid ${token.colorBorderSecondary}`,
        background: token.colorFillQuaternary,
        flexWrap: 'wrap',
      }}
    >
      <Space size={20} wrap split={<span style={{ color: token.colorBorder }}>|</span>}>
        {items.map((item) => (
          <Space key={item.key} size={8} align="center">
            {item.icon}
            <Text type="secondary">{item.label}</Text>
            <Text strong style={{ fontSize: 16, color: item.valueColor || token.colorText }}>
              {item.value}
            </Text>
          </Space>
        ))}
      </Space>
    </div>
  );

  // ─── Column definitions ───────────────────────────────────────

  const impactColumns: ProColumns<DetailItem>[] = [
    {
      title: '分类编码',
      dataIndex: 'code',
      key: 'code',
      width: 150,
      ellipsis: true,
    },
    {
      title: '分类名称',
      dataIndex: 'name',
      key: 'name',
      width: 180,
      ellipsis: true,
    },
    {
      title: '状态',
      key: 'status',
      width: 120,
      render: (_, item) => {
        if (item.dryRunSuccess) return <Tag color="success">待删除</Tag>;
        if (item.errorCode === CATEGORY_HAS_CHILDREN)
          return <Tag color="warning">需级联</Tag>;
        if (item.errorCode === CATEGORY_NOT_FOUND)
          return <Tag color="default">已不存在</Tag>;
        return <Tag color="error">异常</Tag>;
      },
    },
    {
      title: '预计影响',
      key: 'wouldDeleteCount',
      width: 100,
      render: (_, item) =>
        item.wouldDeleteCount > 0 ? item.wouldDeleteCount : '-',
    },
  ];

  const resultColumns: ProColumns<DetailItem>[] = [
    {
      title: '分类编码',
      dataIndex: 'code',
      key: 'code',
      width: 140,
      ellipsis: true,
    },
    {
      title: '分类名称',
      dataIndex: 'name',
      key: 'name',
      width: 160,
      ellipsis: true,
    },
    {
      title: '状态',
      key: 'status',
      width: 100,
      render: (_, item) => {
        if (item.isLocal) return <Tag color="success">已删除</Tag>;
        const r = executeResponse?.results.find((x) => x.id === item.id);
        if (!r) return <Tag color="default">未处理</Tag>;
        if (r.success) return <Tag color="success">已删除</Tag>;
        if (r.code === CATEGORY_HAS_CHILDREN)
          return <Tag color="warning">需级联</Tag>;
        if (r.code === CATEGORY_NOT_FOUND)
          return <Tag color="default">已不存在</Tag>;
        return <Tag color="error">失败</Tag>;
      },
    },
    {
      title: '删除数',
      key: 'deletedCount',
      width: 80,
      render: (_, item) => {
        if (item.isLocal) return 1;
        const r = executeResponse?.results.find((x) => x.id === item.id);
        return r?.deletedCount ?? '-';
      },
    },
    {
      title: '原因',
      key: 'message',
      ellipsis: true,
      render: (_, item) => {
        if (item.isLocal) return '-';
        const r = executeResponse?.results.find((x) => x.id === item.id);
        if (!r || r.success) return '-';
        return (
          <Text type="danger" ellipsis={{ tooltip: true }}>
            {r.message || r.code || '未知错误'}
          </Text>
        );
      },
    },
  ];

  // ─── Phase renderers ──────────────────────────────────────────

  const renderDryRunPhase = () => (
    <div style={{ minHeight: 520, padding: '28px 0 12px' }}>
      <Space orientation="vertical" size={16} align="center">
        <Skeleton active title={{ width: 220 }} paragraph={{ rows: 8, width: ['100%', '100%', '92%', '100%', '94%', '100%', '88%', '96%'] }} />
        <Text type="secondary">正在评估删除影响...</Text>
      </Space>
    </div>
  );

  const renderImpactPhase = () => {
    if (error) {
      return <Result status="error" title="预检失败" subTitle={error} />;
    }

    return (
      <ProTable<DetailItem>
          rowKey="id"
          search={false}
          options={false}
          pagination={
            detailItems.length > 10
              ? { pageSize: 10, size: 'small' }
              : false
          }
          scroll={detailItems.length > 6 ? { y: 240 } : undefined}
          cardBordered={false}
          columns={impactColumns}
          dataSource={detailItems}
          headerTitle={<Text strong>删除影响预检</Text>}
          tableAlertRender={false}
          tableAlertOptionRender={false}
          tableExtraRender={() => (
            <Space orientation="vertical" size={12} style={{ width: '100%' }}>
              {renderSummaryBar([
                {
                  key: 'pending',
                  label: '待删项',
                  value: nodes.length,
                  icon: <DeleteOutlined style={{ color: token.colorPrimary }} />,
                  valueColor: token.colorText,
                },
                {
                  key: 'impact',
                  label: '预计总删除',
                  value: totalWouldDelete,
                  icon: (
                    <ExclamationCircleOutlined
                      style={{ color: totalWouldDelete > nodes.length ? '#d48806' : token.colorTextTertiary }}
                    />
                  ),
                  valueColor: totalWouldDelete > nodes.length ? '#d48806' : token.colorText,
                },
                {
                  key: 'anomaly',
                  label: '异常项',
                  value: anomalyCount,
                  icon: (
                    <WarningOutlined
                      style={{ color: anomalyCount > 0 ? token.colorError : token.colorTextTertiary }}
                    />
                  ),
                  valueColor: anomalyCount > 0 ? token.colorError : token.colorText,
                },
              ])}

              <div
                style={{
                  padding: '12px 14px',
                  borderRadius: token.borderRadiusLG,
                  border: `1px solid ${cascadeEnabled ? token.colorErrorBorder : token.colorBorderSecondary}`,
                  background: cascadeEnabled ? token.colorErrorBg : token.colorBgContainer,
                }}
              >
                <Space orientation="vertical" size={12} style={{ width: '100%' }}>
                  <Text type="secondary" style={{ fontSize: 13 }}>
                    删除策略与高级配置
                  </Text>

                  <div
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'space-between',
                      gap: 16,
                    }}
                  >
                    <Space size={10} align="start">
                      <ExclamationCircleOutlined
                        style={{
                          marginTop: 2,
                          color: cascadeEnabled
                            ? token.colorError
                            : cascadeDisplayCount > 0
                              ? '#d48806'
                              : token.colorTextTertiary,
                        }}
                      />
                      <div>
                        <Text strong type={cascadeEnabled ? 'danger' : undefined}>
                          级联删除
                        </Text>
                        <div>
                          <Text
                            type={cascadeEnabled || cascadeDisplayCount > 0 ? undefined : 'secondary'}
                            style={{
                              fontSize: 12,
                              color: cascadeEnabled ? token.colorError : undefined,
                            }}
                          >
                            {cascadeDescription}
                          </Text>
                        </div>
                      </div>
                    </Space>
                    <Switch checked={cascadeEnabled} onChange={handleCascadeToggle} />
                  </div>

                  <div
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'space-between',
                      gap: 16,
                    }}
                  >
                    <Space size={10} align="start">
                      <WarningOutlined
                        style={{
                          marginTop: 2,
                          color: atomicEnabled ? token.colorPrimary : token.colorTextTertiary,
                        }}
                      />
                      <div>
                        <Text strong>失败时回滚整批操作</Text>
                        <div>
                          <Text type="secondary" style={{ fontSize: 12 }}>
                            开启后，若其中一项删除失败，所有已删项将恢复。
                          </Text>
                        </div>
                      </div>
                    </Space>
                    <Switch checked={atomicEnabled} onChange={handleAtomicToggle} />
                  </div>
                </Space>
              </div>
            </Space>
          )}
        />
    );
  };

  const renderExecutingPhase = () => (
    <div style={{ padding: '60px 0', textAlign: 'center' }}>
      <Spin size="large" />
      <div style={{ marginTop: 16 }}>
        <Text type="secondary">正在执行删除操作...</Text>
      </div>
    </div>
  );

  const renderResultPhase = () => {
    if (error && !executeResponse) {
      return <Result status="error" title="删除执行失败" subTitle={error} />;
    }

    const successCount =
      (executeResponse?.successCount ?? 0) + localNodes.length;
    const failCount = executeResponse?.failureCount ?? 0;
    const totalDeleted =
      (executeResponse?.deletedCount ?? 0) + localNodes.length;
    const isAllSuccess = failCount === 0;
    const isPartialSuccess = successCount > 0 && failCount > 0;
    const failedResultIds = new Set(
      (executeResponse?.results || [])
        .filter((item) => !item.success)
        .map((item) => item.id),
    );
    const failedDetailItems = detailItems.filter((item) => failedResultIds.has(item.id));

    return (
      <ProTable<DetailItem>
        rowKey="id"
        search={false}
        options={false}
        pagination={
          failedDetailItems.length > 8
            ? { pageSize: 8, size: 'small' }
            : false
        }
        scroll={failedDetailItems.length > 6 ? { y: 200 } : undefined}
        cardBordered={false}
        columns={resultColumns}
        dataSource={failCount > 0 ? failedDetailItems : []}
        headerTitle={<Text strong>删除执行结果</Text>}
        tableAlertRender={false}
        tableAlertOptionRender={false}
        tableExtraRender={() => (
          <Space orientation="vertical" size={12} style={{ width: '100%' }}>
            {renderSummaryBar([
              {
                key: 'success',
                label: '成功',
                value: successCount,
                icon: <CheckCircleOutlined style={{ color: '#52c41a' }} />,
                valueColor: '#52c41a',
              },
              {
                key: 'failed',
                label: '失败',
                value: failCount,
                icon: (
                  <ExclamationCircleOutlined
                    style={{ color: failCount > 0 ? token.colorError : token.colorTextTertiary }}
                  />
                ),
                valueColor: failCount > 0 ? token.colorError : token.colorText,
              },
              {
                key: 'deleted',
                label: '总计删除',
                value: totalDeleted,
                icon: <DeleteOutlined style={{ color: token.colorPrimary }} />,
                valueColor: token.colorText,
              },
            ])}

            <Result
              status={
                isAllSuccess ? 'success' : isPartialSuccess ? 'warning' : 'error'
              }
              icon={
                isAllSuccess ? (
                  <CheckCircleOutlined style={{ color: '#52c41a' }} />
                ) : (
                  <ExclamationCircleOutlined style={{ color: '#faad14' }} />
                )
              }
              title={
                isAllSuccess
                  ? '删除完成'
                  : isPartialSuccess
                    ? '部分删除成功'
                    : '删除失败'
              }
              subTitle={
                isAllSuccess
                  ? '所有目标项均已完成删除处理。'
                  : isPartialSuccess
                    ? '部分目标项删除成功，失败项可在下方查看详细原因。'
                    : '本次删除未成功完成，请根据失败原因调整后重试。'
              }
              style={{ padding: '8px 0 0' }}
            />
          </Space>
        )}
      />
    );
  };

  // ─── Footer ───────────────────────────────────────────────────

  const footerButtons = () => {
    if (phase === 'dryrun' || phase === 'executing') {
      return (
        <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
          <Button key="cancel" disabled>
            取消
          </Button>
        </div>
      );
    }

    if (phase === 'impact') {
      return (
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            gap: 16,
            width: '100%',
          }}
        >
          <div style={{ minHeight: 22, display: 'flex', alignItems: 'center' }}>
            {cascadeEnabled ? (
              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <Checkbox
                  checked={cascadeConfirmed}
                  onChange={(e) => setCascadeConfirmed(e.target.checked)}
                />
                <Text type="danger">我已知晓将同步删除所有子分类</Text>
              </div>
            ) : null}
          </div>

          <Space>
            <Button key="cancel" onClick={onClose}>
              取消
            </Button>
            <Tooltip title={!canExecute ? executeDisabledReason : undefined}>
              <span>
                <Button
                  key="execute"
                  type="primary"
                  danger
                  disabled={!canExecute}
                  onClick={handleExecute}
                >
                  确认删除
                </Button>
              </span>
            </Tooltip>
          </Space>
        </div>
      );
    }

    if (phase === 'result') {
      return (
        <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
          <Button key="close" type="primary" onClick={handleFinish}>
            完成
          </Button>
        </div>
      );
    }

    return undefined;
  };

  // ─── Render ───────────────────────────────────────────────────

  return (
    <Modal
      title={
        <Space>
          <span>{modalTitle}</span>
        </Space>
      }
      open={open}
      width={700}
      onCancel={phase === 'result' ? handleFinish : onClose}
      footer={footerButtons()}
      maskClosable={false}
      keyboard={false}
      destroyOnHidden
    >
      <div style={{ position: 'relative', minHeight: 520, paddingTop: 8 }}>
        {(phase === 'dryrun' || rechecking) && (
          <div
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              zIndex: 3,
              pointerEvents: 'none',
            }}
          >
            <LinearProgress
              sx={{
                height: 3,
                borderRadius: 999,
                backgroundColor: token.colorFillSecondary,
                '& .MuiLinearProgress-bar': {
                  backgroundColor: token.colorPrimary,
                },
              }}
            />
          </div>
        )}

        {phase === 'dryrun' && renderDryRunPhase()}
        {phase === 'impact' && renderImpactPhase()}
        {phase === 'executing' && renderExecutingPhase()}
        {phase === 'result' && renderResultPhase()}
      </div>
    </Modal>
  );
};

export default BatchDeleteModal;

import React, { useEffect, useMemo, useState } from 'react';
import { App } from 'antd';
import type { DataNode } from 'antd/es/tree';
import DraggableModal from '@/components/DraggableModal';
import {
  metaCategoryApi,
  type MetaCategoryBatchTransferResponseDto,
  type MetaCategoryBatchTransferTopologyResponseDto,
} from '@/services/metaCategory';
import type { MetaCategoryTreeNodeDto } from '@/models/metaCategory';
import TransferWorkspace, { type TransferTreeNode } from '../batch-transfer/components/TransferWorkspace';

interface BatchTransferModalProps {
  open: boolean;
  actionType: 'copy' | 'move' | null;
  checkedKeys: React.Key[];
  fullTreeData: DataNode[];
  onCancel: () => void;
  onSuccess?: (response: MetaCategoryBatchTransferResponseDto | MetaCategoryBatchTransferTopologyResponseDto) => void;
  defaultBusinessDomain?: string;
}

const formatNodeTitle = (code?: string | null, name?: string | null, fallback?: string) => {
  if (code && name) {
    return `${code} - ${name}`;
  }
  return fallback || name || code || '-';
};

const getNodeDataRef = (node: DataNode) => {
  return (node as any)?.dataRef as
    | {
        id?: string;
        businessDomain?: string;
        code?: string;
        name?: string;
        hasChildren?: boolean;
        leaf?: boolean;
        status?: string;
        level?: number;
        parentId?: string | null;
        path?: string | null;
      }
    | undefined;
};

const toFallbackTransferNode = (node: DataNode): TransferTreeNode => {
  const dataRef = getNodeDataRef(node);
  const rawTitle = typeof node.title === 'string' ? node.title : String(node.title || node.key);
  return {
    key: String(dataRef?.id || node.key),
    title: formatNodeTitle(dataRef?.code, dataRef?.name, rawTitle),
    isLeaf: Boolean(node.isLeaf),
    isContextOnly: false,
    dataRef: dataRef
      ? {
          id: String(dataRef.id || node.key),
          businessDomain: dataRef.businessDomain || '',
          code: dataRef.code || '',
          name: dataRef.name || rawTitle,
          hasChildren: Boolean(dataRef.hasChildren ?? !node.isLeaf),
          leaf: dataRef.leaf ?? Boolean(node.isLeaf),
          status: dataRef.status,
          level: dataRef.level,
          parentId: dataRef.parentId,
          path: dataRef.path,
        }
      : undefined,
    children: node.children ? node.children.map(toFallbackTransferNode) : undefined,
  };
};

const mapSubtreeNodeToTransferNode = (node: MetaCategoryTreeNodeDto): TransferTreeNode => ({
  key: node.id,
  title: formatNodeTitle(node.code, node.name, node.name),
  isLeaf: node.leaf ?? !node.hasChildren,
  isContextOnly: false,
  dataRef: {
    id: node.id,
    businessDomain: node.businessDomain,
    code: node.code,
    name: node.name,
    hasChildren: node.hasChildren,
    leaf: node.leaf,
    status: node.status,
    level: node.level,
    parentId: node.parentId,
    path: node.path,
  },
  children: node.children?.map(mapSubtreeNodeToTransferNode),
});

const collectSelectedRootNodes = (
  nodes: DataNode[],
  checkedKeySet: Set<string>,
  ancestorSelected = false,
): DataNode[] => {
  const result: DataNode[] = [];

  nodes.forEach((node) => {
    const nodeKey = String(node.key);
    const isSelected = checkedKeySet.has(nodeKey);

    if (isSelected && !ancestorSelected) {
      result.push(node);
      return;
    }

    if (node.children?.length) {
      result.push(...collectSelectedRootNodes(node.children, checkedKeySet, ancestorSelected || isSelected));
    }
  });

  return result;
};

const buildContextTree = (
  nodes: DataNode[],
  checkedKeySet: Set<string>,
  subtreeMap: Map<string, TransferTreeNode>,
): TransferTreeNode[] => {
  const result: TransferTreeNode[] = [];

  nodes.forEach((node) => {
    const nodeKey = String(node.key);
    const isSelected = checkedKeySet.has(nodeKey);

    if (isSelected) {
      result.push(subtreeMap.get(nodeKey) || toFallbackTransferNode(node));
      return;
    }

    if (node.children?.length) {
      const childrenContext = buildContextTree(node.children, checkedKeySet, subtreeMap);
      if (childrenContext.length > 0) {
        const dataRef = getNodeDataRef(node);
        const rawTitle = typeof node.title === 'string' ? node.title : String(node.title || node.key);
        result.push({
          key: String(dataRef?.id || node.key),
          title: formatNodeTitle(dataRef?.code, dataRef?.name, rawTitle),
          isLeaf: Boolean(node.isLeaf),
          isContextOnly: true,
          dataRef: dataRef
            ? {
                id: String(dataRef.id || node.key),
                businessDomain: dataRef.businessDomain || '',
                code: dataRef.code || '',
                name: dataRef.name || rawTitle,
                hasChildren: Boolean(dataRef.hasChildren ?? !node.isLeaf),
                leaf: dataRef.leaf ?? Boolean(node.isLeaf),
                status: dataRef.status,
                level: dataRef.level,
                parentId: dataRef.parentId,
                path: dataRef.path,
              }
            : undefined,
          children: childrenContext,
        });
      }
    }
  });

  return result;
};

const normalizeSubtreeRootNode = (data: MetaCategoryTreeNodeDto | MetaCategoryTreeNodeDto[] | null | undefined) => {
  if (Array.isArray(data)) {
    return data[0];
  }
  return data || undefined;
};

export default function BatchTransferModal({
  open,
  actionType,
  checkedKeys,
  fullTreeData,
  onCancel,
  onSuccess,
  defaultBusinessDomain,
}: BatchTransferModalProps) {
  const { message } = App.useApp();
  const checkedKeySet = useMemo(
    () => new Set(checkedKeys.map((key) => String(key))),
    [checkedKeys],
  );
  const selectedRootNodes = useMemo(
    () => collectSelectedRootNodes(fullTreeData, checkedKeySet),
    [fullTreeData, checkedKeySet],
  );
  const businessDomain = useMemo(() => {
    return (
      selectedRootNodes
        .map((node) => getNodeDataRef(node)?.businessDomain)
        .find((value): value is string => Boolean(value)) || defaultBusinessDomain || ''
    );
  }, [defaultBusinessDomain, selectedRootNodes]);
  const [sourceNodesData, setSourceNodesData] = useState<TransferTreeNode[]>([]);
  const [sourceLoading, setSourceLoading] = useState(false);

  useEffect(() => {
    if (!open) {
      setSourceNodesData([]);
      setSourceLoading(false);
      return;
    }

    if (!selectedRootNodes.length) {
      setSourceNodesData([]);
      return;
    }

    let cancelled = false;

    const loadSelectedSubtrees = async () => {
      setSourceLoading(true);
      try {
        const responses = await Promise.all(
          selectedRootNodes.map((node) =>
            metaCategoryApi.getCategorySubtree({
              parentId: String(node.key),
              includeRoot: true,
              maxDepth: -1,
              status: 'ALL',
              mode: 'TREE',
              nodeLimit: 2000,
            }),
          ),
        );

        if (cancelled) {
          return;
        }

        const subtreeMap = new Map<string, TransferTreeNode>();
        responses.forEach((response, index) => {
          const sourceNode = selectedRootNodes[index];
          const rootNode = normalizeSubtreeRootNode(response?.data);
          subtreeMap.set(
            String(sourceNode.key),
            rootNode ? mapSubtreeNodeToTransferNode(rootNode) : toFallbackTransferNode(sourceNode),
          );
        });

        setSourceNodesData(buildContextTree(fullTreeData, checkedKeySet, subtreeMap));
      } catch (error: any) {
        if (!cancelled) {
          message.error(error?.message || error?.error || '加载源分类子树失败');
          setSourceNodesData(buildContextTree(fullTreeData, checkedKeySet, new Map()));
        }
      } finally {
        if (!cancelled) {
          setSourceLoading(false);
        }
      }
    };

    void loadSelectedSubtrees();

    return () => {
      cancelled = true;
    };
  }, [open, fullTreeData, checkedKeySet, selectedRootNodes, message]);

  return (
    <DraggableModal
      open={open}
      title={actionType === 'copy' ? '分类批量复制' : '分类批量移动'}
      onCancel={onCancel}
      footer={null}
      width="80%"
      destroyOnHidden
      styles={{ 
        body: {
          padding: 0,
          height: 'min(80vh, calc(100vh - 160px))',
          minHeight: 0,
          overflow: 'hidden',
          display: 'flex',
          flexDirection: 'column',
        },
      }}
    >
      <div style={{ flex: 1, minHeight: 0, overflow: 'hidden' }}>
        <TransferWorkspace 
          businessDomain={businessDomain}
          initialAction={actionType || undefined}
          sourceNodesData={sourceNodesData}
          externalLoading={sourceLoading}
          onCancelWorkspace={onCancel}
          onComplete={(response) => {
            if (response) {
              onSuccess?.(response);
            }
            onCancel();
          }}
        />
      </div>
    </DraggableModal>
  );
}

import React, { useEffect, useRef, useState } from 'react';
import { App, Form, Input, Select, Button, Row, Col, Space, Card, theme } from 'antd';
import dynamic from 'next/dynamic';
import DraggableModal from '@/components/DraggableModal';
import { metaCategoryApi } from '@/services/metaCategory';
import { useDictionary } from '@/contexts/DictionaryContext';
import {
  CATEGORY_BUSINESS_DOMAIN_DICT_CODE,
  getCategoryBusinessDomainLabel,
} from '@/features/category/businessDomains';

const { Option } = Select;
const ReactQuill = dynamic(() => import('react-quill-new'), { ssr: false });
const EMPTY_QUILL_DELTA_JSON = '{"ops":[{"insert":"\\n"}]}'

const quillModules = {
  toolbar: [
    [{ header: [1, 2, 3, false] }],
    [{ font: [] }],
    ['bold', 'italic', 'underline', 'strike'],
    [{ color: [] }, { background: [] }],
    [{ list: 'ordered' }, { list: 'bullet' }],
    [{ align: [] }],
    ['blockquote', 'code-block'],
    ['link', 'image'],
    ['clean'],
  ],
};

const quillFormats = [
  'header',
  'font',
  'bold',
  'italic',
  'underline',
  'strike',
  'color',
  'background',
  'list',
  'align',
  'blockquote',
  'code-block',
  'link',
  'image',
];

export interface CreateCategoryModalProps {
  open: boolean;
  onCancel: () => void;
  onOk: (values: any) => Promise<void> | void;
  parentNode?: {
    id?: string | null;
    code?: string;
    name?: string;
    level?: number;
    path?: string;
    businessDomain?: string;
    rootCode?: string;
    rootName?: string;
  } | null;
  submitLoading?: boolean;
  defaultBusinessDomain?: string;
}

const CreateCategoryModal: React.FC<CreateCategoryModalProps> = ({
  open,
  onCancel,
  onOk,
  parentNode,
  submitLoading,
  defaultBusinessDomain,
}) => {
  const [form] = Form.useForm();
  const { token } = theme.useToken();
  const { modal } = App.useApp();
  const { ensureScene, getEntries } = useDictionary();
  const previewTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const previewRequestIdRef = useRef(0);
  const suggestedCodeRef = useRef('');
  const [previewLoading, setPreviewLoading] = useState(false);
  const [allowManualOverride, setAllowManualOverride] = useState(false);
  const [previewWarnings, setPreviewWarnings] = useState<string[]>([]);
  const [codeManuallyEdited, setCodeManuallyEdited] = useState(false);

  useEffect(() => {
    void ensureScene('category-admin');
  }, [ensureScene]);

  const watchedBusinessDomain = Form.useWatch('businessDomain', form) as string | undefined;
  const watchedParentId = Form.useWatch('parentId', form) as string | undefined;
  const watchedCode = Form.useWatch('code', form) as string | undefined;

  const businessDomainEntries = getEntries(CATEGORY_BUSINESS_DOMAIN_DICT_CODE);
  const statusEntries = getEntries('META_CATEGORY_STATUS').filter((entry) =>
    ['CREATED', 'EFFECTIVE', 'INVALID'].includes(String(entry.value).toUpperCase()),
  );
  const activeBusinessDomain = parentNode?.businessDomain || defaultBusinessDomain || '';
  const activeBusinessDomainDisplay = activeBusinessDomain
    ? `${getCategoryBusinessDomainLabel(businessDomainEntries, activeBusinessDomain, activeBusinessDomain)} (${activeBusinessDomain})`
    : '-';

  useEffect(() => {
    if (!open) return;
    suggestedCodeRef.current = '';
    form.setFieldsValue({
      code: '',
      name: '',
      businessDomain: activeBusinessDomain,
      parentId: parentNode?.id || null,
      parentDisplay: parentNode?.code || parentNode?.name
        ? `${parentNode?.code || '-'} - ${parentNode?.name || '未命名分类'}`
        : '根分类（无父级）',
      rootDisplay: (() => {
        if (!parentNode) return '当前创建为根分类';
        if (parentNode.rootCode) {
          return `${parentNode.rootCode} - ${parentNode.rootName || '未命名根分类'}`;
        }
        if (parentNode.level === 1) {
          return `${parentNode.code || '-'} - ${parentNode.name || '未命名分类'}`;
        }
        return '根分类信息加载中...';
      })(),
      status: 'CREATED',
      description: EMPTY_QUILL_DELTA_JSON,
    });
    setAllowManualOverride(false);
    setPreviewWarnings([]);
    setCodeManuallyEdited(false);
  }, [open, parentNode, form, defaultBusinessDomain]);

  useEffect(() => {
    if (!open) {
      if (previewTimerRef.current) {
        clearTimeout(previewTimerRef.current);
        previewTimerRef.current = null;
      }
      setPreviewLoading(false);
      return;
    }

    const businessDomain = String(watchedBusinessDomain || '').trim();
    if (!businessDomain) {
      return;
    }

    if (previewTimerRef.current) {
      clearTimeout(previewTimerRef.current);
    }

    previewTimerRef.current = setTimeout(async () => {
      const requestId = ++previewRequestIdRef.current;
      const currentCode = String(watchedCode || '').trim();
      const manualCode = codeManuallyEdited ? currentCode : '';
      if (codeManuallyEdited && !manualCode) {
        setCodeManuallyEdited(false);
        setPreviewWarnings([]);
        setPreviewLoading(false);
        return;
      }

      setPreviewLoading(true);
      try {
        const preview = await metaCategoryApi.previewCreateCode({
          businessDomain,
          parentId: watchedParentId || undefined,
          manualCode: codeManuallyEdited ? manualCode : undefined,
          count: 1,
        });
        if (requestId !== previewRequestIdRef.current) {
          return;
        }

        setAllowManualOverride(Boolean(preview.allowManualOverride));
        setPreviewWarnings(preview.warnings || []);

        if (!codeManuallyEdited) {
          suggestedCodeRef.current = preview.suggestedCode || '';
          form.setFieldValue('code', preview.suggestedCode || '');
        }

        if (codeManuallyEdited && !preview.allowManualOverride) {
          setCodeManuallyEdited(false);
          form.setFieldValue('code', suggestedCodeRef.current || preview.suggestedCode || '');
        }
      } catch (error: any) {
        if (requestId !== previewRequestIdRef.current) {
          return;
        }
        setPreviewWarnings([error?.message || error?.error || '分类编码预计算失败']);
        if (!codeManuallyEdited) {
          form.setFieldValue('code', '');
        }
      } finally {
        if (requestId === previewRequestIdRef.current) {
          setPreviewLoading(false);
        }
      }
    }, codeManuallyEdited ? 300 : 0);

    return () => {
      if (previewTimerRef.current) {
        clearTimeout(previewTimerRef.current);
        previewTimerRef.current = null;
      }
    };
  }, [open, watchedBusinessDomain, watchedParentId, watchedCode, codeManuallyEdited, form]);

  const handleFinish = async (values: any) => {
    const normalizedCode = String(values.code || '').trim();
    const manualOverride = codeManuallyEdited && normalizedCode.length > 0 && allowManualOverride;
    await onOk({
      ...values,
      code: manualOverride ? normalizedCode : undefined,
      generationMode: manualOverride ? 'MANUAL' : undefined,
      freezeCode: undefined,
    });
    form.resetFields();
    setAllowManualOverride(false);
    setPreviewWarnings([]);
    setCodeManuallyEdited(false);
    suggestedCodeRef.current = '';
  };

  const handleRequestClose = () => {
    if (!form.isFieldsTouched(true)) {
      form.resetFields();
      onCancel();
      return;
    }

    modal.confirm({
      title: '存在未保存内容',
      content: '当前表单内容尚未保存，确认关闭并放弃本次编辑吗？',
      okText: '放弃并关闭',
      cancelText: '继续编辑',
      okType: 'danger',
      onOk: () => {
        form.resetFields();
        setAllowManualOverride(false);
        setPreviewWarnings([]);
        setCodeManuallyEdited(false);
        suggestedCodeRef.current = '';
        onCancel();
      },
    });
  };

  const readOnlyStyle = {
    color: token.colorTextDisabled,
    backgroundColor: token.colorBgContainerDisabled,
    cursor: 'not-allowed',
  };

  return (
    <DraggableModal
      title="新增分类"
      open={open}
      width={800}
      onCancel={handleRequestClose}
      maskClosable={false}
      keyboard={false}
      footer={null}
      destroyOnHidden
    >
      <div style={{ padding: '0 0 16px 0' }}>
        <Space size="middle" style={{ marginBottom: 16 }}>
          <Button type="primary" loading={submitLoading} onClick={() => form.submit()}>保存</Button>
          <Button disabled>复制新增</Button>
        </Space>

        <Form
          form={form}
          layout="vertical"
          onFinish={handleFinish}
        >
          <Card 
            size="small" 
            variant="outlined"
            style={{ 
              borderRadius: token.borderRadiusLG,
              backgroundColor: token.colorFillAlter,
              marginBottom: 16
            }}
          >
            <Row gutter={24}>
              <Col span={12}>
                <Form.Item
                  label="分类编码"
                  name="code"
                  rules={[{ required: true, message: '请输入分类编码' }]}
                >
                  <Input
                    onChange={(event) => {
                      const nextCode = event.target.value.trim();
                      setCodeManuallyEdited(nextCode.length > 0 && nextCode !== suggestedCodeRef.current);
                    }}
                  />
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item label="分类名称" name="name" rules={[{ required: true }]}>
                  <Input placeholder="请输入分类名称" />
                </Form.Item>
              </Col>
            </Row>

            <Row gutter={24}>
              <Col span={12}>
                <Form.Item label="业务领域">
                  <Input readOnly value={activeBusinessDomainDisplay} style={readOnlyStyle} />
                </Form.Item>
                <Form.Item name="businessDomain" hidden>
                  <Input />
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item label="父级分类" name="parentDisplay">
                  <Input readOnly style={readOnlyStyle} />
                </Form.Item>
                <Form.Item name="parentId" hidden>
                  <Input />
                </Form.Item>
              </Col>
            </Row>

            <Row gutter={24}>
              <Col span={12}>
                <Form.Item label="分类状态" name="status">
                  <Select>
                    {statusEntries.length > 0
                      ? statusEntries.map((entry) => (
                          <Option key={entry.value} value={entry.value}>
                            {entry.label}
                          </Option>
                        ))
                      : (
                        <>
                          <Option value="CREATED">创建</Option>
                          <Option value="EFFECTIVE">生效</Option>
                          <Option value="INVALID">失效</Option>
                        </>
                      )}
                  </Select>
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item label="根分类" name="rootDisplay">
                  <Input readOnly style={readOnlyStyle} />
                </Form.Item>
              </Col>
            </Row>

            <Row gutter={24}>
              <Col span={24}>
                <Form.Item label="详细描述">
                  <div
                    className="category-description-editor"
                    style={{
                      border: `1px solid ${token.colorBorder}`,
                      borderRadius: token.borderRadius,
                      overflow: 'hidden',
                      background: token.colorBgContainer,
                    }}
                  >
                    <Form.Item
                      name="description"
                      noStyle
                      trigger="onChange"
                      getValueFromEvent={(_content, _delta, _source, editor) => {
                        if (!editor || typeof editor.getContents !== 'function') {
                          return EMPTY_QUILL_DELTA_JSON;
                        }
                        return JSON.stringify(editor.getContents());
                      }}
                      getValueProps={(value) => {
                        if (!value || typeof value !== 'string') {
                          return { value: undefined };
                        }
                        try {
                          return { value: JSON.parse(value) };
                        } catch {
                          return { value: undefined };
                        }
                      }}
                    >
                      <ReactQuill
                        theme="snow"
                        modules={quillModules}
                        formats={quillFormats}
