"use client";

import React, { useEffect, useState } from 'react';
import { usePathname, useRouter } from 'next/navigation';
import { useGlobalLoading } from '@/components/providers/GlobalLoadingProvider';
import { authApi, isAuthErrorResponse } from '@/services/auth';
import {
  clearPersistedAuthState,
  mapWorkspaceSessionDtoToState,
  persistPlatformAuthState,
  persistWorkspaceSessionState,
  readPersistedAuthHeaders,
  readPersistedAuthSnapshot,
} from '@/utils/authStorage';
import './login/login.css';
import './register/register.css';
import './admin-login/admin-login.css';

export default function AuthLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const router = useRouter();
  const pathname = usePathname();
  const { showLoading, hideLoading } = useGlobalLoading();
  const [checkingAccess, setCheckingAccess] = useState(true);

  useEffect(() => {
    let active = true;
    const persistedHeaders = readPersistedAuthHeaders();
    const currentSnapshot = readPersistedAuthSnapshot();
    const isPlatformAdmin = currentSnapshot.platformAuth.principalType === 'platform-admin';

    if (!persistedHeaders.platformToken || !persistedHeaders.platformTokenName) {
      setCheckingAccess(false);
      return;
    }

    const loadingId = showLoading('正在检查登录状态...');

    const allowAuthPage = () => {
      if (!active) {
        return;
      }

      hideLoading(loadingId);
      setCheckingAccess(false);
    };

    const redirectTo = (targetPath: string) => {
      if (!active) {
        return;
      }

      router.replace(targetPath);
    };

    const restoreSession = async () => {
      try {
        if (isPlatformAdmin) {
          const adminMe = await authApi.getPlatformAdminMe(persistedHeaders);

          if (!active) {
            return;
          }

          persistPlatformAuthState({
            ...currentSnapshot.platformAuth,
            user: null,
            admin: adminMe.admin,
            principalType: 'platform-admin',
          });
          redirectTo('/admin/dashboard');
          return;
        }

        const me = await authApi.getMe(persistedHeaders);

        if (!active) {
          return;
        }

        persistPlatformAuthState({
          ...currentSnapshot.platformAuth,
          user: me.user,
          admin: null,
          principalType: 'user',
        });

        const shouldCreateWorkspace = me.user.isFirstLogin || me.user.workspaceCount === 0;

        if (shouldCreateWorkspace) {
          persistWorkspaceSessionState(null);
          redirectTo('/workspace/create');
          return;
        }

        if (me.currentWorkspace) {
          persistWorkspaceSessionState(mapWorkspaceSessionDtoToState(me.currentWorkspace));
          redirectTo('/dashboard');
          return;
        }

        const targetWorkspaceId = me.defaultWorkspace?.workspaceId ?? me.workspaceOptions[0]?.workspaceId;

        if (!targetWorkspaceId) {
          persistWorkspaceSessionState(null);
          redirectTo('/workspace/create');
          return;
        }

        const restoredSession = await authApi.switchWorkspace(
          {
            workspaceId: targetWorkspaceId,
            rememberAsDefault: false,
          },
          persistedHeaders,
        );

        if (!active) {
          return;
        }

        persistWorkspaceSessionState(mapWorkspaceSessionDtoToState(restoredSession));
        redirectTo('/dashboard');
      } catch (error) {
        if (!active) {
          return;
        }

        if (isAuthErrorResponse(error)) {
          if (error.code === 'AUTH_NOT_LOGGED_IN') {
            clearPersistedAuthState();
          }

          if (isPlatformAdmin && (error.code === 'PLATFORM_ADMIN_REQUIRED' || error.code === 'ACCOUNT_NOT_ACTIVE')) {
            clearPersistedAuthState();
          }
        }

        allowAuthPage();
      }
    };

    void restoreSession();

    return () => {
      active = false;
      hideLoading(loadingId);
    };
  }, [hideLoading, pathname, router, showLoading]);

  if (checkingAccess) {
    return null;
  }

  return children;
}

'use client';

import { Form, Input, Button, Typography, Checkbox, Divider, message } from "antd";
import { useEffect, useState } from "react";
import { ArrowRightOutlined, GoogleOutlined, GithubOutlined, QuestionCircleOutlined, LeftOutlined } from "@ant-design/icons";
import Illustration from "@/assets/illustration-final.svg";
import Image from "next/image";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { authApi, isAuthErrorResponse } from '@/services/auth';
import { mapWorkspaceSessionDtoToState, persistPlatformAuthState, persistWorkspaceSessionState } from '@/utils/authStorage';
import { encryptPasswordWithPublicKey } from '@/utils/passwordEncryption';

const { Title, Text } = Typography;

interface LoginFormValuesStep1 {
  plmId: string;
}
interface LoginFormValuesStep2 extends LoginFormValuesStep1 {
  password: string;
  remember?: boolean;
}

const navigateAfterLogin = (targetPath: '/dashboard' | '/workspace/create') => {
  window.location.assign(targetPath);
};

export default function LoginPage() {
  const [stepOneForm] = Form.useForm<LoginFormValuesStep1>();
  const [stepTwoForm] = Form.useForm<LoginFormValuesStep2>();
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState<1 | 2>(1);
  const [plmIdCache, setPlmIdCache] = useState('');
  const router = useRouter();

  useEffect(() => {
    const initialIdentifier = new URLSearchParams(window.location.search)
      .get('identifier')
      ?.trim();
    if (!initialIdentifier) {
      return;
    }

    setPlmIdCache(initialIdentifier);
    stepOneForm.setFieldsValue({ plmId: initialIdentifier });
  }, [stepOneForm]);

  const handleStep1Finish = ({ plmId }: LoginFormValuesStep1) => {
    setPlmIdCache(plmId.trim());
    setStep(2);
    stepTwoForm.setFieldsValue({ remember: true });
  };

  const handleLogin = async (values: LoginFormValuesStep2) => {
    setLoading(true);

    try {
      const encryptionKey = await authApi.getPasswordEncryptionKey();
      const passwordCiphertext = await encryptPasswordWithPublicKey(
        values.password,
        encryptionKey.publicKeyBase64 || encryptionKey.publicKeyPem || '',
        encryptionKey.transformation,
      );

      const response = await authApi.loginWithPassword({
        identifier: plmIdCache,
        passwordCiphertext,
        encryptionKeyId: encryptionKey.keyId,
        remember: values.remember !== false,
      });

      const remember = response.remember;
      const loginHeaders = {
        platformToken: response.platformToken,
        platformTokenName: response.platformTokenName,
      };

      persistPlatformAuthState(
        {
          platformToken: response.platformToken,
          platformTokenName: response.platformTokenName,
          remember: response.remember,
          platformTokenExpireInSeconds: response.platformTokenExpireInSeconds,
          user: response.user,
          admin: null,
          principalType: 'user',
        },
        {
          remember,
          resetWorkspace: true,
        },
      );

      const shouldCreateWorkspace = response.user.isFirstLogin || response.user.workspaceCount === 0;
      let resolvedWorkspaceSession = response.currentWorkspace;

      if (!shouldCreateWorkspace && !resolvedWorkspaceSession) {
        const targetWorkspaceId = response.defaultWorkspace?.workspaceId ?? response.workspaceOptions[0]?.workspaceId;

        if (targetWorkspaceId) {
          try {
            resolvedWorkspaceSession = await authApi.switchWorkspace(
              {
                workspaceId: targetWorkspaceId,
                rememberAsDefault: false,
              },
              loginHeaders,
            );
          } catch (error) {
            if (isAuthErrorResponse(error)) {
              message.error(error.message || '登录成功，但默认工作区恢复失败，请稍后在工作区菜单中手动切换。');
            } else {
              message.error('登录成功，但默认工作区恢复失败，请稍后在工作区菜单中手动切换。');
            }
          }
        }
      }

      persistWorkspaceSessionState(
        mapWorkspaceSessionDtoToState(resolvedWorkspaceSession),
        {
          remember,
        },
      );

      if (shouldCreateWorkspace) {
        message.success(response.user.isFirstLogin ? '登录成功，请先创建第一个工作区。' : '登录成功，当前没有可用工作区，请创建新的工作区。');
        navigateAfterLogin('/workspace/create');
        return;
      }

      if (resolvedWorkspaceSession) {
        message.success('登录成功。');
      } else {
        message.warning('登录成功，但工作区会话尚未恢复，请在工作区菜单中手动切换或新建工作区。');
      }

      navigateAfterLogin('/dashboard');
    } catch (error) {
      if (isAuthErrorResponse(error)) {
        if (error.code === 'AUTH_INVALID_CREDENTIALS') {
          stepTwoForm.setFields([{ name: 'password', errors: ['用户名、邮箱、手机号或密码错误'] }]);
          return;
        }

        if (error.code === 'ACCOUNT_NOT_ACTIVE') {
          message.error('账号当前不可登录，请联系管理员。');
          return;
        }

        if (error.code === 'INVALID_ARGUMENT') {
          message.error(error.message || '登录信息无效或登录加密已过期，请重试');
          return;
        }

        message.error(error.message || '登录失败，请稍后重试');
        return;
      }

      message.error('登录失败，请稍后重试');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="ibm-login-page">
      <header className="ibm-login-header">
        <div className="ibm-header-content">
          <div className="ibm-logo">PLM Cloud Platform</div>
        </div>
      </header>

      <main className="ibm-login-main">
        <div className="ibm-login-container">
          {/* 左侧登录表单区域 */}
          <section className="ibm-login-form-section">
            <div className="ibm-login-form-wrap">
              <Title level={2} className="login-title">
                登录 PLM Cloud Platform
              </Title>
              <Text className="login-subtitle">
                没有账号？ <Link href="/register" style={{ color: '#0f62fe' }}>创建 PLM Cloud Platform 账号</Link>
              </Text>

              {step === 1 && (
                <Form
                  form={stepOneForm}
                  layout="vertical"
                  onFinish={handleStep1Finish}
                  autoComplete="off"
                  className="ibm-login-form"
                >
                  <Form.Item
                    label="PLM Cloud Platform ID"
                    name="plmId"
                    rules={[{ required: true, message: "请输入PLM Cloud Platform ID" }]}
                  >
                    <Input
                      placeholder="用户名、邮箱或手机号"
                      size="large"
                      className="ibm-input"
                    />
                  </Form.Item>
                  <Form.Item style={{ marginBottom: 12 }}>
                    <Button
                      type="primary"
                      htmlType="submit"
                      block
                      size="large"
                      className="ibm-continue-btn"
                      icon={<ArrowRightOutlined />}
                      iconPlacement="end"
                    >
                      继续
                    </Button>
                  </Form.Item>
                  <div className="divider-text">替代登录</div>
                  <Button
                    block
                    size="large"
                    className="google-login-btn"
                    icon={<GoogleOutlined style={{ color: '#4285f4' }} />}
                  >
                    使用 Google 继续
                  </Button>
                  <Button
                    style={{ marginTop: 16 }}
                    block
                    size="large"
                    className="google-login-btn"
                    icon={<GithubOutlined style={{ color: '#000000ff' }} />}
                  >
                    使用 Github 继续
                  </Button>
                  <div className="login-footer-links">
                    <Text className="footer-text">
                      忘记 PLM Cloud Platform ID？ <Link href="#" style={{ color: '#0f62fe' }}>帮助</Link>
                    </Text>
                  </div>
                </Form>
              )}
              {step === 2 && (
                <Form
                  form={stepTwoForm}
                  layout="vertical"
                  onFinish={handleLogin}
                  initialValues={{ remember: true }}
                  autoComplete="off"
                  className="ibm-login-form"
                >
                  <div className="step2-header">
                    <Button type="link" icon={<LeftOutlined />} onClick={() => setStep(1)} className="back-btn">返回</Button>
                  </div>
                  <Divider className="step-divider" />
                  <div className="identity-row">
                    <span className="id-label">以 <strong>{plmIdCache}</strong> 身份登录</span>
                    <Button type="link" size="small" className="not-you" onClick={() => setStep(1)}>不是您?</Button>
                  </div>
                  <Divider className="step-divider" />
                  <Form.Item
                    label="密码"
                    name="password"
                    rules={[{ required: true, message: "请输入密码" }]}
                  >
                    <Input.Password
                      placeholder="请输入密码"
                      size="large"
                      className="ibm-input"
                    />
                  </Form.Item>
                  <Form.Item name="remember" valuePropName="checked" style={{ marginBottom: 16 }}>
                    <Checkbox className="ibm-checkbox">
                      记住我 <QuestionCircleOutlined style={{ fontSize: 12, color: '#666', marginLeft: 4 }} />
                    </Checkbox>
                  </Form.Item>
                  <Form.Item style={{ marginBottom: 12 }}>
                    <Button
                      type="primary"
                      htmlType="submit"
                      block
                      size="large"
                      loading={loading}
                      className="ibm-continue-btn"
                      icon={<ArrowRightOutlined />}
                      iconPlacement="end"
                    >
                      登录
                    </Button>
                  </Form.Item>
                  <div className="login-footer-links step2-extra">
                    <Link href="#" className="forgot-link" style={{ color: '#0f62fe' }}>忘记密码?</Link>
                    <Divider className="step-divider" />
                    <Text className="footer-text small">
                      忘记 ID? <Link href="#" style={{ color: '#0f62fe' }}>帮助中心</Link>
                    </Text>
                  </div>
                </Form>
              )}
            </div>
          </section>

          {/* 右侧装饰区域 */}
          <aside className="ibm-login-art" aria-hidden="true">
            <div className="art-background">
              <Image src={Illustration} alt="" className="login-illustration" />
            </div>
          </aside>
        </div>
      </main>

      <footer className="ibm-login-footer">
        <div className="footer-content">
          <div className="footer-links">
            <Link href="#">联系</Link>
            <Link href="#">隐私条款</Link>
            <Link href="#">使用条款</Link>
            <Link href="#">辅助功能选项</Link>
          </div>
          <Text className="footer-copyright">
            Powered by PLM Cloud Platform © 2026 All Rights Reserved.
          </Text>
        </div>
      </footer>
    </div>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { List, Card, Typography, Space, Button, Tag, Empty, theme, Tabs, Spin } from 'antd';
import { RightOutlined, LeftOutlined, AppstoreOutlined, ShopOutlined, TagOutlined } from '@ant-design/icons';
import type { MillerNode } from '../mockData';
import { metaCategoryApi, type MetaCategoryNodeDto } from '../../../../../services/metaCategory';

const { Title, Text, Paragraph } = Typography;

interface CategoryBrowserProps {
  onSelect: (node: MillerNode) => void;
}

const mapBrowseNodeToMillerNode = (dto: MetaCategoryNodeDto): MillerNode => ({
  key: dto.id,
  code: dto.code,
  title: dto.name,
  hasChildren: dto.hasChildren,
  depth: dto.level,
  fullPathName: dto.path || undefined,
});

interface ClassGroup {
  clazz: MetaCategoryNodeDto;
  commodities: MetaCategoryNodeDto[];
}

const CategoryBrowser: React.FC<CategoryBrowserProps> = ({ onSelect }) => {
  const { token } = theme.useToken();
  
  // Data state (API)
  const [groups, setGroups] = useState<MillerNode[]>([]);
  const [groupsLoading, setGroupsLoading] = useState(false);
  const [activeGroupKey, setActiveGroupKey] = useState<string | null>(null);

  const [families, setFamilies] = useState<MillerNode[]>([]);
  const [familiesLoading, setFamiliesLoading] = useState(false);
  const [activeFamily, setActiveFamily] = useState<MillerNode | null>(null);

  // Right content can drill down: family -> clazz/commodity -> ...
  const [activeScope, setActiveScope] = useState<MillerNode | null>(null);
  const [scopeStack, setScopeStack] = useState<MillerNode[]>([]);

  const [classGroups, setClassGroups] = useState<ClassGroup[]>([]);
  const [classGroupsLoading, setClassGroupsLoading] = useState(false);

  // Selected leaf node for confirmation
  const [selectedLeaf, setSelectedLeaf] = useState<MillerNode | null>(null);

  // Load groups once
  useEffect(() => {
    let cancelled = false;
    const run = async () => {
      setGroupsLoading(true);
      try {
        const resp = await metaCategoryApi.listNodes({ businessDomain: 'MATERIAL', level: 1, page: 0, size: 200 });
        if (cancelled) return;
        const nextGroups = (resp.content || []).map(mapBrowseNodeToMillerNode);
        setGroups(nextGroups);
        setActiveGroupKey((prev) => prev ?? nextGroups[0]?.key ?? null);
      } finally {
        if (!cancelled) setGroupsLoading(false);
      }
    };
    void run();
    return () => {
      cancelled = true;
    };
  }, []);

  // Load families when group changes
  useEffect(() => {
    if (!activeGroupKey) return;
    let cancelled = false;
    const run = async () => {
      setFamiliesLoading(true);
      setFamilies([]);
      setActiveFamily(null);
      setActiveScope(null);
      setScopeStack([]);
      setClassGroups([]);
      setSelectedLeaf(null);
      try {
        const resp = await metaCategoryApi.listNodes({
          businessDomain: 'MATERIAL',
          parentId: activeGroupKey,
          page: 0,
          size: 200,
        });
        if (cancelled) return;
        setFamilies((resp.content || []).map(mapBrowseNodeToMillerNode));
      } finally {
        if (!cancelled) setFamiliesLoading(false);
      }
    };
    void run();
    return () => {
      cancelled = true;
    };
  }, [activeGroupKey]);

  // Reset right-side scope when family changes
  useEffect(() => {
    setActiveScope(activeFamily);
    setScopeStack([]);
    setSelectedLeaf(null);
  }, [activeFamily?.key]);

  // Load right-side classes-with-commodities when scope changes
  useEffect(() => {
    if (!activeScope?.key) return;
    let cancelled = false;
    const run = async () => {
      setClassGroupsLoading(true);
      setClassGroups([]);
      try {
        const resp = await metaCategoryApi.listNodes({
          businessDomain: 'MATERIAL',
          parentId: activeScope.key,
          page: 0,
          size: 200,
        });
        if (cancelled) return;

        const children = resp.content || [];
        const groups = await Promise.all(
          children.map(async (child) => {
            if (!child.hasChildren) {
              return { clazz: child, commodities: [] };
            }
            const sub = await metaCategoryApi.listNodes({
              businessDomain: 'MATERIAL',
              parentId: child.id,
              page: 0,
              size: 200,
            });
            return { clazz: child, commodities: sub.content || [] };
          }),
        );
        if (cancelled) return;
        setClassGroups(groups);
      } finally {
        if (!cancelled) setClassGroupsLoading(false);
      }
    };
    void run();
    return () => {
      cancelled = true;
    };
  }, [activeScope?.key]);

  const activeGroup = useMemo(() => groups.find((g) => g.key === activeGroupKey) ?? null, [groups, activeGroupKey]);

  // Render Left: Families under active group
  const renderFamiliesSidebar = () => (
    <div style={{ 
      width: 280, 
      borderRight: `1px solid ${token.colorBorderSecondary}`, 
      overflowY: 'auto',
      backgroundColor: token.colorFillQuaternary, // Lighter background
      flexShrink: 0,
      display: 'flex',
      flexDirection: 'column'
    }}>
      <div style={{ padding: '12px 16px', borderBottom: `1px solid ${token.colorBorderSecondary}`, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <Text strong>大类</Text>
        <Tag>{families.length}</Tag>
      </div>
      {!activeGroupKey ? (
        <div style={{ padding: 24, textAlign: 'center', color: token.colorTextTertiary }}>
          请先选择上方分组
        </div>
      ) : (
        <Spin spinning={familiesLoading} style={{ padding: 12 }}>
          <List
            dataSource={families}
            size="small"
            split={false}
            renderItem={(item) => {
              const isActive = activeFamily?.key === item.key;
              return (
                <div
                  onClick={() => setActiveFamily(item)}
                  style={{
                    padding: '12px 16px 12px 20px',
                    cursor: 'pointer',
                    backgroundColor: isActive ? token.colorBgContainer : 'transparent',
                    color: isActive ? token.colorPrimary : token.colorText,
                    fontWeight: isActive ? 600 : 400,
                    transition: 'all 0.2s',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    fontSize: 13,
                    borderBottom: `1px solid ${token.colorBorderSecondary}`
                  }}
                >
                  <span style={{ marginRight: 8, overflow: 'hidden', textOverflow: 'ellipsis', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical' }} title={item.title}>
                    {item.title}
                  </span>
                  {isActive && <RightOutlined style={{ fontSize: 10, flexShrink: 0 }} />}
                </div>
              );
            }}
          />
        </Spin>
      )}
    </div>
  );

  // Render Right Content
  const renderContent = () => {
    if (!activeFamily) {
      return (
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: token.colorTextTertiary, backgroundColor: token.colorBgContainer }}>
          <ShopOutlined style={{ fontSize: 48, marginBottom: 16, opacity: 0.1 }} />
          <Text type="secondary">请选择左侧大类以查看详情</Text>
        </div>
      );
    }

    const handleClickNode = (node: MillerNode) => {
      if (node.hasChildren) {
        setScopeStack((prev) => {
          const current = activeScope ?? activeFamily;
          if (!current || current.key === node.key) return prev;
          return [...prev, current];
        });
        setActiveScope(node);
        setSelectedLeaf(null);
        return;
      }
      
      setSelectedLeaf(node);
      onSelect(node);
    };

    const canGoBack = !!activeFamily && (activeScope?.key !== activeFamily.key || scopeStack.length > 0);
    const handleGoBack = () => {
      setScopeStack((prev) => {
        if (prev.length === 0) {
          setActiveScope(activeFamily);
          return [];
        }
        const next = [...prev];
        const last = next.pop() ?? null;
        setActiveScope(last ?? activeFamily);
        return next;
      });
      setSelectedLeaf(null);
    };

    const headerTitle = activeScope?.title ?? activeFamily.title;

    return (
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div style={{ padding: '16px 24px', borderBottom: `1px solid ${token.colorBorderSecondary}`, backgroundColor: token.colorBgContainer }}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
            {canGoBack && (
              <div>
                <Button
                  type="text"
                  size="small"
                  icon={<LeftOutlined />}
                  onClick={handleGoBack}
                  style={{ padding: 0 }}
                >
                  返回上级
                </Button>
              </div>
            )}

            <Title level={4} style={{ margin: 0 }}>{headerTitle}</Title>
          </div>
        </div>

        <div style={{ flex: 1, overflowY: 'auto', padding: '24px', backgroundColor: '#fafafa' }}>
          <Spin spinning={classGroupsLoading}>
            {classGroups.map((group) => {
              const clazzNode = mapBrowseNodeToMillerNode(group.clazz);
              const commodities = (group.commodities || []).map(mapBrowseNodeToMillerNode);

              // Special case: Single Leaf Class (No commodities, no sub-classes)
              // 直接点击整个标题框，提示用户选中高亮显示
              if (commodities.length === 0 && !group.clazz.hasChildren) {
                const isSelected = selectedLeaf?.key === clazzNode.key;
                return (
                  <Card
                    key={group.clazz.id}
                    size="small"
                    hoverable
                    onClick={() => handleClickNode(clazzNode)}
                    style={{ 
                      marginBottom: 16, 
                      boxShadow: '0 1px 2px rgba(0,0,0,0.03)',
                      borderColor: isSelected ? token.colorPrimary : token.colorBorderSecondary,
                      backgroundColor: isSelected ? token.colorPrimaryBg : token.colorBgContainer
                    }}
                    bodyStyle={{ padding: '12px 16px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}
                  >
                    <Space style={{ color: isSelected ? token.colorPrimary : token.colorText, fontWeight: isSelected ? 600 : 400 }}>
                      <TagOutlined />
                      {clazzNode.title}
                    </Space>
                  </Card>
                );
              }

              return (
                <Card
                  key={group.clazz.id}
                  title={<Space><AppstoreOutlined />{group.clazz.name}</Space>}
                  size="small"
                  style={{ marginBottom: 16, boxShadow: '0 1px 2px rgba(0,0,0,0.03)' }}
                  headStyle={{ backgroundColor: token.colorBgContainer, borderBottom: `1px solid ${token.colorBorderSecondary}` }}
                >
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                    {commodities.map((node) => {
                      const isSelected = selectedLeaf?.key === node.key;
                      return (
                        <div
                          key={node.key}
                          onClick={() => handleClickNode(node)}
                          style={{
                            cursor: 'pointer',
                            borderRadius: token.borderRadius,
                            border: `1px solid ${isSelected ? token.colorPrimary : token.colorBorderSecondary}`,
                            backgroundColor: isSelected ? token.colorPrimaryBg : token.colorFillQuaternary,
                            padding: '8px 12px',
                            transition: 'all 0.2s',
                            minWidth: 120,
                            display: 'flex',
                            flexDirection: 'row',
                            alignItems: 'center',
                            justifyContent: 'center',
                            gap: 6,
                            textAlign: 'center'
                          }}
                        >
                          {!node.hasChildren && (
                            <TagOutlined 
                              style={{ 
                                fontSize: 14, 
                                opacity: 0.6,
                                color: isSelected ? token.colorPrimary : token.colorTextTertiary 
                              }} 
                            />
                          )}
                          <Text strong={isSelected} style={{ color: isSelected ? token.colorPrimary : token.colorText }}>
                            {node.title}
                          </Text>
                        </div>
                      );
                    })}

                    {commodities.length === 0 && group.clazz.hasChildren && (
                      <Button
                        type="primary"
                        ghost
                        size="small"
                        onClick={() => handleClickNode(clazzNode)}
                      >
                        查看子分类
                      </Button>
                    )}
                  </div>
                </Card>
              );
            })}

            {!classGroupsLoading && classGroups.length === 0 && (
              <Empty description="暂无子分类" />
            )}
          </Spin>
        </div>
      </div>
    );
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', border: `1px solid ${token.colorBorderSecondary}`, borderRadius: token.borderRadius, overflow: 'hidden', backgroundColor: token.colorBgContainer }}>
      {/* Top Tabs for Groups */}
      <div style={{ borderBottom: `1px solid ${token.colorBorderSecondary}`, padding: '0 16px', backgroundColor: token.colorBgContainer }}>
        <Tabs
          activeKey={activeGroupKey ?? undefined}
          onChange={(key) => setActiveGroupKey(key)}
          items={groups.map(group => ({
            key: group.key,
            label: group.title,
          }))}
          style={{ marginBottom: -1 }}
        />
      </div>
      
      {/* Main Content Area */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {groupsLoading ? (
          <div style={{ flex: 1, padding: 24 }}>
            <Spin spinning />
          </div>
        ) : (
          <>
            {renderFamiliesSidebar()}
            {renderContent()}
          </>
        )}
      </div>
    </div>
  );
};

export default CategoryBrowser;

import React from 'react';
import { Card, Descriptions, Tabs, Tag, Typography, Empty, Button, Space, Modal, App } from 'antd';
import { ProTable } from '@ant-design/pro-components';
import { EditOutlined, PlusOutlined, DeleteOutlined, ExclamationCircleOutlined } from '@ant-design/icons';
import type { DataNode } from 'antd/es/tree';

const { Title } = Typography;

interface CategoryDetailProps {
  selectedKey?: React.Key;
  selectedNode?: DataNode;
  onDelete?: (key: React.Key) => void;
  onCreateSub?: (parentKey: React.Key) => void;
}

const CategoryDetail: React.FC<CategoryDetailProps> = ({ selectedKey, selectedNode, onDelete, onCreateSub }) => {
  const { modal } = App.useApp();

  if (!selectedKey) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100%', color: '#999' }}>
        <Empty description="请选择左侧分类查看详情" />
      </div>
    );
  }

  // 模拟根据 selectedKey 获取的数据
  const isIndustry = String(selectedKey).startsWith('IND');

  const handleDelete = () => {
    modal.confirm({
      title: '确认删除分类?',
      icon: <ExclamationCircleOutlined />,
      content: '删除后无法恢复，且该分类下的所有子分类也将被删除。',
      okText: '确认删除',
      okType: 'danger',
      cancelText: '取消',
      onOk() {
        onDelete?.(selectedKey);
      },
    });
  };

  const items = [
    {
      key: '1',
      label: '基础信息',
      children: (
        <Card title="基本信息" extra={<Button type="link" icon={<EditOutlined />}>编辑</Button>}>
          <Descriptions column={2}>
            <Descriptions.Item label="分类名称">{typeof selectedNode?.title === 'function' ? (selectedNode!.title as (data: DataNode) => React.ReactNode)(selectedNode as DataNode) : selectedNode?.title}</Descriptions.Item>
            <Descriptions.Item label="分类编码">{String(selectedKey)}</Descriptions.Item>
            <Descriptions.Item label="类型">
              {isIndustry ? <Tag color="blue">行业分类</Tag> : <Tag color="green">自定义分类</Tag>}
            </Descriptions.Item>
            <Descriptions.Item label="状态"><Tag color="success">启用</Tag></Descriptions.Item>
            <Descriptions.Item label="创建人">System Admin</Descriptions.Item>
            <Descriptions.Item label="创建时间">2025-01-01</Descriptions.Item>
            <Descriptions.Item label="描述" span={2}>
              {isIndustry ? '系统预置的行业标准分类，不可删除。' : '用户自定义的物料/产品分类文件夹。'}
            </Descriptions.Item>
          </Descriptions>
        </Card>
      ),
    },
    {
      key: '2',
      label: '扩展属性',
      children: (
        <Card title="属性定义" extra={<Button type="primary" size="small" icon={<PlusOutlined />}>添加属性</Button>}>
          <ProTable
            search={false}
            options={false}
            pagination={false}
            dataSource={[
              { id: 1, name: '材质', code: 'MATERIAL', type: '文本', required: '是' },
              { id: 2, name: '重量(kg)', code: 'WEIGHT', type: '数值', required: '否' },
              { id: 3, name: '供应商', code: 'VENDOR', type: '引用', required: '是' },
            ]}
            columns={[
              { title: '属性名称', dataIndex: 'name' },
              { title: '属性编码', dataIndex: 'code' },
              { title: '数据类型', dataIndex: 'type' },
              { title: '是否必填', dataIndex: 'required' },
              {
                title: '操作',
                valueType: 'option',
                render: () => [<a key="edit">编辑</a>, <a key="del" style={{ color: 'red' }}>删除</a>],
              },
            ]}
            rowKey="id"
          />
        </Card>
      ),
    },
    {
      key: '3',
      label: '编码规则',
      children: (
        <Card >
          <Empty description="暂未配置自动编码规则" />
        </Card>
      ),
    },
  ];

  return (
    <div style={{ padding: '0 24px', height: '100%', overflow: 'auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
        <Title level={4} style={{ margin: 0 }}>
          {typeof selectedNode?.title === 'function' ? (selectedNode!.title as (data: DataNode) => React.ReactNode)(selectedNode as DataNode) : selectedNode?.title}
        </Title>
        <Space>
          {!isIndustry && <Button danger icon={<DeleteOutlined />} onClick={handleDelete}>删除分类</Button>}
          <Button type="primary" icon={<PlusOutlined />} onClick={() => onCreateSub?.(selectedKey)}>新建子分类</Button>
        </Space>
      </div>
      <Tabs defaultActiveKey="1" items={items} />
    </div>
  );
};

export default CategoryDetail;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Typography, Checkbox, Button, List, Tag, Empty, Input, Space, Badge, Statistic, Tooltip, Select, Spin, Breadcrumb, Modal, Splitter, Tree, App } from 'antd';
import { ShoppingCartOutlined, PlusOutlined, DeleteOutlined, SearchOutlined, EditOutlined, AppstoreOutlined, DatabaseOutlined, ArrowRightOutlined, FolderOutlined } from '@ant-design/icons';
import { ProCard } from '@ant-design/pro-components';
import type { DataNode, TreeProps } from 'antd/es/tree';
import DraggableModal from '../../../../../components/DraggableModal';
import { lightPalette } from '../../../../../styles/colors';

import { LIBRARIES, MOCK_DB, MOCK_ATTRIBUTES, type CategoryItem, type MillerNode } from '../mockData';
import { metaCategoryApi } from '../../../../../services/metaCategory';
import MillerColumns from './MillerColumns';
import CategoryBrowser from './CategoryBrowser';

const { Title, Text } = Typography;

// --- 类型定义 ---

export interface CartItem extends CategoryItem {
  attributes: string[];
  // targetKey 移除，改为在 Stage 2 统一处理
}

interface CategoryMarketplaceProps {
  open: boolean;
  onCancel: () => void;
  onOk: (treeData: DataNode[]) => void; // 接口变更：返回最终的树结构
  userTreeData?: DataNode[];
}

const CategoryMarketplace: React.FC<CategoryMarketplaceProps> = ({ open, onCancel, onOk, userTreeData = [] }) => {
  const { message, modal } = App.useApp();
  // --- 状态管理 ---

  const [stage, setStage] = useState<0 | 1>(0); // 0: 选品, 1: 分配位置

  // 1. 购物车状态 (持久化)
  const [cart, setCart] = useState<CartItem[]>([]);
  
  // 2. 搜索与浏览状态
  const [selectedLibrary, setSelectedLibrary] = useState<string>('GB');
  const [searchResults, setSearchResults] = useState<CategoryItem[]>([]);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [searchQuery, setSearchQuery] = useState<string>('');

  // 3. 当前选中的分类 (配置区)
  const [activeCategory, setActiveCategory] = useState<CategoryItem | null>(null);
  const [checkedAttributes, setCheckedAttributes] = useState<string[]>([]);
  const [selectedMillerPath, setSelectedMillerPath] = useState<string[]>([]);

  // Handler for CategoryBrowser selection (Leaf node)
  const handleBrowserSelect = (node: MillerNode) => {
    const pathTitles: string[] = node.fullPathName
      ? node.fullPathName.split('/').filter(Boolean)
      : ['UNSPSC', node.title];
    
    const categoryItem: CategoryItem = {
      key: node.key,
      title: node.title,
      code: node.code,
      path: pathTitles,
      library: 'UNSPSC'
    };
    handleSelectCategory(categoryItem);
  };

  const handleMillerSelect = (node: MillerNode, level: number) => {
    // Update selected path
    const newPath = selectedMillerPath.slice(0, level);
    newPath.push(node.key);
    setSelectedMillerPath(newPath);

    if (node.isLeaf) {
      const categoryItem: CategoryItem = {
        key: node.key,
        title: node.title,
        code: node.code,
        path: ['UNSPSC', node.title],
        library: 'UNSPSC'
      };
      handleSelectCategory(categoryItem);
    }
  };

  // 4. Stage 2 状态
  const [previewTreeData, setPreviewTreeData] = useState<DataNode[]>([]);
  const [pendingItems, setPendingItems] = useState<CartItem[]>([]);
  const [selectedPendingKeys, setSelectedPendingKeys] = useState<string[]>([]);
  const [lastSelectedKey, setLastSelectedKey] = useState<string | null>(null);
  const [selectedTargetNodeKey, setSelectedTargetNodeKey] = useState<React.Key | null>(null);
  const [expandedKeys, setExpandedKeys] = useState<React.Key[]>([]);
  const [autoExpandParent, setAutoExpandParent] = useState<boolean>(true);
  
  // Tree height auto-adjustment
  const [treeHeight, setTreeHeight] = useState<number>(600);
  const treeContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (stage === 1 && treeContainerRef.current) {
      const updateHeight = () => {
        if (treeContainerRef.current) {
          setTreeHeight(treeContainerRef.current.offsetHeight);
        }
      };

      // Initial calculation
      updateHeight();

      const observer = new ResizeObserver(updateHeight);
      observer.observe(treeContainerRef.current);
      
      return () => observer.disconnect();
    }
  }, [stage]);

  // --- 业务逻辑 ---

  // UNSPSC search via backend; other libraries stay on mock
  const handleSearch = useCallback(async (query: string) => {
    setSearchQuery(query);
    const q = query.trim();
    if (!q) {
      setSearchResults([]);
      return;
    }

    setIsSearching(true);
    try {
      if (selectedLibrary === 'UNSPSC') {
        const page = await metaCategoryApi.search({ businessDomain: 'MATERIAL', keyword: q, size: 50, page: 0 });
        const results: CategoryItem[] = (page.content || []).map((hit) => ({
          key: hit.node.id,
          title: hit.node.name,
          code: hit.node.code,
          path: (hit.pathNodes && hit.pathNodes.length > 0)
            ? hit.pathNodes.map((p) => p.name)
            : ['UNSPSC', hit.node.name],
          library: 'UNSPSC',
        }));
        setSearchResults(results);
      } else {
        const source = MOCK_DB[selectedLibrary] || [];
        const results = source.filter(item =>
          item.title.toLowerCase().includes(q.toLowerCase()) || item.code.includes(q)
        );
        setSearchResults(results);
      }
    } finally {
      setIsSearching(false);
    }
  }, [selectedLibrary]);

  // --- 持久化逻辑 ---
  const STORAGE_KEY = 'PLM_CATEGORY_CART_DRAFT';

  // 初始化加载
  useEffect(() => {
    if (open) {
      const savedCart = localStorage.getItem(STORAGE_KEY);
      if (savedCart) {
        try {
          const parsed = JSON.parse(savedCart);
          if (Array.isArray(parsed) && parsed.length > 0) {
            setCart(parsed);
            message.success({ content: `已恢复上次未提交的 ${parsed.length} 项分类`, key: 'restore_cart' });
          }
        } catch (e) {
          console.error('Failed to parse cart draft', e);
        }
      }
      // 初始加载列表
      setSearchQuery('');
      setSearchResults([]);
      // 重置 Stage
      setStage(0);
    }
  }, [open]);

  // 自动保存
  useEffect(() => {
    if (open && stage === 0) { // 只有打开状态下才同步，避免意外覆盖
      localStorage.setItem(STORAGE_KEY, JSON.stringify(cart));
    }
  }, [cart, open, stage]);

  const handleLibraryChange = (value: string) => {
    setSelectedLibrary(value);
    // 切换库后重置搜索结果，或者自动触发一次空搜索
    setIsSearching(true);
    setTimeout(() => {
      const source = MOCK_DB[value] || [];
      setSearchResults(source); // 显示全部或前N条
      setIsSearching(false);
    }, 300);
  };

  const handleSelectCategory = (item: CategoryItem) => {
    setActiveCategory(item);

    // 检查是否已在购物车中 (编辑模式)
    const existingItem = cart.find(c => c.key === item.key);
    if (existingItem) {
      setCheckedAttributes(existingItem.attributes);
    } else {
      // 默认全选或者空，这里设为默认选前3个模拟智能推荐
      setCheckedAttributes(MOCK_ATTRIBUTES.slice(0, 3));
    }
  };

  const handleAddToCart = () => {
    if (!activeCategory) return;

    const newItem: CartItem = {
      ...activeCategory,
      attributes: checkedAttributes,
    };

    const index = cart.findIndex(item => item.key === newItem.key);
    if (index > -1) {
      const newCart = [...cart];
      newCart[index] = newItem;
      setCart(newCart);
      message.success('已更新配置');
    } else {
      setCart([...cart, newItem]);
      message.success('已加入清单');
    }
  };

  const handleRemoveFromCart = (key: string) => {
    setCart(prev => prev.filter(item => item.key !== key));
    if (activeCategory?.key === key) {
      // 如果删除的是当前正在配置的，可以选择重置状态，或者保持不变
    }
  };

  const handleClearCart = () => {
    modal.confirm({
      title: '确认清空清单?',
      content: '此操作将移除所有已选分类，且不可恢复。',
      onOk: () => {
        setCart([]);
        localStorage.removeItem(STORAGE_KEY);
        message.info('清单已清空');
      }
    });
  };

  // --- Stage 2 Logic ---

  // Helper for deep cloning tree data while preserving React Nodes (like icon)
  const cloneTree = (data: DataNode[]): DataNode[] => {
    return data.map(item => ({
      ...item,
      children: item.children ? cloneTree(item.children) : undefined,
    }));
  };

  const getAllKeys = (data: DataNode[]): React.Key[] => {
    let keys: React.Key[] = [];
    data.forEach(item => {
      keys.push(item.key);
      if (item.children) {
        keys = keys.concat(getAllKeys(item.children));
      }
    });
    return keys;
  };

  const onExpand = (newExpandedKeys: React.Key[]) => {
    setExpandedKeys(newExpandedKeys);
    setAutoExpandParent(false);
  };

  const handleNextStage = () => {
    if (cart.length === 0) {
      message.warning('请先选择要导入的分类');
      return;
    }
    // 初始化 Stage 2 数据
    // 深拷贝 userTreeData 以便在预览中修改
    const clonedData = cloneTree(userTreeData);
    setPreviewTreeData(clonedData);
    setExpandedKeys(getAllKeys(clonedData));
    setPendingItems([...cart]);
    setSelectedPendingKeys([]);
    setLastSelectedKey(null);
    setSelectedTargetNodeKey(null);
    setStage(1);
  };

  const handlePrevStage = () => {
    setStage(0);
  };

  const handleAssignToTree = () => {
    if (selectedPendingKeys.length === 0) {
      message.warning('请先在左侧选择要分配的分类');
      return;
    }
    if (!selectedTargetNodeKey) {
      message.warning('请在右侧树中选择一个目标节点');
      return;
    }

    const itemsToAssign = pendingItems.filter(item => selectedPendingKeys.includes(item.key));
    
    // 构建新节点
    const newNodes: DataNode[] = itemsToAssign.map(item => ({
      title: item.title,
      key: item.key, // 注意：这里直接使用了库中的 key，实际可能需要生成新 key 避免冲突，这里暂且假设库 key 唯一或作为前缀
      icon: <FolderOutlined />,
      isLeaf: true,
      // 可以在这里添加额外属性标识这是新导入的节点
    }));

    // 递归更新树
    const updateTree = (data: DataNode[]): DataNode[] => {
      return data.map(node => {
        if (node.key === selectedTargetNodeKey) {
          return {
            ...node,
            children: [...(node.children || []), ...newNodes],
            isLeaf: false,
          };
        }
        if (node.children) {
          return {
            ...node,
            children: updateTree(node.children),
          };
        }
        return node;
      });
    };

    setPreviewTreeData(prev => updateTree(prev));
    
    // 自动展开目标节点
    if (selectedTargetNodeKey) {
      setExpandedKeys(prev => {
        if (!prev.includes(selectedTargetNodeKey)) {
          return [...prev, selectedTargetNodeKey];
        }
        return prev;
      });
      setAutoExpandParent(true);
    }

    // 从待分配列表中移除
    setPendingItems(prev => prev.filter(item => !selectedPendingKeys.includes(item.key)));
    setSelectedPendingKeys([]);
    setLastSelectedKey(null);
    message.success(`已将 ${itemsToAssign.length} 个分类分配到目标节点`);
  };

  const onDrop: TreeProps['onDrop'] = (info) => {
    const dropKey = info.node.key;
    const dragKey = info.dragNode.key;
    const dropPos = info.node.pos.split('-');
    const dropPosition = info.dropPosition - Number(dropPos[dropPos.length - 1]);

    const loop = (data: DataNode[], key: React.Key, callback: (node: DataNode, i: number, data: DataNode[]) => void) => {
      for (let i = 0; i < data.length; i++) {
        if (data[i].key === key) {
          return callback(data[i], i, data);
        }
        if (data[i].children) {
          loop(data[i].children!, key, callback);
        }
      }
    };
    const data = cloneTree(previewTreeData);

    // Find dragObject
    let dragObj: DataNode;
    loop(data, dragKey, (item, index, arr) => {
      arr.splice(index, 1);
      dragObj = item;
    });

    if (!info.dropToGap) {
      // Drop on the content
      loop(data, dropKey, (item) => {
        item.children = item.children || [];
        // where to insert? default to end
        item.children.unshift(dragObj);
        item.isLeaf = false; // 确保父节点不再是叶子节点
      });
      
      // 自动展开目标节点
      setExpandedKeys(prev => {
        if (!prev.includes(dropKey)) {
          return [...prev, dropKey];
        }
        return prev;
      });
      setAutoExpandParent(true);
    } else if (
      ((info.node as any).props.children || []).length > 0 && // Has children
      (info.node as any).expanded && // Is expanded
      dropPosition === 1 // On the bottom gap
    ) {
      loop(data, dropKey, (item) => {
        item.children = item.children || [];
        item.children.unshift(dragObj);
      });
    } else {
      let ar: DataNode[] = [];
      let i: number;
      loop(data, dropKey, (_, index, arr) => {
        ar = arr;
        i = index;
      });
      if (dropPosition === -1) {
        ar.splice(i!, 0, dragObj!);
      } else {
        ar.splice(i! + 1, 0, dragObj!);
      }
    }
    setPreviewTreeData(data);
  };

  const handlePendingItemClick = (key: string, e: React.MouseEvent) => {
    // 阻止默认行为，防止 Checkbox 自身的 onChange 干扰
    // e.preventDefault(); 
    // 注意：如果阻止了 Checkbox 的默认行为，可能导致 Checkbox 状态不更新，所以这里我们主要依赖 onClick 处理逻辑
    
    let newSelectedKeys = [...selectedPendingKeys];

    if (e.shiftKey && lastSelectedKey) {
      // Shift 范围选择
      const lastIndex = pendingItems.findIndex(item => item.key === lastSelectedKey);
      const currentIndex = pendingItems.findIndex(item => item.key === key);
      
      if (lastIndex !== -1 && currentIndex !== -1) {
        const start = Math.min(lastIndex, currentIndex);
        const end = Math.max(lastIndex, currentIndex);
        const rangeKeys = pendingItems.slice(start, end + 1).map(item => item.key);
        
        // 合并选中（去重）
        newSelectedKeys = Array.from(new Set([...newSelectedKeys, ...rangeKeys]));
      }
    } else if (e.ctrlKey || e.metaKey) {
      // Ctrl/Cmd 单选（切换）
      if (newSelectedKeys.includes(key)) {
        newSelectedKeys = newSelectedKeys.filter(k => k !== key);
      } else {
        newSelectedKeys.push(key);
      }
      setLastSelectedKey(key);
    } else {
      // 普通点击：只选中当前项
      newSelectedKeys = [key];
      setLastSelectedKey(key);
    }

    setSelectedPendingKeys(newSelectedKeys);
  };

  const handleCheckboxClick = (key: string, e: React.MouseEvent) => {
    e.stopPropagation(); // 阻止冒泡到行点击事件
    
    let newSelectedKeys = [...selectedPendingKeys];
    if (newSelectedKeys.includes(key)) {
      newSelectedKeys = newSelectedKeys.filter(k => k !== key);
    } else {
      newSelectedKeys.push(key);
    }
    // Checkbox 点击通常不更新 Shift 选择的锚点，或者更新？Windows Explorer 似乎更新。
    setLastSelectedKey(key);
    setSelectedPendingKeys(newSelectedKeys);
  };

  const handleFinalSubmit = () => {
    if (pendingItems.length > 0) {
      modal.confirm({
        title: '还有未分配的分类',
        content: `还有 ${pendingItems.length} 个分类未分配到树中。继续提交将忽略这些分类。`,
        onOk: () => {
          onOk(previewTreeData);
          localStorage.removeItem(STORAGE_KEY);
          setCart([]);
          setStage(0);
        }
      });
    } else {
      onOk(previewTreeData);
      localStorage.removeItem(STORAGE_KEY);
      setCart([]);
      setStage(0);
    }
  };

  // --- 渲染辅助 ---

  const renderSearchResultItem = (item: CategoryItem) => {
    const isActive = activeCategory?.key === item.key;
    const isInCart = cart.some(c => c.key === item.key);

    return (
      <List.Item
        onClick={() => handleSelectCategory(item)}
        style={{
          cursor: 'pointer',
          padding: '12px',
          borderRadius: '6px',
          backgroundColor: isActive ? lightPalette.menuItemSelectedBg : 'transparent',
          border: isActive ? `1px solid ${lightPalette.menuTextSelected}` : '1px solid transparent',
          transition: 'all 0.2s',
          marginBottom: 4
        }}
        className="search-result-item"
      >
        <div style={{ width: '100%' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
            <Text strong style={{ color: isActive ? lightPalette.menuTextSelected : lightPalette.textPrimary }}>
              {item.title}
            </Text>
            {isInCart && <Badge status="processing" text={<span style={{ fontSize: 12, color: lightPalette.textSecondary }}>已选</span>} />}
          </div>
          <Space size={4} style={{ flexWrap: 'wrap' }}>
            <Tag variant="filled" style={{ fontSize: 10, margin: 0 }}>{item.code}</Tag>
            <Text type="secondary" style={{ fontSize: 12 }}>
              {item.path.join(' / ')}
            </Text>
          </Space>
        </div>
      </List.Item>
    );
  };

  return (
    <DraggableModal
      title={
        <Space>
          <ShoppingCartOutlined style={{ color: lightPalette.menuTextSelected, fontSize: 20 }} />
          <span style={{ fontSize: 16, fontWeight: 600 }}>
            {stage === 0 ? '分类采购中心 (Category Marketplace) - 选品' : '分类导入向导 - 位置分配'}
          </span>
        </Space>
      }
      open={open}
      onCancel={onCancel}
      onOk={stage === 0 ? handleNextStage : handleFinalSubmit}
      width="90%"
      okText={stage === 0 ? "下一步：分配位置" : "确认导入"}
      cancelText={stage === 0 ? "取消" : "上一步"}
      // 注意：DraggableModal 可能不支持 onCancelText 属性，这里需要自定义 footer
      footer={[
        <Button key="cancel" onClick={stage === 0 ? onCancel : handlePrevStage}>
          {stage === 0 ? "取消" : "上一步"}
        </Button>,
        <Button key="submit" type="primary" onClick={stage === 0 ? handleNextStage : handleFinalSubmit}>
          {stage === 0 ? "下一步：分配位置" : "确认导入"}
        </Button>
      ]}
      styles={{ body: { height: '80vh', padding: 0, overflow: 'hidden' } }}
      destroyOnClose={false} // 保持状态
      maskClosable={false}
    >
      {stage === 0 ? (
        <Splitter style={{ height: '100%', boxShadow: '0 0 10px rgba(0, 0, 0, 0.1)' }}>
          {/* --- 左侧：选品区 (Discovery) --- */}
          <Splitter.Panel defaultSize="50%" min="30%" max="70%">
            <ProCard
              title="1. 选品 (Discovery - UNSPSC)"
              headerBordered
              style={{ height: '100%', display: 'flex', flexDirection: 'column', border: 'none' }}
              bodyStyle={{ padding: '16px', display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden', backgroundColor: '#fafafa' }}
            >
              <Space orientation="vertical" style={{ width: '100%', marginBottom: 16 }}>
                <Input.Search
                  placeholder="输入 UNSPSC 编码或名称搜索..."
                  allowClear
                  onSearch={handleSearch}
                  onChange={(e) => {
                    if (e.target.value === '') {
                      setSearchQuery('');
                      setSearchResults([]);
                    }
                  }}
                  enterButton={<Button icon={<SearchOutlined />} type="primary" />}
                />
              </Space>

              <div style={{ flex: 1, overflow: 'hidden' }}>
                {searchQuery.trim() ? (
                  isSearching ? (
                    <div style={{ padding: 24 }}><Spin /></div>
                  ) : searchResults.length > 0 ? (
                    <List
                      dataSource={searchResults}
                      renderItem={renderSearchResultItem}
                      style={{ height: '100%', overflowY: 'auto' }}
                    />
                  ) : (
                    <Empty description="未找到匹配结果" />
                  )
                ) : (
                  <CategoryBrowser onSelect={handleBrowserSelect} />
                )}
              </div>
            </ProCard>
          </Splitter.Panel>

          {/* --- 中间：配置区 (Configuration) --- */}
          <Splitter.Panel defaultSize="25%" min="20%">
            <ProCard
              title="2. 配置 (Configuration)"
              headerBordered
              style={{ height: '100%', display: 'flex', flexDirection: 'column', border: 'none' }}
              extra={
                activeCategory && (
                  <Space>
                    <Button size="small" type="text" onClick={() => setCheckedAttributes(MOCK_ATTRIBUTES)}>全选</Button>
                    <Button size="small" type="text" onClick={() => setCheckedAttributes([])}>清空</Button>
                </Space>
              )
            }
            bodyStyle={{ padding: '24px', display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden' }}
          >
            {activeCategory ? (
              <>
                <div style={{ marginBottom: 24 }}>
                  <Breadcrumb items={activeCategory.path.map(p => ({ title: p }))} style={{ marginBottom: 8, fontSize: 12 }} />
                  <Title level={4} style={{ margin: 0, color: lightPalette.textPrimary }}>{activeCategory.title}</Title>
                  <Space style={{ marginTop: 8 }}>
                    <Tag color="blue">{activeCategory.code}</Tag>
                    <Tag>{LIBRARIES.find(l => l.value === activeCategory.library)?.label}</Tag>
                  </Space>
                </div>

                <div style={{ flex: 1, overflowY: 'auto' }}>
                  <Title level={5} style={{ fontSize: 14, marginBottom: 16 }}>选择业务属性</Title>
                  <Checkbox.Group
                    style={{ display: 'flex', flexDirection: 'column', gap: 12 }}
                    value={checkedAttributes}
                    onChange={(vals) => setCheckedAttributes(vals as string[])}
                  >
                    {MOCK_ATTRIBUTES.map(attr => (
                      <Checkbox key={attr} value={attr} style={{ marginLeft: 0 }}>
                        <Space>
                          <span>{attr}</span>
                          {/* 模拟一些属性的元数据展示 */}
                          <Text type="secondary" style={{ fontSize: 12 }}>(String)</Text>
                        </Space>
                      </Checkbox>
                    ))}
                  </Checkbox.Group>
                </div>

                <div style={{ marginTop: 24, paddingTop: 16, borderTop: `1px solid ${lightPalette.borderColor}` }}>
                  <Button
                    type="primary"
                    block
                    size="large"
                    icon={cart.some(c => c.key === activeCategory.key) ? <EditOutlined /> : <PlusOutlined />}
                    onClick={handleAddToCart}
                    style={{ height: 48, fontSize: 16 }}
                  >
                    {cart.some(c => c.key === activeCategory.key) ? '更新配置 (Update)' : '加入清单 (Add to Cart)'}
                  </Button>
                </div>
              </>
            ) : (
              <div style={{ height: '100%', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', color: lightPalette.textSecondary }}>
                <AppstoreOutlined style={{ fontSize: 48, marginBottom: 16, opacity: 0.2 }} />
                <Text type="secondary">请从左侧选择一个分类进行配置</Text>
              </div>
            )}
          </ProCard>
        </Splitter.Panel>

        {/* --- 右侧：清单区 (Cart) --- */}
        <Splitter.Panel defaultSize="25%" min="20%" max="40%">
          <ProCard
            title={
              <Space>
                <span>3. 清单 (Cart)</span>
                <Badge count={cart.length} showZero color={lightPalette.menuTextSelected} />
              </Space>
            }
            headerBordered
            style={{ height: '100%', display: 'flex', flexDirection: 'column', border: 'none' }}
            extra={
              cart.length > 0 && (
                <Button type="text" danger size="small" icon={<DeleteOutlined />} onClick={handleClearCart}>
                  清空
                </Button>
              )
            }
            bodyStyle={{ padding: '0', display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden', backgroundColor: '#fafafa' }}
          >
            <div style={{ flex: 1, overflowY: 'auto', padding: '12px' }}>
              <List
                dataSource={cart}
                renderItem={(item) => (
                  <div
                    key={item.key}
                    style={{
                      backgroundColor: '#fff',
                      padding: '12px',
                      borderRadius: '8px',
                      marginBottom: '8px',
                      border: activeCategory?.key === item.key ? `1px solid ${lightPalette.menuTextSelected}` : `1px solid ${lightPalette.borderColor}`,
                      cursor: 'pointer',
                      position: 'relative',
                      boxShadow: '0 1px 2px rgba(0,0,0,0.03)'
                    }}
                    onClick={() => handleSelectCategory(item)}
                  >
                    <div style={{ paddingRight: 24 }}>
                      <Text strong>{item.title}</Text>
                      <div style={{ marginTop: 4 }}>
                        <Tag style={{ fontSize: 10 }}>{item.code}</Tag>
                        <Text type="secondary" style={{ fontSize: 12 }}>已选 {item.attributes.length} 个属性</Text>
                      </div>
                    </div>

                    <div style={{ position: 'absolute', top: 8, right: 8 }}>
                      <Tooltip title="移除">
                        <Button
                          type="text"
                          size="small"
                          danger
                          icon={<DeleteOutlined />}
                          onClick={(e) => {
                            e.stopPropagation();
                            handleRemoveFromCart(item.key);
                          }}
                        />
                      </Tooltip>
                    </div>
                  </div>
                )}
                locale={{ emptyText: <Empty image={Empty.PRESENTED_IMAGE_SIMPLE} description="清单为空" /> }}
              />
            </div>

            {/* 底部统计 */}
            <div style={{ padding: '16px', backgroundColor: '#fff', borderTop: `1px solid ${lightPalette.borderColor}` }}>
              <Space size="large" style={{ width: '100%', justifyContent: 'space-between' }}>
                <Statistic
                  title="分类数量"
                  value={cart.length}
                  valueStyle={{ fontSize: 18, fontWeight: 600 }}
                />
                <Statistic
                  title="属性总数"
                  value={cart.reduce((acc, cur) => acc + cur.attributes.length, 0)}
                  valueStyle={{ fontSize: 18, fontWeight: 600 }}
                />
              </Space>
            </div>
          </ProCard>
        </Splitter.Panel>
      </Splitter>
      ) : (
        <Splitter style={{ height: '100%', boxShadow: '0 0 10px rgba(0, 0, 0, 0.1)' }}>
          {/* --- 左侧：待分配列表 --- */}
          <Splitter.Panel defaultSize="30%" min="20%" max="40%">
            <ProCard
              title="待分配分类 (Pending)"
              headerBordered
              style={{ height: '100%', display: 'flex', flexDirection: 'column', border: 'none' }}
              bodyStyle={{ padding: '0', display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden', backgroundColor: '#fafafa' }}
            >
              <div style={{ padding: '12px', borderBottom: `1px solid ${lightPalette.borderColor}`, backgroundColor: '#fff' }}>
                <Space orientation="vertical" style={{ width: '100%' }}>
                  <Text type="secondary">选中下方分类，然后在右侧树中选择目标节点，点击分配。</Text>
                  <Button 
                    type="primary" 
                    block 
                    icon={<ArrowRightOutlined />} 
                    disabled={selectedPendingKeys.length === 0 || !selectedTargetNodeKey}
                    onClick={handleAssignToTree}
                  >
                    分配到选中节点
                  </Button>
                </Space>
              </div>

              <div style={{ flex: 1, overflowY: 'auto', padding: '12px' }}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                  {pendingItems.map(item => {
                    const isSelected = selectedPendingKeys.includes(item.key);
                    return (
                      <div 
                        key={item.key}
                        onClick={(e) => handlePendingItemClick(item.key, e)}
                        style={{ 
                          padding: '8px 12px', 
                          backgroundColor: isSelected ? lightPalette.menuItemSelectedBg : '#fff', 
                          borderRadius: '6px', 
                          border: isSelected ? `1px solid ${lightPalette.menuTextSelected}` : `1px solid ${lightPalette.borderColor}`,
                          display: 'flex',
                          alignItems: 'center',
                          cursor: 'pointer',
                          userSelect: 'none', // 防止 Shift 选择时出现文本选中
                          transition: 'all 0.1s'
                        }}
                      >
                        <Checkbox 
                          checked={isSelected} 
                          onClick={(e) => handleCheckboxClick(item.key, e)}
                        />
                        <div style={{ marginLeft: 8, flex: 1 }}>
                          <Space>
                            <Text strong style={{ color: isSelected ? lightPalette.menuTextSelected : undefined }}>{item.title}</Text>
                            <Tag style={{ fontSize: 10 }}>{item.code}</Tag>
                          </Space>
                        </div>
                      </div>
                    );
                  })}
                </div>
                {pendingItems.length === 0 && <Empty description="所有分类已分配" image={Empty.PRESENTED_IMAGE_SIMPLE} />}
              </div>
            </ProCard>
          </Splitter.Panel>

          {/* --- 右侧：预览树 --- */}
          <Splitter.Panel defaultSize="70%" min="50%">
            <ProCard
              title="预览树 (Preview Tree)"
              headerBordered
              style={{ height: '100%', display: 'flex', flexDirection: 'column', border: 'none' }}
              extra={<Text type="secondary">支持拖拽调整位置</Text>}
              bodyStyle={{ padding: '16px', display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden' }}
            >
              <div ref={treeContainerRef} style={{ flex: 1, overflow: 'hidden' }}>
                <Tree
                  treeData={previewTreeData}
                  draggable
                  blockNode
                  expandedKeys={expandedKeys}
                  onExpand={onExpand}
                  autoExpandParent={autoExpandParent}
                  onDrop={onDrop}
                  onSelect={(keys) => setSelectedTargetNodeKey(keys[0])}
                  selectedKeys={selectedTargetNodeKey ? [selectedTargetNodeKey] : []}
                  height={treeHeight} // Dynamic height for virtual scroll
                  virtual // Explicitly enable virtual scroll
                />
              </div>
            </ProCard>
          </Splitter.Panel>
        </Splitter>
      )}
    </DraggableModal>
  );
};

export default CategoryMarketplace;

'use client';

import React, { useState } from 'react';
import { theme, Splitter, Button, Space, App, Modal, Input, Form } from 'antd';
import { PlusOutlined, ShoppingCartOutlined, FolderOutlined } from '@ant-design/icons';
import type { DataNode, TreeProps } from 'antd/es/tree';
import CategoryTree from './components/CategoryTree';
import CategoryDetail from './components/CategoryDetail';
import CategoryMarketplace from './components/CategoryMarketplace';
import { defaultUserTreeData } from './mockData';

const CategoryPage: React.FC = () => {
  const { message } = App.useApp();
  const {
    token: { colorBgContainer, borderRadiusLG, colorBorderSecondary },
  } = theme.useToken();

  const [selectedKey, setSelectedKey] = useState<React.Key>('CAT-001-01');
  const [selectedNode, setSelectedNode] = useState<DataNode | undefined>({ title: '休闲零食', key: 'CAT-001-01-01' }); // 默认选中一个用于展示
  const [leftCollapsed, setLeftCollapsed] = useState(false);
  const [marketplaceVisible, setMarketplaceVisible] = useState(false);
  const [treeData, setTreeData] = useState<DataNode[]>(defaultUserTreeData);

  // 新建分类相关状态
  const [createModalVisible, setCreateModalVisible] = useState(false);
  const [createParentKey, setCreateParentKey] = useState<React.Key | null>(null); // null 表示根节点
  const [form] = Form.useForm();
  
  const onSelect: TreeProps['onSelect'] = (keys, info) => {
    if (keys.length > 0) {
      setSelectedKey(keys[0]);
      setSelectedNode(info.node);
    } else {
      setSelectedKey('');
      setSelectedNode(undefined);
    }
  };

  // --- CRUD Logic ---

  const handleDeleteCategory = (key: React.Key) => {
    const deleteNode = (data: DataNode[]): DataNode[] => {
      return data
        .filter(item => item.key !== key)
        .map(item => {
          if (item.children) {
            return {
              ...item,
              children: deleteNode(item.children),
            };
          }
          return item;
        });
    };

    setTreeData(prev => deleteNode(prev));
    message.success('分类已删除');
    setSelectedKey('');
    setSelectedNode(undefined);
  };

  const handleOpenCreateModal = (parentKey: React.Key | null = null) => {
    setCreateParentKey(parentKey);
    form.resetFields();
    setCreateModalVisible(true);
  };

  const handleCreateSubmit = () => {
    form.validateFields().then(values => {
      const newKey = `NEW-${Date.now()}`;
      const newNode: DataNode = {
        title: values.name,
        key: newKey,
        icon: <FolderOutlined />,
        isLeaf: true,
      };

      if (createParentKey === null) {
        // Add to root (In this mock, we might want to restrict root addition or just add it)
        // For now, let's assume root addition is allowed and it's a new "Industry" or top level category
        setTreeData(prev => [...prev, newNode]);
      } else {
        // Add to parent
        const addNode = (data: DataNode[]): DataNode[] => {
          return data.map(node => {
            if (node.key === createParentKey) {
              return {
                ...node,
                children: [...(node.children || []), newNode],
                isLeaf: false,
              };
            }
            if (node.children) {
              return {
                ...node,
                children: addNode(node.children),
              };
            }
            return node;
          });
        };
        setTreeData(prev => addNode(prev));
      }

      message.success('分类创建成功');
      setCreateModalVisible(false);
    });
  };

  const handleMarketplaceOk = (newTreeData: DataNode[]) => {
    setTreeData(newTreeData);
    message.success('分类导入成功');
    setMarketplaceVisible(false);
  };

  return (
    <div style={{ height: 'calc(100vh - 163px)', display: 'flex', flexDirection: 'column', gap: 16, overflow: 'hidden' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Space>
          <Button type="primary" icon={<PlusOutlined />} onClick={() => handleOpenCreateModal(null)}>新建分类</Button>
          <Button icon={<ShoppingCartOutlined />} onClick={() => setMarketplaceVisible(true)}>从标准库导入</Button>
        </Space>
      </div>

      <Splitter
        onCollapse={(collapsed) => setLeftCollapsed(collapsed[0] ?? false)}
        style={{
          flex: 1,
          minHeight: 0,
          background: colorBgContainer,
          borderRadius: borderRadiusLG,
          border: `1px solid ${colorBorderSecondary}`,
          boxShadow: '0 0 10px rgba(0, 0, 0, 0.05)',
          overflow: 'hidden',
        }}
      >
        <Splitter.Panel
          defaultSize={280}
          min={200}
          max={600}
          collapsible={{ end: true, showCollapsibleIcon: leftCollapsed ? true : 'auto' }}
        >
          <CategoryTree onSelect={onSelect} treeData={treeData} />
        </Splitter.Panel>
        <Splitter.Panel>
          <div style={{ height: '100%', padding: '24px 0' }}>
            <CategoryDetail 
              selectedKey={selectedKey} 
              selectedNode={selectedNode} 
              onDelete={handleDeleteCategory}
              onCreateSub={handleOpenCreateModal}
            />
          </div>
        </Splitter.Panel>
      </Splitter>

      <CategoryMarketplace 
        open={marketplaceVisible}
        onCancel={() => setMarketplaceVisible(false)}
        onOk={handleMarketplaceOk}
        userTreeData={treeData}
      />

      <Modal
        title={createParentKey ? "新建子分类" : "新建根分类"}
        open={createModalVisible}
        onOk={handleCreateSubmit}
        onCancel={() => setCreateModalVisible(false)}
        destroyOnHidden={true}
      >
        <Form form={form} layout="vertical">
          <Form.Item
            name="name"
            label="分类名称"
            rules={[{ required: true, message: '请输入分类名称' }]}
          >
            <Input placeholder="请输入分类名称" />
          </Form.Item>
          <Form.Item
            name="code"
            label="分类编码"
            initialValue={`CAT-${Date.now()}`} // Auto-generate a mock code
          >
            <Input disabled placeholder="自动生成" />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
};

export default CategoryPage;

